-- Schema for Domain: sequencing | Business: Genomics Biotech | Version: v1_ecm
-- Generated on: 2026-05-06 13:04:46

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `genomics_biotech_ecm`.`sequencing` COMMENT 'Core NGS operations including WGS, WES, targeted sequencing, library preparation, flow cell management, multiplexing, demultiplexing, and raw data generation. Manages sequencing runs, read quality (Phred scores), coverage depth, read length, and FASTQ output. Central to genomic data production workflows integrated with Illumina BaseSpace Sequence Hub.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sequencing`.`sequencing_run` (
    `sequencing_run_id` BIGINT COMMENT 'Unique surrogate identifier for each Next-Generation Sequencing (NGS) run record in the Databricks Silver layer. Primary key for the sequencing_run entity. Role: TRANSACTION_HEADER — this entity represents a discrete NGS sequencing execution event with a full operational lifecycle.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Sequencing runs performed as service for customer accounts in contract research/service lab operations. Essential for billing, SLA tracking, regulatory compliance, and customer-specific data segregati',
    `asset_id` BIGINT COMMENT 'Reference to the sequencing instrument (e.g., NovaSeq, NextSeq, HiSeq) on which this run was executed. Used to trace run performance back to a specific physical instrument asset.',
    `basecall_model_id` BIGINT COMMENT 'Foreign key linking to sequencing.basecall_model. Business justification: Sequencing runs use specific basecalling algorithm models to convert raw signal data to nucleotide sequences. This is a critical lineage attribute for data quality tracking and regulatory compliance. ',
    `capa_id` BIGINT COMMENT 'Foreign key linking to quality.capa. Business justification: Systematic sequencing run failures (repeated QC failures, instrument issues, process deviations) trigger CAPAs. Labs must link runs to CAPAs for effectiveness checks, trend analysis, and regulatory co',
    `contact_id` BIGINT COMMENT 'Foreign key linking to customer.contact. Business justification: Technical contact for run-specific communications: QC notifications, result delivery, troubleshooting. Critical for customer-facing service operations and regulatory traceability of data delivery.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Sequencing runs consume significant lab resources (reagents, instrument time, labor) requiring cost center assignment for accurate departmental cost allocation, project budget tracking, and R&D capita',
    `deviation_id` BIGINT COMMENT 'Foreign key linking to quality.quality_deviation. Business justification: Sequencing runs frequently trigger quality deviations (failed QC, instrument errors, contamination events). GxP labs must link runs to deviations for investigation, root cause analysis, and regulatory',
    `experiment_id` BIGINT COMMENT 'Foreign key linking to research.experiment. Business justification: Sequencing runs generate data for specific experiments. Tracking this link enables experiment-level data aggregation, cost allocation to R&D experiments, and traceability from raw sequencing output to',
    `genome_assembly_id` BIGINT COMMENT 'Foreign key linking to reference.genome_assembly. Business justification: Every sequencing run aligns reads to a reference genome assembly. Alignment, variant calling, QC metrics, and regulatory compliance all require tracking which reference build was used. Fundamental to ',
    `instrument_asset_id` BIGINT COMMENT 'FK to instrument.instrument_asset.instrument_asset_id — Sequencing runs must reference the physical instrument they executed on for instrument utilization tracking, maintenance correlation, and performance trending.',
    `internal_order_id` BIGINT COMMENT 'Foreign key linking to finance.internal_order. Business justification: Sequencing runs frequently execute against specific internal orders (R&D projects, validation campaigns, clinical studies) requiring direct cost capture for project budget control, capitalization deci',
    `production_batch_id` BIGINT COMMENT 'Foreign key linking to manufacturing.production_batch. Business justification: Direct traceability from sequencing run to manufactured reagent batch enables rapid quality investigations. When Q30 scores drop or error rates spike, QC teams must immediately identify affected manuf',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to manufacturing.work_order. Business justification: Vertically-integrated genomics companies manufacture custom reagent kits in-house. Sequencing runs must trace to manufacturing work orders for regulatory compliance (21 CFR Part 11, ISO 13485), qualit',
    `opportunity_id` BIGINT COMMENT 'Foreign key linking to commercial.opportunity. Business justification: Sequencing runs are frequently performed as billable services for commercial opportunities (customer evaluation studies, contract research, pilot projects). Essential for revenue recognition, project ',
    `employee_id` BIGINT COMMENT 'Reference to the laboratory operator or scientist who initiated and is responsible for this sequencing run. Supports GxP audit trail and operator accountability requirements.',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to supply.purchase_order. Business justification: Sequencing runs consume reagent kits purchased via PO. Link enables cost accounting per run, supplier performance tracking, and GMP traceability required for regulated assays. Critical for COGS calcul',
    `quality_issue_id` BIGINT COMMENT 'Foreign key linking to data.quality_issue. Business justification: Run failures (low Q30, cluster density out-of-spec, instrument errors) logged as quality issues for root cause analysis and CAPA - GxP requirement per 21 CFR Part 11 and ISO 13485.',
    `catalog_item_id` BIGINT COMMENT 'Foreign key linking to product.catalog_item. Business justification: Sequencing runs consume specific reagent kit catalog items. Essential for cost-per-run analysis, inventory management, regulatory lot traceability, and procurement planning. Labs must track which comm',
    `lot_id` BIGINT COMMENT 'Reference to the reagent kit lot (LOT number) consumed during this sequencing run. Enables traceability from run output back to reagent manufacturing lot for quality investigations and COA verification.',
    `retention_policy_id` BIGINT COMMENT 'Foreign key linking to data.retention_policy. Business justification: Sequencing run data retention governed by regulatory requirements (FDA 21 CFR Part 11 requires clinical data retention, CLIA mandates diagnostic record retention) - compliance mandate. Retention perio',
    `revenue_recognition_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_recognition. Business justification: Customer sequencing runs in service revenue models must link to revenue recognition for accurate revenue allocation, performance obligation fulfillment tracking, and ASC 606 compliance. Essential for ',
    `sequencing_protocol_id` BIGINT COMMENT 'Foreign key linking to sequencing.sequencing_protocol. Business justification: Sequencing runs must follow approved, validated sequencing protocols that define run configuration, QC thresholds, and regulatory compliance requirements. sequencing_run currently has run_mode, run_ty',
    `service_agreement_id` BIGINT COMMENT 'Foreign key linking to customer.service_agreement. Business justification: Runs performed under specific service agreements defining SLA terms, turnaround time, pricing tier, regulatory classification. Essential for contract compliance verification and billing.',
    `supplier_id` BIGINT COMMENT 'Foreign key linking to supply.supplier. Business justification: Tracks reagent kit supplier for run. Enables supplier performance evaluation (run failures, Q30 scores by supplier), quality investigations, deviation tracking, and supplier scorecarding based on sequ',
    `technical_requirement_id` BIGINT COMMENT 'Foreign key linking to customer.technical_requirement. Business justification: Runs executed to fulfill customer-specified technical requirements (coverage depth, read length, platform). Links run parameters to customer engagement specifications for QC validation and acceptance ',
    `validation_study_id` BIGINT COMMENT 'Foreign key linking to quality.validation_study. Business justification: Sequencing runs are used in validation studies (assay validation, instrument qualification, method verification, software validation). Labs must link validation runs to study records for regulatory su',
    `actual_sample_count` STRING COMMENT 'Actual number of samples successfully demultiplexed and yielding usable FASTQ data from this run. May differ from planned_sample_count due to index mismatches, low-quality libraries, or run failures. Key metric for run efficiency and yield reporting.',
    `basespace_run_code` STRING COMMENT 'The unique run identifier assigned by Illumina BaseSpace Sequence Hub for this sequencing run. Used to link the internal enterprise record to the BaseSpace cloud platform for FASTQ retrieval, run monitoring, and bioinformatics pipeline initiation.',
    `cluster_density` DECIMAL(18,2) COMMENT 'The density of sequencing clusters generated on the flow cell surface, measured in thousands of clusters per mm². A critical run quality parameter — too low indicates under-loading, too high causes cluster overlap and quality degradation. Reported by the instrument and BaseSpace.',
    `cluster_pf_pct` DECIMAL(18,2) COMMENT 'Percentage of clusters that pass the Illumina chastity filter (PF = Passing Filter), indicating the proportion of reads with sufficient signal purity for reliable base calling. A key run-level QC metric; typically expected to be >75-80% for a passing run.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this sequencing run record was first created in the enterprise data system (LIMS or BaseSpace ingestion). Serves as the RECORD_AUDIT_CREATED timestamp for this TRANSACTION_HEADER entity. Distinct from run_start_timestamp which reflects the physical run start. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `data_retention_category` STRING COMMENT 'Data retention classification for this sequencing run record and its associated FASTQ/BAM/VCF outputs, determining the minimum retention period per applicable regulations. standard = 2 years (RUO); extended = 10+ years (clinical/GxP); permanent = indefinite (regulatory submission data); restricted_deletion = deletion requires regulatory approval.. Valid values are `standard|extended|permanent|restricted_deletion`',
    `demultiplexing_status` STRING COMMENT 'Current status of the FASTQ demultiplexing process for this run, which separates pooled (multiplexed) sample reads by their index barcodes into individual sample FASTQ files. Tracks the post-run data processing step that precedes bioinformatics pipeline execution.. Valid values are `pending|in_progress|completed|failed`',
    `end_timestamp` TIMESTAMP COMMENT 'Date and time when the sequencing run completed (final cycle finished or run terminated). Used with run_start_timestamp to calculate run duration and TAT. Null if run is still in progress or queued. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `error_rate_pct` DECIMAL(18,2) COMMENT 'The base-level sequencing error rate for this run expressed as a percentage, calculated using PhiX control spike-in alignment. Lower values indicate higher sequencing accuracy. Used for run QC acceptance/rejection decisions and instrument performance trending.',
    `fastq_output_path` STRING COMMENT 'The storage path or URI (e.g., S3 bucket path, BaseSpace project URL, or HPC filesystem path) where the FASTQ output files for this run are stored. Confidential as it reveals internal data infrastructure topology. Used by bioinformatics pipelines to locate raw sequencing data.',
    `flow_cell_type` STRING COMMENT 'The type/format of flow cell used in this run (e.g., SP, S1, S2, S4 for NovaSeq; P1, P2, P3 for NovaSeq X; nano, micro for MiSeq). Determines lane count, cluster capacity, and maximum output yield. Critical for run planning and cost accounting. [ENUM-REF-CANDIDATE: SP|S1|S2|S4|P1|P2|P3|nano|micro|high|mid — promote to reference product]',
    `folder_name` STRING COMMENT 'The instrument-generated run folder name following Illumina naming convention (e.g., 240115_A00001_0001_AHXXXXXX). Contains date, instrument serial, run number, and flow cell ID. Used for data traceability between instrument output and enterprise data systems.',
    `index_read_length` STRING COMMENT 'Number of base pairs sequenced for the index (barcode) reads used in multiplexing/demultiplexing. Typically 6, 8, or 10 bp per index. Determines the number of samples that can be multiplexed on a single flow cell and the accuracy of demultiplexing.',
    `instrument_platform` STRING COMMENT 'The specific Illumina instrument platform model used for this sequencing run. Captured at run time for performance benchmarking, platform-specific QC thresholds, and bioinformatics pipeline configuration. [ENUM-REF-CANDIDATE: NovaSeq 6000|NovaSeq X|NextSeq 2000|NextSeq 550|HiSeq 4000|MiSeq|iSeq 100|PromethION|GridION — promote to reference product]',
    `is_paired_end` BOOLEAN COMMENT 'Indicates whether this run was configured as paired-end (True) or single-read (False) sequencing. Paired-end sequencing generates reads from both ends of a DNA fragment, improving alignment accuracy and variant detection. Critical parameter for bioinformatics pipeline configuration.',
    `lane_count` STRING COMMENT 'Number of lanes on the flow cell used in this sequencing run (e.g., 1 for MiSeq, 2 for NextSeq, 4 for NovaSeq SP/S1/S2, 8 for NovaSeq S4). Used for per-lane QC analysis, sample distribution planning, and run capacity calculations.',
    `library_prep_kit` STRING COMMENT 'Name or catalog identifier of the library preparation kit used to prepare samples for this sequencing run (e.g., Illumina DNA Prep, TruSeq Stranded mRNA, Nextera DNA Flex). Affects sequencing performance, adapter trimming parameters, and bioinformatics pipeline configuration.',
    `notes` STRING COMMENT 'Free-text field for operator or QC reviewer notes about this sequencing run, including observations about run performance, deviations from SOP, troubleshooting actions taken, or contextual information relevant to data interpretation. Supports GxP deviation documentation.',
    `output_yield_gb` DECIMAL(18,2) COMMENT 'Total sequencing data output generated by this run measured in gigabases (Gb). Represents the QUANTITATIVE_RESULT for this non-monetary TRANSACTION_HEADER. Used for run performance benchmarking, storage capacity planning, and comparison against instrument specifications.',
    `phix_spike_in_pct` DECIMAL(18,2) COMMENT 'Percentage of PhiX bacteriophage control library spiked into the sequencing run for real-time quality monitoring and error rate calibration. Typically 1-5% for standard runs. Used to calculate error_rate_pct and validate instrument performance.',
    `planned_sample_count` STRING COMMENT 'Number of samples planned to be multiplexed and sequenced in this run as defined in the sample sheet at run setup. Used for capacity planning, reagent consumption estimation, and comparison against actual demultiplexed sample count.',
    `q30_pct` DECIMAL(18,2) COMMENT 'Percentage of bases with a Phred quality score of 30 or higher (Q30), indicating ≥99.9% base call accuracy. The primary industry-standard run quality metric. Typically required to be >75-80% for a run to pass QC. Directly impacts variant calling accuracy and clinical reporting confidence.',
    `qc_reviewed_timestamp` TIMESTAMP COMMENT 'Date and time when the QC review of this sequencing run was completed and the run_qc_status was formally assigned. Part of the GxP electronic audit trail. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `qc_status` STRING COMMENT 'The overall QC pass/fail determination for this sequencing run based on evaluation of run metrics (Q30%, cluster density, error rate, yield). pass = all metrics within specification; fail = one or more critical metrics out of specification; pending_review = awaiting manual QC review; conditional_pass = passed with noted deviations. Determines whether downstream FASTQ data is released for analysis.. Valid values are `pass|fail|pending_review|conditional_pass`',
    `read_length` STRING COMMENT 'The number of base pairs sequenced per read in this run (e.g., 75, 100, 150, 250 bp). A key sequencing parameter that determines data quality, coverage, and application suitability. Configured at run setup and recorded for QC and reproducibility.',
    `regulatory_use_classification` STRING COMMENT 'Regulatory classification of this sequencing runs intended use. IVD = In Vitro Diagnostic (FDA/IVDR regulated); RUO = Research Use Only (not for clinical use); LDT = Laboratory Developed Test (CLIA-regulated); GMP/GLP/GCP = applicable Good Practice framework. Determines data handling, retention, and reporting obligations.. Valid values are `IVD|RUO|LDT|GMP|GLP|GCP`',
    `run_mode` STRING COMMENT 'The NGS application type or sequencing strategy for this run. Determines the library preparation approach, bioinformatics pipeline, and downstream analysis. WGS = Whole Genome Sequencing; WES = Whole Exome Sequencing; targeted = targeted panel sequencing; amplicon = amplicon-based sequencing; RNA-seq = transcriptome sequencing; metagenomics = environmental/microbial sequencing.. Valid values are `WGS|WES|targeted|amplicon|RNA-seq|metagenomics`',
    `run_name` STRING COMMENT 'Human-readable name assigned to the sequencing run, typically following a lab naming convention (e.g., RUN-2024-001-NovaSeq). Used for identification in LIMS, BaseSpace, and operational dashboards. Maps to the Run Name field in Illumina BaseSpace Sequence Hub.',
    `run_number` STRING COMMENT 'Externally-known business identifier for the sequencing run, assigned by the LIMS or laboratory operations system. Used for cross-system referencing, customer reporting, and regulatory traceability. Serves as the BUSINESS_IDENTIFIER for this TRANSACTION_HEADER entity.. Valid values are `^RUN-[0-9]{4}-[0-9]{4,6}$`',
    `run_status` STRING COMMENT 'Current lifecycle state of the sequencing run. Drives operational workflows, downstream pipeline triggering, and SLA monitoring. queued = scheduled but not started; in_progress = actively sequencing; completed = run finished successfully; failed = run terminated with errors; aborted = manually stopped; paused = temporarily halted. Serves as the LIFECYCLE_STATUS for this TRANSACTION_HEADER entity.. Valid values are `queued|in_progress|completed|failed|aborted|paused`',
    `run_type` STRING COMMENT 'Classification of the run by its intended use context. clinical = IVD/LDT clinical diagnostic run subject to CLIA/CAP; research = RUO research run; validation = assay validation run; QC = quality control run; development = R&D development run. Determines applicable regulatory framework and data handling requirements.. Valid values are `clinical|research|validation|QC|development`',
    `sample_sheet_version` STRING COMMENT 'Version identifier of the Illumina sample sheet file used to configure this sequencing run, specifying sample IDs, index sequences, and demultiplexing parameters. Used for run reproducibility, troubleshooting, and audit trail. Maps to Illumina SampleSheet.csv versioning.',
    `start_timestamp` TIMESTAMP COMMENT 'Date and time when the sequencing run was initiated on the instrument (first cycle commenced). Serves as the BUSINESS_EVENT_TIMESTAMP for this TRANSACTION_HEADER entity. Used for TAT (Turnaround Time) calculation, SLA monitoring, and run scheduling. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `target_coverage_depth` STRING COMMENT 'The intended mean sequencing coverage depth (number of times each base is sequenced) specified at run design time (e.g., 30x for WGS, 100x for WES, 500x for targeted panels). Used to validate whether the run met its coverage objectives and for clinical reporting thresholds.',
    `total_cycles` STRING COMMENT 'Total number of sequencing chemistry cycles executed in this run. For paired-end runs, this includes both read 1, index reads, and read 2 cycles (e.g., 2×150 bp = 300 cycles + index cycles). Used for run cost accounting, reagent consumption tracking, and run configuration validation.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this sequencing run record was last modified in the enterprise data system. Serves as the RECORD_AUDIT_UPDATED timestamp for this TRANSACTION_HEADER entity. Used for change tracking, data synchronization, and audit compliance. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    CONSTRAINT pk_sequencing_run PRIMARY KEY(`sequencing_run_id`)
) COMMENT 'Core master record for each NGS sequencing run executed on an instrument. Captures run identity, instrument assignment, flow cell, run mode (WGS, WES, targeted), read length, paired-end configuration, run status (queued, in-progress, completed, failed), start/end timestamps, operator, reagent kit lot, BaseSpace run ID, total cycles, and run-level QC pass/fail outcome. This is the central operational entity of the sequencing domain — every downstream FASTQ, QC metric, and library result traces back to a sequencing run.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sequencing`.`flow_cell` (
    `flow_cell_id` BIGINT COMMENT 'Unique surrogate identifier for each flow cell master record in the Genomics Biotech lakehouse. Primary key for the flow_cell data product. Role: MASTER_RESOURCE.',
    `asset_id` BIGINT COMMENT 'Identifier of the sequencing instrument on which this flow cell was or is currently loaded. Links to the instrument domain for instrument qualification records, maintenance history, and run association. Populated when status transitions to loaded.',
    `batch_id` BIGINT COMMENT 'Foreign key linking to supply.batch. Business justification: Flow cells are batch-managed consumables. Link enables lot traceability, expiry tracking, recall management, and quality investigations correlating run failures to specific batches. Critical for GMP c',
    `catalog_id` BIGINT COMMENT 'Foreign key linking to reagent.reagent_catalog. Business justification: Flow cells are catalog items with part_number, requiring linkage to reagent catalog for procurement, inventory management, and compatibility verification with instruments. New FK needed; removes denor',
    `catalog_item_id` BIGINT COMMENT 'Foreign key linking to product.catalog_item. Business justification: Flow cells are consumable products with SKUs, pricing, and regulatory classifications. Critical for procurement, cost accounting, supply chain management, and compatibility validation with instruments',
    `coa_id` BIGINT COMMENT 'Foreign key linking to reagent.coa. Business justification: Flow cells require Certificate of Analysis verification for GxP-compliant sequencing runs, quality control, and regulatory audits. supplier_lot_certificate_number is a reference string, not a denormal',
    `employee_id` BIGINT COMMENT 'Identifier of the QA/QC personnel who performed the incoming inspection of this flow cell. Links to the workforce domain for personnel qualification records. Required for GMP audit trails and electronic signature compliance under 21 CFR Part 11.',
    `production_batch_id` BIGINT COMMENT 'Foreign key linking to manufacturing.production_batch. Business justification: Vertically-integrated genomics companies manufacturing flow cells in-house require full batch traceability for regulatory compliance (ISO 13485, FDA QSR). Flow cell performance issues (low cluster den',
    `material_id` BIGINT COMMENT 'Foreign key linking to supply.material. Business justification: Flow cells are materials in supply chain. Link enables inventory management, MRP planning, demand forecasting, and integration with ERP material master for procurement, costing, and warehouse manageme',
    `sequencing_run_id` BIGINT COMMENT 'Identifier of the sequencing run associated with this flow cell. Links to the sequencing_run data product for run parameters, quality metrics, and FASTQ output tracking. A flow cell may be associated with at most one sequencing run in its lifecycle.',
    `basespace_flow_cell_code` STRING COMMENT 'External identifier assigned to this flow cell within the Illumina BaseSpace Sequence Hub system. Enables cross-system reconciliation between the internal lakehouse record and the BaseSpace sequencing data management platform. Used for data lineage and run data retrieval.',
    `cluster_density_spec_mm2` DECIMAL(18,2) COMMENT 'Manufacturer-specified target cluster density in clusters per square millimeter (K/mm²) for optimal sequencing performance. Used to evaluate loading concentration and diagnose under- or over-clustering quality failures. Critical QC parameter tracked in LabVantage LIMS.',
    `cold_chain_breach_flag` BOOLEAN COMMENT 'Indicates whether a temperature excursion or cold chain breach was detected during shipping or storage of this flow cell (True = breach detected). Triggers quarantine workflow and quality investigation in LabVantage LIMS and Veeva Vault. A breached flow cell must not be used until cleared by QA.',
    `consumed_timestamp` TIMESTAMP COMMENT 'Date and time when the sequencing run was completed and the flow cell was fully consumed or removed from the instrument. Marks the end of the flow cells active lifecycle. Used for TAT reporting, instrument utilization metrics, and inventory depletion tracking.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the flow cell master record was first created in the Genomics Biotech lakehouse, typically at the point of goods receipt registration. Supports audit trail requirements under GxP, 21 CFR Part 11, and SOX internal controls.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the unit_cost field (e.g., USD, EUR, GBP). Enables multi-currency financial reporting and cost normalization across global procurement activities.. Valid values are `^[A-Z]{3}$`',
    `disposal_date` DATE COMMENT 'Date on which the consumed, failed, or expired flow cell was disposed of per the applicable disposal method. Required for environmental compliance records and GMP documentation of consumable lifecycle closure.',
    `disposal_method` STRING COMMENT 'Method used for disposal of the consumed or failed flow cell. Governs environmental health and safety (EHS) compliance for waste management. Options include standard laboratory waste, biohazardous waste, chemical waste, or return to supplier for failed/defective units.. Valid values are `standard_waste|biohazard_waste|chemical_waste|returned_to_supplier`',
    `expiry_date` DATE COMMENT 'Manufacturer-specified expiration date after which the flow cell must not be used for sequencing. Critical for GMP compliance, inventory management, and preventing use of expired consumables that could compromise sequencing quality. Monitored in SAP S/4HANA QM and LabVantage LIMS for automated expiry alerts.',
    `facility_code` BIGINT COMMENT 'Identifier of the Genomics Biotech facility (laboratory or sequencing center) where this flow cell is stored and used. Supports multi-site inventory management, site-level capacity planning, and regulatory site-specific compliance reporting.',
    `flow_cell_status` STRING COMMENT 'Current lifecycle status of the physical flow cell consumable. Tracks the operational state from receipt through consumption or disposal. in_stock = received and available; reserved = allocated to a planned run; loaded = currently on instrument; consumed = run completed; failed = quality failure; expired = past expiry date; quarantined = held for investigation. [ENUM-REF-CANDIDATE: in_stock|reserved|loaded|consumed|failed|expired|quarantined — promote to reference product]',
    `flow_cell_type` STRING COMMENT 'Instrument-specific flow cell format designation indicating throughput tier and lane configuration (e.g., S1, S2, S4, SP for NovaSeq 6000; MID, HIGH for NextSeq 550; P1, P2, P3 for NovaSeq X). Determines maximum output (Gb), number of lanes, and cluster density specifications. [ENUM-REF-CANDIDATE: S1|S2|S4|SP|MID|HIGH|P1|P2|P3 — promote to reference product]',
    `instrument_platform` STRING COMMENT 'The sequencing instrument platform for which this flow cell is designed and compatible (e.g., NovaSeq 6000, NovaSeq X, NextSeq 2000, MiSeq). Governs compatibility rules for loading, reagent kits, and run parameters. [ENUM-REF-CANDIDATE: NovaSeq 6000|NovaSeq X|NextSeq 550|NextSeq 2000|MiSeq|HiSeq 4000|iSeq 100 — promote to reference product]',
    `intended_application` STRING COMMENT 'Primary sequencing application for which this flow cell is designated (e.g., WGS — Whole Genome Sequencing, WES — Whole Exome Sequencing, targeted sequencing, RNA-seq, single-cell). Drives run parameter configuration and quality acceptance criteria. Also distinguishes Research Use Only (RUO) from In Vitro Diagnostic (IVD) use contexts for regulatory compliance. [ENUM-REF-CANDIDATE: WGS|WES|targeted_sequencing|amplicon|RNA_seq|single_cell|RUO|IVD — 8 candidates stripped; promote to reference product]',
    `is_single_use` BOOLEAN COMMENT 'Indicates whether the flow cell is designed for single use only (True) or supports multiple sequencing runs (False). Governs reuse policies, disposal procedures, and run scheduling logic. Most modern Illumina flow cells are single-use; this flag supports future platform compatibility.',
    `lane_count` STRING COMMENT 'Number of independent sequencing lanes on the flow cell (e.g., 1, 2, or 4 lanes for NovaSeq S1/S2/S4). Each lane can be loaded with a separate library pool, enabling multiplexing strategies. Drives capacity planning for sample batching and run scheduling.',
    `lims_barcode` STRING COMMENT 'Barcode label scanned into LabVantage LIMS at receipt to register the flow cell in the laboratory inventory system. Used for physical tracking, chain-of-custody documentation, and automated workflow triggering in the LIMS. May differ from the manufacturer serial number.',
    `loaded_timestamp` TIMESTAMP COMMENT 'Date and time when the flow cell was physically loaded onto the sequencing instrument, marking the transition from reserved to loaded status. Recorded in Illumina BaseSpace Sequence Hub and LabVantage LIMS. Used for run scheduling, instrument utilization analysis, and TAT (Turnaround Time) calculations.',
    `manufacture_date` DATE COMMENT 'Date the flow cell was manufactured by the supplier, as printed on the product label or Certificate of Analysis (COA). Used for shelf-life calculations, lot traceability, and quality investigations. Sourced from the COA accompanying the shipment.',
    `max_output_gb` DECIMAL(18,2) COMMENT 'Manufacturer-specified maximum sequencing output in gigabases (Gb) achievable under optimal conditions for this flow cell type. Used for capacity planning, run design, and cost-per-sample calculations. Represents the principal quantitative performance specification of the flow cell resource.',
    `notes` STRING COMMENT 'Free-text field for laboratory personnel to record observations, anomalies, deviations, or special handling instructions associated with this flow cell. Examples include cold chain deviation details, physical damage observations, or QA hold reasons. Captured in LabVantage LIMS.',
    `purchase_order_number` STRING COMMENT 'SAP S/4HANA purchase order number under which this flow cell was procured. Provides procurement lineage linking the physical consumable to the financial transaction, supplier contract, and goods receipt documentation. Supports COGS tracking and financial reconciliation.',
    `qc_inspection_date` DATE COMMENT 'Date on which the incoming QC inspection was performed for this flow cell. Used for compliance audit trails, SOP adherence tracking, and calculating time-from-receipt-to-clearance metrics.',
    `qc_inspection_status` STRING COMMENT 'Result of the incoming quality control inspection performed upon receipt of the flow cell. pending = inspection not yet completed; passed = meets acceptance criteria; failed = does not meet criteria, quarantined; waived = inspection waived per approved SOP (e.g., for pre-qualified lots). Managed in SAP S/4HANA QM and LabVantage LIMS.. Valid values are `pending|passed|failed|waived`',
    `read_length_spec` STRING COMMENT 'Maximum supported read length in base pairs (bp) for this flow cell type as specified by the manufacturer (e.g., 150 bp, 250 bp, 300 bp). Determines compatibility with library preparation protocols for WGS, WES, or targeted sequencing applications.',
    `reagent_kit_lot_number` STRING COMMENT 'Lot number of the sequencing reagent kit used in conjunction with this flow cell. Enables paired traceability between the flow cell consumable and its associated reagent kit for quality investigations, recall management, and GMP compliance. Sourced from LabVantage LIMS run setup records.',
    `receipt_date` DATE COMMENT 'Date the flow cell was physically received at the Genomics Biotech facility and logged into inventory. Recorded in SAP S/4HANA MM Goods Receipt and LabVantage LIMS. Used to calculate storage duration, validate shelf life, and support FIFO inventory management.',
    `regulatory_use_classification` STRING COMMENT 'Regulatory classification of the flow cell indicating its approved use context: RUO (Research Use Only), IVD (In Vitro Diagnostic), LDT (Laboratory Developed Test), or CE-IVD (Conformité Européenne In Vitro Diagnostic). Determines applicable regulatory requirements, labeling obligations, and permissible clinical use. Critical for FDA, EMA, and IVDR compliance.. Valid values are `RUO|IVD|LDT|CE-IVD`',
    `serial_number` STRING COMMENT 'Manufacturer-assigned unique serial number printed on the physical flow cell cartridge. Used as the primary external identifier for traceability across LabVantage LIMS, Illumina BaseSpace Sequence Hub, and SAP S/4HANA inventory management. Enables one-to-one mapping between the physical consumable and its digital record.',
    `storage_location_code` STRING COMMENT 'Alphanumeric code identifying the physical storage location (e.g., freezer unit, shelf, rack position) where the flow cell is currently stored within the facility. Managed in SAP S/4HANA MM Warehouse Management and LabVantage LIMS. Enables rapid physical retrieval and inventory audits.',
    `storage_temperature_max_c` DECIMAL(18,2) COMMENT 'Maximum allowable storage temperature in degrees Celsius as specified by the manufacturer. Paired with storage_temperature_min_c to define the acceptable cold chain range. Monitored against environmental monitoring system data to ensure GMP-compliant storage conditions.',
    `storage_temperature_min_c` DECIMAL(18,2) COMMENT 'Minimum required storage temperature in degrees Celsius as specified by the manufacturer. Used to validate cold chain compliance during receipt inspection and ongoing storage monitoring. Deviations from this range trigger quarantine and quality investigation workflows.',
    `supplier_lot_certificate_number` STRING COMMENT 'Reference number of the Certificate of Analysis (COA) issued by the supplier for this specific lot. The COA documents manufacturer QC test results confirming the flow cell meets specification. Stored in Veeva Vault for regulatory document management and GMP compliance.',
    `supplier_name` STRING COMMENT 'Name of the external supplier or manufacturer who supplied this flow cell (e.g., Illumina, Inc.). Used for procurement lineage, supplier qualification tracking, and quality management. Linked to the reagent and consumable domain for full procurement traceability.',
    `unit_cost` DECIMAL(18,2) COMMENT 'Actual procurement cost per flow cell unit in the operating currency (USD). Sourced from SAP S/4HANA MM invoice verification. Used for Cost of Goods Sold (COGS) allocation, run cost accounting, and financial reporting. Classified as confidential due to commercial sensitivity of supplier pricing.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the flow cell master record. Tracks status transitions, QC result updates, and any modifications to the record. Required for data lineage, GxP audit trails, and Silver Layer change tracking in the Databricks Lakehouse.',
    CONSTRAINT pk_flow_cell PRIMARY KEY(`flow_cell_id`)
) COMMENT 'Master record for each physical flow cell consumable loaded onto a sequencing instrument. Tracks flow cell serial number, part number, lot number, flow cell type (e.g., S1, S2, S4, SP for NovaSeq; MID, HIGH for NextSeq), number of lanes, cluster density specification, maximum output (Gb), expiry date, storage conditions, receipt date, and current status (in-stock, loaded, consumed, failed). Links to reagent domain for procurement lineage and to sequencing_run for usage tracking.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sequencing`.`library` (
    `library_id` BIGINT COMMENT 'Unique surrogate identifier for the sequencing library record within the Genomics Biotech data platform. Primary key for the library master record. MASTER_RESOURCE role — serves as the SSOT for library identity within the sequencing domain.',
    `access_request_id` BIGINT COMMENT 'Foreign key linking to data.access_request. Business justification: Access requests target specific library datasets for external collaboration or reanalysis - standard data sharing workflow in genomics consortia. Requests track IRB approvals, data use agreements, and',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Libraries prepared for customer samples in service/contract research. Essential for sample ownership tracking, billing, data access control, consent management, and regulatory compliance (PHI/GDPR).',
    `approval_id` BIGINT COMMENT 'Foreign key linking to regulatory.regulatory_approval. Business justification: Libraries used in IVD/clinical workflows must be traceable to the regulatory approval authorizing the assay. Required for 21 CFR Part 820 device history records and ISO 13485 traceability. Genomics la',
    `contact_id` BIGINT COMMENT 'Foreign key linking to customer.contact. Business justification: Sample submitter/technical contact for library-specific communications: QC results, resequencing decisions, consent verification. Critical for customer-facing service labs and regulatory traceability.',
    `container_id` BIGINT COMMENT 'Identifier of the physical plate or rack in which the library is stored. Used for laboratory inventory management, retrieval workflows, and storage location tracking within the LIMS.',
    `employee_id` BIGINT COMMENT 'Reference to the laboratory operator or scientist who performed the library preparation. Supports personnel traceability, training compliance verification, and deviation investigation per GxP and CLIA requirements.',
    `gene_annotation_track_id` BIGINT COMMENT 'Foreign key linking to reference.gene_annotation_track. Business justification: Targeted sequencing libraries (exome capture, gene panels, RNA-seq) are designed against specific gene annotations. This link enables validation that library targets match intended gene coverage and s',
    `gene_model_id` BIGINT COMMENT 'Foreign key linking to reference.gene_model. Business justification: RNA-seq and targeted gene sequencing libraries target specific genes. This link enables gene-level QC, coverage reporting, and validation that library captures intended gene targets for clinical and r',
    `genome_assembly_id` BIGINT COMMENT 'Foreign key linking to reference.genome_assembly. Business justification: Libraries are designed and QCd against specific reference builds. Coverage calculations, target enrichment validation, and variant interpretation require knowing the reference genome. Essential for r',
    `genomic_access_control_id` BIGINT COMMENT 'Foreign key linking to data.genomic_access_control. Business justification: Libraries from consented samples subject to access controls (dbGaP accession, IRB restrictions, data use limitations) - ethical and legal requirement. Controls enforce consent boundaries, publication ',
    `genomic_region_id` BIGINT COMMENT 'Foreign key linking to reference.genomic_region. Business justification: Targeted sequencing libraries are designed to capture specific genomic regions (panels, exomes). This is the core business relationship for panel-based assays - library targets a defined region set fo',
    `index_set_id` BIGINT COMMENT 'Foreign key linking to sequencing.index_set. Business justification: Libraries are assigned index adapters from controlled index sets for multiplexing. library currently has adapter_sequence_i7, adapter_sequence_i5, and udi_plate_id but no FK to index_set. Adding index',
    `library_prep_run_id` BIGINT COMMENT 'Foreign key linking to sequencing.library_prep_run. Business justification: Each library is produced by a specific library preparation run. This is a standard parent-child relationship where library_prep_run is the batch execution entity and library is the output product. Cur',
    `lims_workflow_assignment_id` BIGINT COMMENT 'Foreign key linking to sample.lims_workflow_assignment. Business justification: Library prep is a LIMS-tracked workflow in genomics operations. Linking library to its originating workflow assignment enables SLA tracking, operator accountability, batch quality correlation, and reg',
    `pool_id` BIGINT COMMENT 'Identifier of the multiplexing pool to which this library has been assigned for co-loading onto a flow cell. Enables tracking of pooled libraries, demultiplexing yield analysis, and per-library coverage attribution within a pooled run.',
    `oos_investigation_id` BIGINT COMMENT 'Foreign key linking to quality.oos_investigation. Business justification: Libraries with out-of-specification QC results (concentration out of range, wrong fragment size, high adapter dimer) trigger OOS investigations. Labs link investigations to specific libraries for root',
    `opportunity_id` BIGINT COMMENT 'Foreign key linking to commercial.opportunity. Business justification: Libraries prepared for customer projects must be linked to commercial opportunities for accurate service billing, project costing, and margin analysis. Critical for genomics service providers tracking',
    `original_library_id` BIGINT COMMENT 'Reference to the original library record when this library is a resequencing attempt (resequencing_flag = True). Enables lineage tracking across preparation attempts and supports failure analysis workflows. Null for original preparations.',
    `catalog_item_id` BIGINT COMMENT 'Foreign key linking to product.catalog_item. Business justification: Library prep kits are commercial catalog items. Labs track which kit SKU was used for cost allocation, protocol validation, regulatory compliance, and troubleshooting quality issues. Essential for GxP',
    `project_id` BIGINT COMMENT 'Reference to the research or clinical project under which this library was prepared. Supports project-level tracking, cost allocation, and reporting across the R&D and clinical genomics domains.',
    `qc_result_id` BIGINT COMMENT 'Foreign key linking to quality.qc_result. Business justification: Libraries undergo QC testing (concentration via Qubit/qPCR, fragment size via Bioanalyzer/TapeStation, adapter dimer assessment). Each library has multiple QC results tracked for batch release, troubl',
    `quality_assessment_id` BIGINT COMMENT 'Foreign key linking to data.quality_assessment. Business justification: Libraries assessed for concentration, fragment size, adapter content before sequencing - standard prep QC workflow. Failed assessments trigger reprocessing or rejection, critical for sequencing succes',
    `quality_issue_id` BIGINT COMMENT 'Foreign key linking to data.quality_issue. Business justification: Failed library QC (concentration below threshold, wrong insert size, adapter dimer contamination) triggers quality issue tracking for lab investigation and process improvement - standard LIMS workflow',
    `revenue_recognition_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_recognition. Business justification: Libraries prepared for customer samples in fee-for-service models require linkage to revenue recognition for accurate revenue allocation by performance obligation, contract compliance tracking, and AS',
    `sample_specimen_id` BIGINT COMMENT 'Reference to the biological sample from which this library was prepared. Links the library to its upstream sample management record, enabling traceability from raw specimen through sequencing output.',
    `target_panel_id` BIGINT COMMENT 'Identifier of the capture or amplicon panel used for targeted sequencing libraries (e.g., Illumina TruSight Oncology 500, custom gene panel). Null for WGS/WES libraries. Links to panel design specifications for bioinformatics pipeline configuration.',
    `technical_requirement_id` BIGINT COMMENT 'Foreign key linking to customer.technical_requirement. Business justification: Libraries prepared to meet customer-specified technical requirements (coverage, insert size, prep method). Links library design to customer engagement specifications for acceptance criteria validation',
    `variant_database_id` BIGINT COMMENT 'Foreign key linking to reference.variant_database. Business justification: Clinical sequencing libraries are interpreted against specific variant databases (ClinVar, COSMIC). This link enables tracking which database version was used for clinical interpretation, critical for',
    `basespace_library_code` STRING COMMENT 'External identifier assigned to this library within Illumina BaseSpace Sequence Hub. Enables cross-system traceability between the internal LIMS record and the BaseSpace sequencing data management platform for FASTQ retrieval and run association.',
    `concentration_nm` DECIMAL(18,2) COMMENT 'Measured molar concentration of the library in nanomolar (nM) units. Used for accurate loading onto flow cells and pooling calculations during multiplexing. Sourced from quantification instrument output.',
    `consent_flag` BOOLEAN COMMENT 'Indicates whether valid informed consent has been obtained for the use of the source sample in sequencing and data sharing (True = consent confirmed; False = consent not confirmed or withdrawn). Required for HIPAA, GDPR, and NIH Genomic Data Sharing Policy compliance.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the library record was first created in the system of record. Supports audit trail requirements, TAT calculations, and data lineage tracking. Aligns with FDA 21 CFR Part 11 electronic record requirements.',
    `data_sharing_restricted` BOOLEAN COMMENT 'Indicates whether genomic data derived from this library is subject to data sharing restrictions (True = restricted; False = unrestricted). Restrictions may arise from consent limitations, IRB conditions, contractual obligations, or GDPR/HIPAA data subject rights. Governs downstream data product access controls.',
    `input_dna_mass_ng` DECIMAL(18,2) COMMENT 'Mass of input nucleic acid (DNA or RNA) used for library preparation, measured in nanograms (ng). A key QC parameter — insufficient input mass is a leading cause of library preparation failure and low complexity.',
    `insert_size_bp` STRING COMMENT 'Target or measured average insert size of the library fragments in base pairs (bp). A key MEASUREMENT_OR_VALUE (MASTER_RESOURCE category) for library quality assessment. Impacts read alignment efficiency, coverage uniformity, and variant calling accuracy. Typically 150–500 bp for WGS/WES.',
    `intended_use` STRING COMMENT 'Regulatory classification of the librarys intended use. Determines applicable quality, documentation, and reporting requirements. Values: RUO — Research Use Only; IVD — In Vitro Diagnostic; LDT — Laboratory Developed Test; clinical_trial — use in regulated clinical study; research — internal R&D use.. Valid values are `RUO|IVD|LDT|clinical_trial|research`',
    `is_paired_end` BOOLEAN COMMENT 'Indicates whether the library is designed for paired-end (True) or single-read (False) sequencing. Paired-end sequencing generates two reads per fragment, improving alignment accuracy and structural variant detection. Drives instrument run configuration.',
    `is_pcr_free` BOOLEAN COMMENT 'Indicates whether the library was prepared using a PCR-free protocol (True) or a PCR-amplified protocol (False). PCR-free libraries have lower duplicate rates and reduced GC bias, preferred for high-accuracy WGS applications.',
    `library_code` STRING COMMENT 'Externally-known, human-readable unique identifier for the sequencing library, used in LIMS, BaseSpace, and laboratory documentation. Follows the internal naming convention LIB-{alphanumeric}. This is the BUSINESS_IDENTIFIER (MASTER_RESOURCE category) used across operational systems.. Valid values are `^LIB-[A-Z0-9]{6,20}$`',
    `library_name` STRING COMMENT 'Human-readable descriptive name assigned to the sequencing library, typically incorporating sample identifier, preparation date, and assay type. Used as the IDENTITY_LABEL (MASTER_RESOURCE category) for display in LIMS dashboards, BaseSpace projects, and laboratory reports.',
    `library_type` STRING COMMENT 'Classification of the sequencing library by assay strategy. Drives downstream bioinformatics pipeline selection, coverage expectations, and reporting templates. CLASSIFICATION_OR_TYPE (MASTER_RESOURCE category). [ENUM-REF-CANDIDATE: WGS|WES|amplicon|RNA-seq|targeted_panel|methylation|ChIP-seq|ATAC-seq|single_cell — promote to reference product]. Valid values are `WGS|WES|amplicon|RNA-seq|targeted_panel|methylation`',
    `lims_library_code` STRING COMMENT 'Native identifier for this library record within LabVantage LIMS. Supports bidirectional reconciliation between the Silver Layer data product and the operational LIMS system of record for audit and data lineage purposes.',
    `nucleic_acid_type` STRING COMMENT 'Type of nucleic acid used as input for library preparation. Drives protocol selection, QC thresholds, and bioinformatics pipeline configuration. Values: gDNA — genomic DNA; cfDNA — cell-free DNA (liquid biopsy); RNA — total or mRNA; cDNA — complementary DNA; FFPE_DNA — formalin-fixed paraffin-embedded DNA; amplicon_DNA — pre-amplified target DNA.. Valid values are `gDNA|cfDNA|RNA|cDNA|FFPE_DNA|amplicon_DNA`',
    `pcr_cycle_count` STRING COMMENT 'Number of PCR amplification cycles applied during library preparation. Impacts PCR duplicate rate, GC bias, and library complexity. PCR-free libraries have a value of 0. Tracked for QC benchmarking and protocol optimization.',
    `pooling_proportion_pct` DECIMAL(18,2) COMMENT 'Percentage contribution of this library to the total multiplexing pool by molar concentration. Used to balance per-library coverage in multiplexed sequencing runs and to investigate coverage imbalance post-sequencing.',
    `prep_date` DATE COMMENT 'Calendar date on which the library preparation protocol was completed. Used for lot traceability, reagent expiry correlation, and turnaround time (TAT) calculations. Aligns with GxP batch record requirements.',
    `qc_failure_reason` STRING COMMENT 'Free-text or coded description of the reason for QC failure when qc_status is fail or conditional_pass. Supports root-cause analysis, protocol improvement, and regulatory deviation reporting. Null when qc_status is pass or pending.',
    `qc_status` STRING COMMENT 'Current quality control disposition of the library. Determines whether the library is eligible for sequencing run loading. LIFECYCLE_STATUS (MASTER_RESOURCE category). Values: pass — meets all QC thresholds; fail — does not meet thresholds; pending — QC not yet completed; conditional_pass — meets minimum thresholds with caveats; requeue — failed and scheduled for re-preparation.. Valid values are `pass|fail|pending|conditional_pass|requeue`',
    `quantification_method` STRING COMMENT 'Analytical method used to measure library concentration and/or size distribution. Affects confidence in concentration accuracy and downstream loading calculations. Common methods: qPCR (most accurate for sequenceable molecules), Bioanalyzer/TapeStation (size + concentration), Qubit (fluorometric mass concentration).. Valid values are `qPCR|Bioanalyzer|Qubit|TapeStation|ddPCR|fluorometry`',
    `resequencing_flag` BOOLEAN COMMENT 'Indicates whether this library was prepared as a resequencing attempt for a previously failed or insufficient-coverage library (True = resequencing; False = original preparation). Supports TAT tracking, cost analysis, and failure rate reporting.',
    `storage_temperature_c` DECIMAL(18,2) COMMENT 'Required or actual storage temperature for the library in degrees Celsius (e.g., -20°C for long-term, 4°C for short-term). Supports cold chain compliance, stability monitoring, and deviation investigation.',
    `storage_well_position` STRING COMMENT 'Well position (e.g., A01, H12) within the storage plate where the library aliquot is located. Combined with storage_plate_id, provides precise physical location for laboratory retrieval and inventory audits.. Valid values are `^[A-H][0-9]{1,2}$`',
    `strand_specificity` STRING COMMENT 'Indicates whether the library preserves strand-of-origin information for RNA-seq or other strand-aware assays. Values: unstranded — no strand information retained; forward — read 1 maps to sense strand; reverse — read 1 maps to antisense strand. Required for correct transcript quantification in RNA-seq pipelines.. Valid values are `unstranded|forward|reverse`',
    `target_coverage_depth` STRING COMMENT 'Intended sequencing coverage depth (read depth) for this library, expressed as fold-coverage (e.g., 30x for WGS, 100x for WES, 500x for targeted panels). Drives sequencing run planning, flow cell loading calculations, and QC pass/fail thresholds.',
    `target_read_length` STRING COMMENT 'Intended sequencing read length in base pairs (e.g., 150 bp for paired-end short-read WGS). Determines sequencing run configuration, instrument chemistry selection, and bioinformatics pipeline parameters.',
    `udi_plate_code` STRING COMMENT 'Identifier of the unique dual index (UDI) plate from which the index pair was assigned. Enables traceability of index assignments across batches and supports investigation of index hopping or cross-contamination events.',
    `udi_well_position` STRING COMMENT 'Well position (e.g., A01, B12) on the UDI plate from which the index pair was drawn. Together with udi_plate_id, uniquely identifies the index assignment for demultiplexing and audit purposes.. Valid values are `^[A-H][0-9]{1,2}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the library record. Supports change tracking, audit trail completeness, and Silver Layer incremental load processing. Aligns with FDA 21 CFR Part 11 electronic record requirements.',
    `volume_remaining_ul` DECIMAL(18,2) COMMENT 'Current volume of library material remaining in storage, measured in microliters (µL). Tracks consumable inventory for re-sequencing eligibility and storage management. Updated after each aliquot event.',
    CONSTRAINT pk_library PRIMARY KEY(`library_id`)
) COMMENT 'Master record representing a prepared sequencing library — the biochemically processed form of a biological sample ready for loading onto a flow cell. Captures library identity, source sample reference (FK to sample domain), preparation protocol and kit, insert size (bp), concentration (nM), quantification method (qPCR, Bioanalyzer, Qubit), library type (WGS, WES, amplicon, RNA-seq, ChIP-seq, targeted panel, methylation), adapter sequences, unique dual index (UDI) assignment, strand specificity, preparation date, operator, QC status (pass/fail/pending), volume remaining (µL), and storage location (plate/well). SSOT for library identity within the sequencing domain — the central entity linking sample preparation to sequencing output and the primary unit of work for coverage tracking.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sequencing`.`library_prep_run` (
    `library_prep_run_id` BIGINT COMMENT 'Unique surrogate identifier for the library preparation run record in the Databricks Silver Layer. Primary key. Entity role: TRANSACTION_HEADER — captures a discrete batch execution event with a full lifecycle from initiation through QC disposition.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Library prep services performed for customer accounts. Essential for service delivery tracking, billing, batch-level customer segregation, and GxP compliance in regulated service environments.',
    `asset_id` BIGINT COMMENT 'Identifier of the liquid handling instrument or automated workstation (e.g., Hamilton, Beckman Coulter) used to execute the library preparation run. Supports instrument qualification tracking, preventive maintenance scheduling, and GxP equipment traceability.',
    `audit_id` BIGINT COMMENT 'Foreign key linking to quality.audit. Business justification: Library prep runs are audited for GxP compliance, protocol adherence, documentation completeness, and reagent traceability. Auditors link findings to specific prep runs for corrective action tracking.',
    `batch_id` BIGINT COMMENT 'Foreign key linking to supply.batch. Business justification: Library prep kits are batch-managed. Link enables GMP traceability, QC correlation (prep failures to kit lots), recall management, and expiry tracking. Critical for regulated workflows. Removes denorm',
    `capa_id` BIGINT COMMENT 'Foreign key linking to quality.capa. Business justification: Systematic library prep issues (adapter dimer problems, low yield trends, contamination patterns) trigger CAPAs. Labs link prep runs to CAPAs for root cause analysis, process improvement, and effectiv',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Library prep runs are resource-intensive activities requiring cost center assignment for activity-based costing, departmental budget management, and R&D capitalization eligibility assessment. Essentia',
    `deviation_id` BIGINT COMMENT 'Foreign key linking to quality.quality_deviation. Business justification: Library prep runs can deviate from protocol (wrong reagent lot, temperature excursion, contamination). GxP labs track prep run deviations for batch disposition, investigation, and CAPA initiation. Sta',
    `experiment_id` BIGINT COMMENT 'Foreign key linking to research.experiment. Business justification: Library prep runs prepare samples for specific experiments. Linking enables experiment-level cost tracking (reagent/labor allocation), protocol compliance verification for GxP experiments, and traceab',
    `genome_assembly_id` BIGINT COMMENT 'Foreign key linking to reference.genome_assembly. Business justification: Prep protocols specify target regions defined in reference coordinates. QC metrics like on-target rate and size selection validation require reference genome context for protocol validation and optimi',
    `installed_instrument_id` BIGINT COMMENT 'Foreign key linking to customer.installed_instrument. Business justification: Library prep performed on customer-installed automation instruments. Tracks utilization, service delivery, and instrument-specific performance for customer-site operations.',
    `internal_order_id` BIGINT COMMENT 'Foreign key linking to finance.internal_order. Business justification: Library prep activities often support specific R&D projects tracked via internal orders for accurate project cost accumulation, capitalization eligibility assessment, and budget variance analysis. Sta',
    `catalog_item_id` BIGINT COMMENT 'Foreign key linking to product.catalog_item. Business justification: Library prep runs consume specific kit catalog items. Essential for batch cost tracking, lot-to-lot performance analysis, regulatory traceability, and quality investigations when prep runs fail QC.',
    `lot_id` BIGINT COMMENT 'Identifier of the reagent kit lot used in this library preparation run. Enables reagent lot traceability, recall management, and correlation of kit lot performance with QC outcomes.',
    `production_batch_id` BIGINT COMMENT 'Foreign key linking to manufacturing.production_batch. Business justification: Links library prep runs to specific manufactured kit batches for root cause analysis. When multiple prep runs from same batch fail QC, triggers manufacturing investigation and potential batch recall. ',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to manufacturing.work_order. Business justification: Library prep kits manufactured in-house require full traceability from prep run to manufacturing work order. When library prep QC fails (adapter dimer >5%, wrong insert size), manufacturing must inves',
    `material_id` BIGINT COMMENT 'Foreign key linking to supply.material. Business justification: Library prep kits are materials. Link enables inventory tracking, demand planning based on prep run forecasts, MRP triggers, and integration with supply chain for automated reordering and stock manage',
    `opportunity_id` BIGINT COMMENT 'Foreign key linking to commercial.opportunity. Business justification: Library prep runs executed for customer projects require opportunity linkage for service billing, resource allocation tracking, and project profitability analysis. Standard practice in genomics servic',
    `employee_id` BIGINT COMMENT 'Identifier of the laboratory scientist or technician who executed the library preparation run. Links to the workforce/personnel master for GxP operator qualification tracking and audit trail. Satisfies TRANSACTION_HEADER PARTY_REFERENCE category.',
    `project_id` BIGINT COMMENT 'Identifier of the research or clinical project to which this library preparation run is attributed. Enables project-level cost allocation, throughput reporting, and cross-run traceability within Benchling or the LIMS project hierarchy.',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to supply.purchase_order. Business justification: Library prep runs consume purchased kits. Link enables cost allocation to projects, supplier quality tracking when prep failures occur, and GMP documentation of material sources for regulated workflow',
    `quality_assessment_id` BIGINT COMMENT 'Foreign key linking to data.quality_assessment. Business justification: Library prep runs assessed for adapter dimer percentage, fragment size distribution, yield against protocol specifications - batch release requirement in GxP environments. Failed assessments prevent d',
    `quality_issue_id` BIGINT COMMENT 'Foreign key linking to data.quality_issue. Business justification: Library prep run failures (kit lot defects, instrument errors, protocol deviations) logged as quality issues for manufacturing QC and CAPA - GxP requirement. Issues trigger investigations, supplier no',
    `research_protocol_id` BIGINT COMMENT 'Identifier of the standard operating procedure (SOP) or library preparation protocol document used for this run. Links to the document control system (MasterControl/Veeva Vault) for version-controlled protocol traceability.',
    `service_agreement_id` BIGINT COMMENT 'Foreign key linking to customer.service_agreement. Business justification: Library prep services governed by service agreements defining turnaround time, QC standards, pricing. Critical for SLA compliance verification and contract-specific protocol adherence.',
    `supplier_id` BIGINT COMMENT 'Foreign key linking to supply.supplier. Business justification: Library prep kit supplier tracking. Enables supplier performance evaluation based on prep run outcomes (QC failures, adapter dimer rates), quality investigations, and supplier scorecarding for procure',
    `validation_study_id` BIGINT COMMENT 'Foreign key linking to quality.validation_study. Business justification: Library prep runs are used in validation studies (kit validation, protocol verification, robustness testing). Labs track which prep runs contributed to validation data for regulatory documentation and',
    `adapter_dimer_pct` DECIMAL(18,2) COMMENT 'Percentage of adapter dimer contamination detected in the final library by electrophoresis (Bioanalyzer/TapeStation). High adapter dimer content reduces effective sequencing yield and is a key QC failure indicator. Typically must be below 5% for pass disposition.',
    `adapter_ligation_method` STRING COMMENT 'Method used to ligate sequencing adapters to the end-repaired DNA fragments. Tagmentation (Nextera) combines fragmentation and adapter ligation in a single step. Affects ligation efficiency, adapter dimer formation rate, and overall library yield.. Valid values are `T4_ligase|quick_ligase|tagmentation|ligation_free`',
    `approval_timestamp` TIMESTAMP COMMENT 'Date and time when the library preparation run record received formal QA/supervisor approval. Distinct from run completion timestamp. Required for GxP electronic record compliance and regulatory audit trail.',
    `basespace_run_code` STRING COMMENT 'Run identifier assigned by Illumina BaseSpace Sequence Hub for the downstream sequencing run associated with this library preparation batch. Enables end-to-end traceability from library preparation through raw data generation and FASTQ output.',
    `batch_qc_outcome` STRING COMMENT 'Overall quality control disposition for the library preparation run batch. Determines whether the batch is approved for sequencing submission. A conditional pass may require additional review or re-quantification before proceeding.. Valid values are `pass|fail|conditional_pass|pending_review`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this library preparation run record was first created in the source LIMS system. Supports GxP audit trail and data lineage requirements. Satisfies TRANSACTION_HEADER RECORD_AUDIT_CREATED category.',
    `deviation_description` STRING COMMENT 'Free-text description of any deviation from the approved SOP observed during this library preparation run. Populated only when sop_deviation_flag is True. Supports GxP deviation management, CAPA (Corrective and Preventive Action) initiation, and regulatory audit readiness.',
    `end_repair_performed` BOOLEAN COMMENT 'Indicates whether an end-repair and A-tailing step was performed on the fragmented DNA prior to adapter ligation. End repair is required for blunt-end ligation protocols but may be skipped in tagmentation-based workflows.',
    `end_timestamp` TIMESTAMP COMMENT 'Date and time when the library preparation run was completed or terminated. Used in conjunction with start_timestamp to compute total run duration and TAT metrics. Nullable if run is still in progress.',
    `final_library_concentration_nm` DECIMAL(18,2) COMMENT 'Measured concentration of the final pooled library in nanomolar (nM), typically quantified by qPCR or fluorometric assay (e.g., Qubit). Used to calculate the dilution factor for optimal flow cell loading and to assess library yield.',
    `final_pooling_volume_ul` DECIMAL(18,2) COMMENT 'Total volume in microliters (µL) of the final pooled library submitted for sequencing. Used to calculate loading concentration for the flow cell and to assess library yield sufficiency for sequencing.',
    `fragmentation_method` STRING COMMENT 'DNA/RNA fragmentation approach applied during library preparation. Enzymatic fragmentation uses restriction enzymes or transposases (e.g., Nextera); mechanical fragmentation uses sonication or acoustic shearing (e.g., Covaris). Affects insert size distribution and library quality metrics.. Valid values are `enzymatic|mechanical|chemical|none`',
    `index_collision_check_passed` BOOLEAN COMMENT 'Indicates whether the selected multiplexing index combinations were verified to have sufficient Hamming distance to prevent index hopping or misassignment during demultiplexing. A failed check requires index reassignment before sequencing.',
    `input_dna_amount_ng` DECIMAL(18,2) COMMENT 'Total mass of input DNA or RNA (in nanograms) used per sample in this library preparation run. Critical QC parameter — insufficient input material is a leading cause of library preparation failure and low-complexity libraries.',
    `input_material_type` STRING COMMENT 'Type of nucleic acid input material used for library preparation (e.g., genomic DNA (gDNA), cell-free DNA (cfDNA), RNA, formalin-fixed paraffin-embedded (FFPE) DNA). Determines applicable protocol, QC acceptance criteria, and downstream analytical interpretation.. Valid values are `gDNA|cfDNA|RNA|FFPE_DNA|FFPE_RNA|amplicon`',
    `library_type` STRING COMMENT 'Classification of the sequencing library type prepared in this run. Determines downstream bioinformatics pipeline selection, QC thresholds, and sequencing parameters. Examples: Whole Genome Sequencing (WGS), Whole Exome Sequencing (WES), targeted panel, RNA-seq. [ENUM-REF-CANDIDATE: WGS|WES|targeted|RNA-seq|amplicon|ChIP-seq|ATAC-seq|other — promote to reference product]',
    `lims_run_code` STRING COMMENT 'Native run identifier assigned by the source LabVantage LIMS system. Preserved as a cross-reference key to enable bidirectional traceability between the Databricks Silver Layer and the operational LIMS without relying solely on the surrogate primary key.',
    `mean_fragment_size_bp` STRING COMMENT 'Measured mean fragment size in base pairs (bp) of the final library as determined by Bioanalyzer, TapeStation, or equivalent electrophoresis instrument. Compared against target_insert_size_bp to assess size selection success and protocol adherence.',
    `multiplexing_index_set` STRING COMMENT 'Name or identifier of the index/barcode set used for sample multiplexing in this library preparation run (e.g., Illumina TruSeq CD Index Set A, IDT for Illumina 10 bp UDI). Enables demultiplexing of pooled samples post-sequencing and prevents index collision errors.',
    `pcr_amplification_cycles` STRING COMMENT 'Number of PCR amplification cycles applied during library preparation. Excessive PCR cycles introduce duplicate reads and GC bias, reducing library complexity. Zero cycles indicates a PCR-free protocol. Key parameter for library quality assessment and protocol compliance.',
    `protocol_version` STRING COMMENT 'Version identifier of the library preparation SOP or protocol document applied during this run (e.g., v2.1.0). Critical for GxP compliance to confirm the correct, approved protocol version was followed and to detect protocol drift across runs.. Valid values are `^v[0-9]+.[0-9]+(.[0-9]+)?$`',
    `qc_method` STRING COMMENT 'Analytical method used to quantify and assess library quality (e.g., qPCR for accurate molar quantification, Qubit fluorometry for mass concentration, Bioanalyzer/TapeStation for fragment size distribution). Affects the reliability of concentration measurements and QC pass/fail decisions.. Valid values are `qPCR|Qubit|Bioanalyzer|TapeStation|BioRad_ddPCR`',
    `run_code` STRING COMMENT 'Human-readable, externally-known business identifier for the library preparation run, typically generated by the LIMS (e.g., LP-NGSA-240315). Used for cross-system traceability, SOP deviation tracking, and GxP audit references. Satisfies TRANSACTION_HEADER BUSINESS_IDENTIFIER category.. Valid values are `^LP-[A-Z0-9]{4,12}-[0-9]{6}$`',
    `run_notes` STRING COMMENT 'Free-text field for operator observations, troubleshooting notes, or contextual comments recorded during or after the library preparation run. Supplements structured deviation documentation and supports root cause analysis.',
    `run_status` STRING COMMENT 'Current lifecycle state of the library preparation run. Drives workflow routing, QC gating, and downstream sequencing scheduling. Satisfies TRANSACTION_HEADER LIFECYCLE_STATUS category. [ENUM-REF-CANDIDATE: pending|in_progress|completed|failed|cancelled|on_hold — promote to reference product]. Valid values are `pending|in_progress|completed|failed|cancelled|on_hold`',
    `sample_count` STRING COMMENT 'Total number of biological samples processed in this library preparation run batch. Used for capacity planning, throughput reporting, and cost-per-sample calculations. Represents the principal quantitative result of this transaction.',
    `size_selection_method` STRING COMMENT 'Method used to select the target insert size range from the library pool (e.g., SPRI bead-based cleanup, gel excision, Pippin Prep automated electrophoresis). Size selection removes adapter dimers and off-target fragments, improving sequencing efficiency.. Valid values are `SPRI_beads|gel_excision|pippin_prep|none`',
    `sop_deviation_flag` BOOLEAN COMMENT 'Indicates whether any deviation from the approved standard operating procedure (SOP) was recorded during this library preparation run. A True value triggers mandatory deviation documentation and review per GxP requirements.',
    `start_timestamp` TIMESTAMP COMMENT 'Date and time when the library preparation run was physically initiated in the laboratory. Represents the principal real-world business event time. Used for turnaround time (TAT) calculation and GxP audit trails. Satisfies TRANSACTION_HEADER BUSINESS_EVENT_TIMESTAMP category.',
    `target_insert_size_bp` STRING COMMENT 'Intended DNA insert size in base pairs (bp) for the prepared library, as specified by the protocol. Insert size directly impacts sequencing read overlap, coverage uniformity, and variant calling accuracy. Typical ranges: 150–400 bp for short-read NGS.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this library preparation run record. Enables change detection, incremental data loading, and GxP audit trail compliance. Satisfies TRANSACTION_HEADER RECORD_AUDIT_UPDATED category.',
    `use_type` STRING COMMENT 'Regulatory use classification of the library preparation run. Research Use Only (RUO) runs are not subject to IVD regulatory controls; In Vitro Diagnostic (IVD) and Laboratory Developed Test (LDT) runs require CLIA/CAP compliance and stricter QC documentation. Drives applicable regulatory requirements.. Valid values are `RUO|IVD|LDT|GMP|research`',
    `workgroup_code` BIGINT COMMENT 'Identifier of the laboratory workgroup or team responsible for executing this library preparation run. Supports capacity planning, workload balancing, and team-level performance reporting.',
    CONSTRAINT pk_library_prep_run PRIMARY KEY(`library_prep_run_id`)
) COMMENT 'Transactional record capturing the execution of a library preparation workflow batch. Tracks prep run ID, protocol version, kit lot number, number of samples processed, start/end timestamps, operator, instrument used (e.g., liquid handler), fragmentation method (enzymatic, mechanical), end-repair and adapter ligation steps, PCR amplification cycles, final pooling volume, batch QC outcome, and any deviations from SOP. Enables traceability from raw sample to sequencing-ready library and supports GxP audit requirements.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sequencing`.`pool` (
    `pool_id` BIGINT COMMENT 'Unique system-generated identifier for the multiplexed library pool record. Primary key for the pool entity in the sequencing domain.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Pooling services for customer samples in multiplexed sequencing. Tracks service delivery, billing, and customer-specific pooling strategies. Essential for multi-customer pool segregation and data acce',
    `asset_id` BIGINT COMMENT 'Reference to the sequencing instrument (e.g., Illumina NovaSeq, NextSeq) onto which this pool is intended to be loaded.',
    `employee_id` BIGINT COMMENT 'Reference to the laboratory operator or scientist who performed the pooling procedure.',
    `flow_cell_id` BIGINT COMMENT 'Reference to the specific flow cell onto which this pool will be or has been loaded for sequencing.',
    `genome_assembly_id` BIGINT COMMENT 'Foreign key linking to reference.genome_assembly. Business justification: Pooling strategies and expected coverage calculations are reference-build specific, especially for targeted panels. Enables pool-level QC validation and coverage planning against reference coordinates',
    `genomic_region_id` BIGINT COMMENT 'Foreign key linking to reference.genomic_region. Business justification: Pools of targeted libraries share common target regions. This enables pooling strategy validation, coverage planning, and verification that all libraries in pool target compatible genomic regions for ',
    `index_set_id` BIGINT COMMENT 'Foreign key linking to sequencing.index_set. Business justification: Pools use specific index sets for multiplexing libraries. pool currently has index_type (string) but no FK to the index_set reference master. Adding index_set_id formalizes the relationship to the con',
    `oos_investigation_id` BIGINT COMMENT 'Foreign key linking to quality.oos_investigation. Business justification: Pools with OOS QC results (concentration deviation, fragment size out of range, index imbalance) trigger OOS investigations. Labs track which pool triggered each investigation for root cause analysis ',
    `parent_pool_id` BIGINT COMMENT 'Reference to the original pool from which this re-pool was derived, when is_repool is True. Enables lineage tracking and root cause analysis for failed pools.',
    `project_id` BIGINT COMMENT 'Reference to the research or clinical project under which this pool was created. Links the pool to project-level objectives, funding, and reporting requirements.',
    `qc_result_id` BIGINT COMMENT 'Foreign key linking to quality.qc_result. Business justification: Pools undergo QC testing (concentration, fragment size, index balance, PhiX spike-in verification) before sequencing. QC results determine pool disposition, loading concentration adjustments, and repr',
    `catalog_item_id` BIGINT COMMENT 'Foreign key linking to product.catalog_item. Business justification: Pooling operations use reagents/normalization kits that are catalog items. Needed for cost accounting, protocol compliance, and tracking which commercial products were used for library normalization a',
    `basespace_pool_code` STRING COMMENT 'External identifier assigned to this pool within Illumina BaseSpace Sequence Hub. Used for cross-system traceability between the internal LIMS and the BaseSpace sequencing data management platform.',
    `concentration_method` STRING COMMENT 'Analytical method used to measure the pool concentration. Qubit and qPCR are preferred for accurate molar quantification; Bioanalyzer and TapeStation provide both concentration and fragment size data.. Valid values are `qubit|qpcr|bioanalyzer|tapestation|nanodrop`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the pool record was first created in the system. Used for audit trail, data lineage, and regulatory traceability.',
    `expiry_date` DATE COMMENT 'Date after which the pool is considered expired and should not be loaded onto the sequencer. Determined by the stability window of the pooled libraries under specified storage conditions.',
    `final_concentration_nm` DECIMAL(18,2) COMMENT 'Measured molar concentration of the pool in nanomolar (nM) after pooling, as determined by Qubit fluorometry or qPCR quantification. Used to calculate dilution for loading concentration.',
    `flow_cell_lane` STRING COMMENT 'Specific lane(s) on the flow cell to which this pool is assigned for loading. A pool may occupy a single lane or the entire flow cell depending on the instrument type and run design.',
    `fragment_size_lower_bp` STRING COMMENT 'Lower bound of the acceptable fragment size distribution range in base pairs (bp) for this pool, as defined by the QC specification. Fragments below this threshold indicate adapter contamination or over-fragmentation.',
    `fragment_size_method` STRING COMMENT 'Instrument or method used to assess the fragment size distribution of the pool (e.g., Agilent Bioanalyzer, Agilent TapeStation, Advanced Analytical Fragment Analyzer, or gel electrophoresis).. Valid values are `bioanalyzer|tapestation|fragment_analyzer|gel_electrophoresis`',
    `fragment_size_upper_bp` STRING COMMENT 'Upper bound of the acceptable fragment size distribution range in base pairs (bp) for this pool. Fragments above this threshold may indicate incomplete fragmentation or genomic DNA contamination.',
    `index_collision_risk` STRING COMMENT 'Assessed risk level of index sequence collision (cross-contamination between demultiplexed samples) within this pool, based on Hamming distance analysis of the index set. Low risk indicates sufficient edit distance between all index pairs.. Valid values are `low|medium|high`',
    `is_repool` BOOLEAN COMMENT 'Indicates whether this pool is a re-pool created to replace or supplement a previously failed or underperforming pool (True = re-pool, False = original pool). Used for tracking remediation events.',
    `library_count` STRING COMMENT 'Total number of individually indexed libraries combined into this pool. Determines the degree of multiplexing and directly impacts per-library read depth allocation.',
    `lims_pool_code` STRING COMMENT 'Native pool identifier from LabVantage LIMS, used for cross-system reconciliation between the enterprise data lakehouse and the operational LIMS source system.',
    `loading_concentration_pm` DECIMAL(18,2) COMMENT 'Target loading concentration of the diluted pool in picomolar (pM) for the specific instrument and flow cell type. Directly impacts cluster density and sequencing quality.',
    `lot_number` STRING COMMENT 'Lot number of the pooling reagents or library preparation kit used to create this pool. Enables traceability to reagent lots for root cause analysis and regulatory compliance.',
    `mean_fragment_size_bp` STRING COMMENT 'Mean insert fragment size of the pool in base pairs (bp) as measured by Bioanalyzer or TapeStation electrophoresis. Critical for assessing library quality and estimating molar concentration.',
    `notes` STRING COMMENT 'Free-text field for laboratory scientists to record observations, deviations, or special handling instructions associated with this pool that are not captured in structured fields.',
    `phix_spike_in_pct` DECIMAL(18,2) COMMENT 'Percentage of PhiX Control library spiked into the pool prior to sequencing. PhiX is used as an internal sequencing quality control to monitor cluster density, error rate, and base calling performance.',
    `pool_code` STRING COMMENT 'Human-readable, externally-known unique alphanumeric code assigned to the pool for tracking across LIMS, BaseSpace, and laboratory worksheets. Used as the business identifier on COAs and run manifests.. Valid values are `^POOL-[A-Z0-9]{6,20}$`',
    `pool_name` STRING COMMENT 'Descriptive human-readable name assigned to the pool, typically encoding project, date, and cohort information for easy identification in run planning and reporting.',
    `pool_status` STRING COMMENT 'Current lifecycle status of the pool. Tracks progression from initial creation through QC verification, loading onto the sequencer, sequencing completion, or expiry. [ENUM-REF-CANDIDATE: pending|qc_in_progress|qc_passed|qc_failed|loaded|sequenced|expired — promote to reference product]',
    `pooling_date` DATE COMMENT 'Calendar date on which the individual libraries were combined to form this pool. Used for traceability, stability window calculation, and laboratory scheduling.',
    `pooling_strategy` STRING COMMENT 'Method used to combine individual indexed libraries into the pool. Equimolar pools combine equal molar quantities; custom ratio pools use user-defined proportions; normalized pools use concentration normalization prior to combining; volume-based pools combine equal volumes.. Valid values are `equimolar|custom_ratio|normalized|volume_based`',
    `protocol_version` STRING COMMENT 'Version identifier of the Standard Operating Procedure (SOP) or laboratory protocol used to perform the pooling procedure. Ensures reproducibility and regulatory traceability.',
    `qc_concentration_passed` BOOLEAN COMMENT 'Indicates whether the pool passed the concentration QC threshold check (True = passed, False = failed). A pool must pass concentration QC before it is eligible for loading onto the sequencer.',
    `qc_date` DATE COMMENT 'Date on which QC measurements (concentration and fragment size) were performed on the pool. May differ from pooling date if QC is conducted on a subsequent day.',
    `qc_failure_reason` STRING COMMENT 'Free-text or coded description of the reason(s) for QC failure when qc_overall_passed is False. Used for root cause analysis, CAPA initiation, and laboratory troubleshooting.',
    `qc_fragment_size_passed` BOOLEAN COMMENT 'Indicates whether the pool passed the fragment size distribution QC check (True = passed, False = failed). Ensures the pools insert size profile is within acceptable bounds for the target sequencing application.',
    `qc_overall_passed` BOOLEAN COMMENT 'Composite QC pass/fail flag indicating whether the pool has passed all required QC checks (concentration and fragment size) and is approved for sequencer loading. True = all QC checks passed.',
    `run_type` STRING COMMENT 'Intended use classification of the sequencing run for which this pool is prepared. RUO (Research Use Only) pools are not subject to clinical regulatory requirements; IVD and LDT pools require CLIA/CAP compliance.. Valid values are `research_use_only|clinical_validation|ivd|ldt`',
    `sequencing_application` STRING COMMENT 'Genomic sequencing application type for which this pool was prepared. Determines bioinformatics pipeline routing, QC thresholds, and coverage requirements. [ENUM-REF-CANDIDATE: wgs|wes|targeted_panel|amplicon|rna_seq|chip_seq|atac_seq|methyl_seq — promote to reference product]',
    `storage_location` STRING COMMENT 'Physical storage location identifier (freezer, rack, box, position) where the pool is stored in the laboratory. Used for sample retrieval and inventory management within LIMS.',
    `storage_temperature_c` DECIMAL(18,2) COMMENT 'Required storage temperature in degrees Celsius for maintaining pool stability and integrity. Typically -20°C for long-term storage or 4°C for short-term use.',
    `target_read_depth` STRING COMMENT 'Expected average sequencing read depth (coverage depth) per library within the pool, expressed as number of reads. Used for run planning, yield allocation, and per-sample coverage estimation.',
    `target_read_length` STRING COMMENT 'Intended sequencing read length in base pairs (bp) for this pool (e.g., 150 bp paired-end). Determines the sequencing run configuration and impacts data output volume.',
    `total_volume_ul` DECIMAL(18,2) COMMENT 'Total volume of the combined pool in microlitres (µL) after all libraries have been pooled. Used to assess whether sufficient material exists for loading and archival.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the pool record. Used for change tracking, audit trail compliance, and data synchronization between source systems and the lakehouse.',
    CONSTRAINT pk_pool PRIMARY KEY(`pool_id`)
) COMMENT 'Master record for a multiplexed pool of indexed libraries combined for co-sequencing on a single flow cell lane or entire flow cell. Captures pool identity, pooling strategy (equimolar, custom ratio, normalized), number of constituent libraries, total volume (µL), final concentration (nM), loading concentration for the target instrument and flow cell type, pooling date, operator, pool QC status (concentration verification via Qubit/qPCR, fragment size distribution via Bioanalyzer/TapeStation), expected per-library read depth targets, and pool expiry/stability window. Central to multiplexing operations — the pool is what physically gets loaded onto the sequencer and determines per-sample yield allocation.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sequencing`.`pool_library` (
    `pool_library_id` BIGINT COMMENT 'Unique surrogate identifier for the pool-library association record. Primary key for this junction entity linking a sequencing library to a pool.',
    `employee_id` BIGINT COMMENT 'Reference to the laboratory operator or scientist who performed the physical pooling of this library. Supports GxP audit trail and personnel accountability requirements.',
    `index_set_id` BIGINT COMMENT 'Foreign key linking to sequencing.index_set. Business justification: pool_library tracks individual library assignments within pools with their specific index sequences. Currently has index_kit_name (string) and index sequences but no FK to index_set. Adding index_set_',
    `library_id` BIGINT COMMENT 'Reference to the sequencing library that has been assigned to this pool. Enables reconstruction of which library contributed reads in a pooled run.',
    `pool_id` BIGINT COMMENT 'Reference to the sequencing pool to which this library has been assigned. Supports demultiplexing traceability back to the originating pool.',
    `actual_molar_fraction_pct` DECIMAL(18,2) COMMENT 'The measured proportion (%) of this librarys molar contribution in the final pool, determined by qPCR or fluorometric quantification. Deviations from expected fraction indicate pipetting or quantification errors.',
    `assigned_read_count` BIGINT COMMENT 'Total number of sequencing reads successfully demultiplexed and assigned to this library from the pool run. Populated post-sequencing from demultiplexing output (e.g., bcl2fastq/BCL Convert reports). Used to assess yield per library.',
    `assigned_read_fraction_pct` DECIMAL(18,2) COMMENT 'Percentage of total pool reads assigned to this library after demultiplexing. Compared against expected molar fraction to assess pooling balance and identify over- or under-represented libraries.',
    `assigned_timestamp` TIMESTAMP COMMENT 'Precise date and time (ISO 8601 with timezone) when this library was assigned to the pool in the LIMS or BaseSpace Sequence Hub. Serves as the primary business event timestamp for this junction record.',
    `assignment_status` STRING COMMENT 'Current lifecycle status of the library-to-pool assignment. Tracks whether the library is pending confirmation, actively loaded, failed QC, or removed from the pool.. Valid values are `pending|active|loaded|failed|removed|cancelled`',
    `basespace_dataset_code` STRING COMMENT 'Identifier of the FASTQ dataset generated for this library in Illumina BaseSpace Sequence Hub following demultiplexing. Links the pool-library assignment to the resulting sequencing data artifact for downstream bioinformatics pipeline ingestion.',
    `cluster_density` DECIMAL(18,2) COMMENT 'Cluster density (in thousands per mm²) on the flow cell lane attributable to this librarys loading contribution. Excessively high or low cluster density impacts sequencing quality and read assignment accuracy.',
    `demultiplex_mismatch_allowed` STRING COMMENT 'Number of base mismatches permitted during demultiplexing for this librarys index sequence. Typically 0 or 1. Higher values increase sensitivity but risk misassignment between similar indexes.',
    `expected_molar_fraction_pct` DECIMAL(18,2) COMMENT 'The theoretical proportion (%) of this librarys molar contribution relative to the total pool. Used to balance sequencing depth across libraries in a multiplexed run. Sum across all libraries in a pool should equal 100%.',
    `i5_index_sequence` STRING COMMENT 'The i5 (read 2 side) barcode index nucleotide sequence assigned to this library for dual-index multiplexing. Required for dual-indexed library pools to prevent index hopping. Typically 6–10 bases.. Valid values are `^[ACGTN]{6,12}$`',
    `i7_index_sequence` STRING COMMENT 'The i7 (read 1 side) barcode index nucleotide sequence assigned to this library for multiplexing identification. Used during demultiplexing to assign reads back to the originating library. Typically 6–10 bases.. Valid values are `^[ACGTN]{6,12}$`',
    `index_collision_flag` BOOLEAN COMMENT 'Indicates whether this librarys index sequence conflicts (collides) with another librarys index in the same pool, which would impair demultiplexing accuracy. True = collision detected; False = no collision. Populated by index compatibility checking tools.',
    `index_distance` STRING COMMENT 'Minimum Hamming distance between this librarys index sequence and all other index sequences in the same pool. A distance of ≥2 is typically required for reliable demultiplexing with 1 mismatch tolerance. Low values indicate collision risk.',
    `index_name` STRING COMMENT 'Human-readable name or catalog designation of the index pair (e.g., IDT-10nt-UDI-0001, TruSeq-D701-D501). Corresponds to the index kit nomenclature used during library preparation.',
    `insert_size_bp` STRING COMMENT 'Mean insert size in base pairs (bp) of this library as measured prior to pooling. Insert size affects read overlap, coverage uniformity, and compatibility with the sequencing run parameters.',
    `lane_assignment` STRING COMMENT 'The specific flow cell lane(s) to which this library-pool combination is assigned for sequencing (e.g., 1, 1,2, all). Relevant for patterned flow cells with lane-level loading (e.g., Illumina NovaSeq S4 flow cell).',
    `lims_pool_library_ref` STRING COMMENT 'External reference identifier for this pool-library association record as recorded in LabVantage LIMS. Enables cross-system traceability between the lakehouse silver layer and the operational LIMS source of record.',
    `loading_ratio` DECIMAL(18,2) COMMENT 'The ratio of this librarys contribution relative to the total pool volume or molar amount at the time of flow cell loading. Used to normalize read depth expectations and assess pooling balance post-sequencing.',
    `mean_quality_score` DECIMAL(18,2) COMMENT 'Average Phred quality score across all bases in reads assigned to this library. Provides a summary measure of base call accuracy for this librarys contribution to the pool run.',
    `normalization_tool` STRING COMMENT 'Name of the instrument or software tool used to quantify and normalize this library prior to pooling (e.g., Qubit 4 Fluorometer, Agilent Bioanalyzer 2100, Agilent TapeStation 4200, KAPA Library Quantification qPCR). Supports reagent and instrument traceability.',
    `notes` STRING COMMENT 'Free-text field for laboratory operator observations, deviations, or contextual remarks specific to this librarys pooling event. Supports GxP batch record documentation and investigation workflows.',
    `phred_q30_pct` DECIMAL(18,2) COMMENT 'Percentage of bases in reads assigned to this library that meet or exceed Phred quality score Q30 (≥99.9% base call accuracy). Key NGS quality metric; typically ≥80% Q30 is required for clinical-grade sequencing.',
    `pooling_date` DATE COMMENT 'Calendar date on which this library was physically added to the pool. Used for traceability, lot expiry checks, and TAT (Turnaround Time) calculations.',
    `pooling_method` STRING COMMENT 'Method used to determine the volume of this library added to the pool. Options include equimolar normalization, volume-based, mass-based, qPCR-normalized, or fluorometric quantification-based pooling.. Valid values are `equimolar|by_volume|by_mass|qpcr_normalized|fluorometric`',
    `project_name` STRING COMMENT 'Name of the research or clinical project to which this library belongs within the pool. Used for downstream FASTQ file organization, billing allocation, and project-level reporting in BaseSpace Sequence Hub.',
    `regulatory_use_classification` STRING COMMENT 'Regulatory classification of this librarys intended use context within the pool. RUO (Research Use Only), IVD (In Vitro Diagnostic), LDT (Laboratory Developed Test), or GxP-governed (GMP/GCP/GLP). Determines applicable compliance requirements for data handling and reporting.. Valid values are `RUO|IVD|LDT|GMP|GCP|GLP`',
    `removal_reason` STRING COMMENT 'Reason code explaining why this library was removed from the pool. Populated only when assignment_status is removed or failed. Supports root cause analysis and CAPA (Corrective and Preventive Action) workflows.. Valid values are `qc_failure|index_collision|operator_error|sample_swap|volume_insufficient|cancelled_by_requester`',
    `removed_timestamp` TIMESTAMP COMMENT 'Date and time when this library was removed or disqualified from the pool, if applicable. Null if the library remains active in the pool. Supports lifecycle tracking and investigation of failed runs.',
    `sample_sheet_position` STRING COMMENT 'Row position of this library entry in the Illumina sample sheet (SampleSheet.csv) used to configure the sequencing run and demultiplexing. Ensures correct index-to-sample mapping during BCL conversion.',
    `sequencing_application` STRING COMMENT 'The NGS application type for which this library was prepared and pooled. Determines expected coverage depth, read length, and bioinformatics pipeline routing. [ENUM-REF-CANDIDATE: WGS|WES|targeted_panel|amplicon|RNA_seq|ChIP_seq|ATAC_seq|methylation_seq|single_cell — promote to reference product]',
    `spike_in_flag` BOOLEAN COMMENT 'Indicates whether this library entry represents a spike-in control (e.g., PhiX, synthetic spike-in) rather than a biological sample library. True = spike-in control; False = biological sample. Spike-ins are used for sequencing quality calibration and are excluded from biological analysis.',
    `target_coverage_depth` STRING COMMENT 'The intended sequencing coverage depth (×) for this library in the pool (e.g., 30× for WGS, 100× for WES, 500× for targeted panels). Used to calculate required read count and validate pooling balance.',
    `undetermined_read_flag` BOOLEAN COMMENT 'Indicates whether this library contributed a disproportionate number of reads to the undetermined (unassigned) category during demultiplexing, suggesting index sequence issues or contamination. True = flagged; False = within acceptable threshold.',
    `volume_added_ul` DECIMAL(18,2) COMMENT 'Actual volume in microliters (µL) of this library pipetted into the pool. Critical for molar balance calculations and audit of physical pooling operations.',
    CONSTRAINT pk_pool_library PRIMARY KEY(`pool_library_id`)
) COMMENT 'Association entity linking libraries to pools, capturing the multiplexing relationship with its own business data. Records the library-to-pool assignment, index sequence (i7/i5), expected molar fraction (%), actual volume contributed (µL), loading ratio, and any index collision flags. Essential for demultiplexing traceability — enables reconstruction of which library contributed which reads in a pooled run.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sequencing`.`run_lane` (
    `run_lane_id` BIGINT COMMENT 'Unique surrogate identifier for a single lane record within a sequencing run on a multi-lane flow cell. Primary key for the run_lane entity. Entity role: TRANSACTION_LINE — represents one lane/line of a sequencing run (TRANSACTION_HEADER), carrying its own QC metrics, yield, and operational state.',
    `asset_id` BIGINT COMMENT 'Reference to the sequencing instrument (e.g., NovaSeq 6000, NextSeq 2000) on which this lane was sequenced. Supports instrument utilization tracking, maintenance scheduling, and cross-instrument performance benchmarking.',
    `employee_id` BIGINT COMMENT 'Reference to the laboratory operator or scientist responsible for loading and initiating the sequencing run for this lane. Supports GxP audit trail requirements, operator performance tracking, and training compliance verification. Satisfies TRANSACTION_LINE category: PARTY_REFERENCE (via the parent run, but captured at lane level for traceability).',
    `flow_cell_id` BIGINT COMMENT 'Reference to the physical flow cell consumable loaded on the instrument for this run. Links lane-level performance data to the specific flow cell lot and type (e.g., NovaSeq 6000 S4 flow cell). Satisfies TRANSACTION_LINE category: RESOURCE_REFERENCE.',
    `genome_assembly_id` BIGINT COMMENT 'Foreign key linking to reference.genome_assembly. Business justification: Lane-level QC metrics (alignment rate, on-target percentage) require reference genome specification. Critical for lane-level quality assessment and troubleshooting in production sequencing operations.',
    `pool_id` BIGINT COMMENT 'Reference to the multiplexed library pool or individual library loaded onto this lane. Enables traceability from lane-level sequencing output back to the sample preparation and library construction records in the LIMS.',
    `sequencing_run_id` BIGINT COMMENT 'Reference to the parent sequencing run (TRANSACTION_HEADER) that this lane belongs to. Satisfies TRANSACTION_LINE category: HEADER_REFERENCE — the lane is a line-level record within the run.',
    `basecalling_software` STRING COMMENT 'Name and version of the base calling software used to convert raw intensity signals to nucleotide sequences (FASTQ) for this lane (e.g., Illumina RTA 3.4.4, DRAGEN). Critical for data provenance, reproducibility, and regulatory traceability of genomic data.',
    `basecalling_software_version` STRING COMMENT 'Version identifier of the base calling software used for this lane. Required for GxP audit trails and bioinformatics reproducibility; version changes may affect base quality scores and downstream variant calling results.',
    `basespace_lane_code` STRING COMMENT 'Unique identifier for this lane as recorded in Illumina BaseSpace Sequence Hub, the primary system of record for sequencing data management. Enables direct linkage between the enterprise data lakehouse and the BaseSpace platform for data retrieval and audit.',
    `cluster_density_k_per_mm2` DECIMAL(18,2) COMMENT 'Number of clusters generated per square millimeter on this lane, expressed in thousands (K/mm²). A key sequencing performance metric; values outside the instrument-specific acceptable range indicate over- or under-clustering, leading to reduced data quality or yield.',
    `clusters_passing_filter_pct` DECIMAL(18,2) COMMENT 'Percentage of clusters on this lane that pass the Illumina chastity filter, indicating the proportion of high-quality reads retained for downstream analysis. Industry benchmark is typically ≥75–80%. Low values indicate poor library quality, phasing issues, or flow cell defects.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this run lane record was first created in the system, typically upon run initiation or lane assignment. Satisfies TRANSACTION_LINE category: RECORD_AUDIT_CREATED. Required for data lineage, GxP audit trail, and regulatory compliance.',
    `demultiplexing_status` STRING COMMENT 'Current status of the demultiplexing process for this lane, which separates pooled sample reads by index barcode to generate per-sample FASTQ files. Tracks whether the bioinformatics demultiplexing step has been initiated, completed, or encountered errors.. Valid values are `pending|in_progress|completed|failed|not_applicable`',
    `error_rate_pct` DECIMAL(18,2) COMMENT 'Sequencing error rate for this lane, expressed as a percentage, calculated from PhiX alignment. Reflects the per-base mismatch rate against the PhiX reference and is a key indicator of instrument and reagent performance. Typical acceptable threshold is <1%.',
    `fastq_output_path` STRING COMMENT 'File system or cloud storage path (e.g., AWS S3 URI or BaseSpace project path) where the demultiplexed FASTQ files for this lane are stored. Enables downstream bioinformatics pipelines to locate and consume the raw sequencing data output.',
    `index_read_length_i1` STRING COMMENT 'Length of Index Read 1 (i7 index) in base pairs used for demultiplexing samples on this lane. Defines the barcode length for sample identification in multiplexed sequencing runs.',
    `index_read_length_i2` STRING COMMENT 'Length of Index Read 2 (i5 index) in base pairs used for dual-index demultiplexing on this lane. Null for single-index runs. Dual indexing reduces index hopping and improves sample assignment accuracy in high-multiplex runs.',
    `lane_end_timestamp` TIMESTAMP COMMENT 'Date and time when sequencing completed on this lane. Together with lane_start_timestamp, enables calculation of lane-level sequencing duration and instrument cycle time for operational efficiency reporting.',
    `lane_failure_reason` STRING COMMENT 'Free-text or coded description of the root cause when a lane fails QC (lane_qc_status = fail). Captures failure categories such as low cluster density, high error rate, low Q30, PhiX misalignment, or reagent lot issues. Used for root cause analysis, CAPA, and instrument troubleshooting.',
    `lane_number` STRING COMMENT 'Physical lane position number on the flow cell (e.g., 1–8 for NovaSeq 6000 S4 flow cell). Satisfies TRANSACTION_LINE category: LINE_SEQUENCE — the ordinal position of this lane within the flow cell/run.',
    `lane_qc_status` STRING COMMENT 'Overall Quality Control (QC) disposition for this lane based on cluster density, clusters passing filter, PhiX alignment, and yield thresholds. Drives downstream bioinformatics pipeline gating and sample release decisions. Satisfies TRANSACTION_LINE category: LINE_VALUE_OR_RESULT. [ENUM-REF-CANDIDATE: pass|fail|warning|pending|under_review|cancelled — promote to reference product if additional statuses are required]. Valid values are `pass|fail|warning|pending|under_review|cancelled`',
    `lane_start_timestamp` TIMESTAMP COMMENT 'Date and time when sequencing commenced on this lane. Used for Turnaround Time (TAT) calculation, instrument utilization reporting, and scheduling of downstream bioinformatics processing. Satisfies TRANSACTION_LINE category: BUSINESS_EVENT_TIMESTAMP.',
    `lane_yield_gb` DECIMAL(18,2) COMMENT 'Total sequencing output (data yield) generated from this lane, expressed in gigabases (Gb). Primary throughput metric for lane-level performance assessment and SLA compliance. Satisfies TRANSACTION_LINE category: LINE_QUANTITY.',
    `lims_lane_reference` STRING COMMENT 'External identifier for this lane record as assigned by the Laboratory Information Management System (LIMS), such as LabVantage. Enables cross-system traceability between the Databricks Silver Layer analytical record and the operational LIMS source of record.',
    `loading_concentration_pm` DECIMAL(18,2) COMMENT 'Concentration of the library or pool loaded onto this lane, expressed in picomolar (pM). Critical operational parameter that directly influences cluster density and sequencing quality. Deviations from the target loading concentration are a primary root cause of lane failures.',
    `mean_phred_q30_pct` DECIMAL(18,2) COMMENT 'Percentage of bases on this lane with a Phred quality score ≥30 (Q30), indicating a base call accuracy of 99.9% or higher. Industry-standard quality threshold for NGS data; Illumina specifies Q30 ≥75–80% as a minimum acceptance criterion for most applications.',
    `mean_phred_score` DECIMAL(18,2) COMMENT 'Average Phred base quality score across all bases sequenced on this lane. Provides a single summary quality metric complementing the Q30 percentage for lane-level quality trending and instrument performance monitoring.',
    `num_samples_multiplexed` STRING COMMENT 'Count of individual samples multiplexed (pooled) and loaded onto this lane. Determines the expected per-sample read depth after demultiplexing and is a key parameter for capacity planning and SLA compliance per sample.',
    `phix_alignment_pct` DECIMAL(18,2) COMMENT 'Percentage of reads on this lane that aligned to the PhiX reference genome. Used to validate the PhiX spike-in and assess lane-level sequencing error rate. Significant deviation from the expected PhiX spike-in percentage indicates a lane-level quality issue.',
    `phix_spike_in_pct` DECIMAL(18,2) COMMENT 'Percentage of PhiX Control v3 library spiked into this lane for sequencing quality monitoring and calibration. PhiX is an Illumina-standard internal control used to assess error rate, base quality, and instrument performance per lane.',
    `qc_review_timestamp` TIMESTAMP COMMENT 'Date and time when the QC review of this lane was completed and the QC disposition (pass/fail/warning) was recorded. Required for GxP audit trail and regulatory submission traceability.',
    `qc_reviewed_by` BIGINT COMMENT 'Reference to the Quality Control (QC) scientist or analyst who reviewed and approved or rejected the lane QC results. Required for GxP electronic signature compliance and audit trail integrity under FDA 21 CFR Part 11.',
    `read_length_r1` STRING COMMENT 'Length of Read 1 in base pairs (bp) for this lane, as configured in the sequencing run setup. Determines the sequencing mode (e.g., 150 bp paired-end) and directly impacts the genomic applications supported (WGS, WES, targeted panels).',
    `read_length_r2` STRING COMMENT 'Length of Read 2 in base pairs (bp) for paired-end sequencing on this lane. Null for single-read runs. Together with read_length_r1, defines the paired-end read configuration (e.g., 2×150 bp) used for library insert size estimation and alignment accuracy.',
    `reads_passing_filter` BIGINT COMMENT 'Number of reads on this lane that passed the Illumina chastity filter and are available for downstream bioinformatics processing. Directly determines the effective sequencing depth available for variant calling and genomic analysis.',
    `requeue_count` STRING COMMENT 'Number of times this lane has been requeued for resequencing due to QC failure or insufficient yield. Tracks repeat failure patterns for root cause analysis and supports escalation decisions when a lane repeatedly fails.',
    `requeue_required` BOOLEAN COMMENT 'Indicates whether this lane requires resequencing (requeue) due to QC failure or insufficient yield. Triggers downstream sample management and scheduling workflows in the LIMS to prioritize reruns and maintain customer SLA commitments.',
    `run_mode` STRING COMMENT 'Sequencing run mode for this lane: paired-end (reads generated from both ends of the DNA fragment) or single-read (reads generated from one end only). Determines FASTQ file structure and alignment strategy for downstream bioinformatics processing.. Valid values are `paired_end|single_read`',
    `sequencing_application` STRING COMMENT 'Genomic sequencing application type assigned to this lane (e.g., Whole Genome Sequencing (WGS), Whole Exome Sequencing (WES), targeted panel, RNA-seq). Determines QC thresholds, coverage requirements, and downstream bioinformatics pipeline routing. [ENUM-REF-CANDIDATE: WGS|WES|targeted_panel|amplicon|RNA_seq|methylation|other — promote to reference product if additional application types are required]',
    `target_cluster_density_k_per_mm2` DECIMAL(18,2) COMMENT 'Instrument- and flow-cell-specific target cluster density in thousands per square millimeter (K/mm²) for this lane, as defined in the sequencing SOP. Used to assess whether the actual cluster density (cluster_density_k_per_mm2) is within the acceptable operating range.',
    `target_yield_gb` DECIMAL(18,2) COMMENT 'Expected or contracted sequencing yield in gigabases (Gb) for this lane, as defined by the run plan or customer SLA. Used to assess whether the actual lane yield (lane_yield_gb) meets the planned output and to trigger reruns or escalations when yield is insufficient.',
    `total_reads` BIGINT COMMENT 'Total number of sequencing reads generated from this lane before quality filtering. Provides a raw throughput count used alongside yield (Gb) for per-lane performance benchmarking and capacity planning.',
    `undetermined_reads_pct` DECIMAL(18,2) COMMENT 'Percentage of reads on this lane that could not be assigned to a sample index during demultiplexing. High undetermined read rates indicate index contamination, index hopping, or sample sheet errors. Typically acceptable threshold is <5–10%.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this run lane record was last modified, such as when QC metrics were populated post-run or when the QC status was updated. Satisfies TRANSACTION_LINE category: RECORD_AUDIT_UPDATED. Required for data lineage and GxP audit trail.',
    CONSTRAINT pk_run_lane PRIMARY KEY(`run_lane_id`)
) COMMENT 'Operational record representing a single lane within a sequencing run on a multi-lane flow cell. Captures lane number, assigned pool or library, loading concentration, cluster density (K/mm²), clusters passing filter (%), PhiX spike-in percentage, lane-level QC status, and lane yield (Gb). Enables per-lane performance monitoring and troubleshooting of lane-specific failures on instruments such as NovaSeq 6000 with S-series flow cells.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sequencing`.`run_qc_metric` (
    `run_qc_metric_id` BIGINT COMMENT 'Unique surrogate identifier for each run QC metric record. Serves as the primary key for this transactional entity capturing quantitative quality measurements at run, lane, or library granularity. Entity role: TRANSACTION_HEADER — stores discrete QC measurement events with a clear lifecycle and multiple metric dimensions sourced from Illumina InterOp, BaseSpace, bcl2fastq, Picard, and samtools.',
    `approval_id` BIGINT COMMENT 'Foreign key linking to regulatory.regulatory_approval. Business justification: QC metrics for regulated assays must reference the approval defining acceptance criteria. Required for lot release decisions, batch records, and regulatory inspections. QC pass/fail thresholds are app',
    `asset_id` BIGINT COMMENT 'Reference to the sequencing instrument (e.g., NovaSeq, NextSeq, HiSeq) that produced the run. Enables instrument-level performance trending, preventive maintenance correlation, and GxP instrument qualification tracking.',
    `experiment_id` BIGINT COMMENT 'Foreign key linking to research.experiment. Business justification: QC metrics are evaluated in experiment context to determine if data quality meets experimental design requirements (coverage depth, Q30 thresholds). Drives go/no-go decisions for downstream analysis, ',
    `flow_cell_id` BIGINT COMMENT 'Reference to the flow cell consumable used in the sequencing run. Supports lot-level quality tracking, reagent performance correlation, and consumable failure root-cause analysis.',
    `gene_annotation_track_id` BIGINT COMMENT 'Foreign key linking to reference.gene_annotation_track. Business justification: QC metrics for RNA-seq and targeted gene panels require gene annotation context for on-target calculations and gene-level coverage reporting. Essential for assay validation and clinical quality contro',
    `gene_model_id` BIGINT COMMENT 'Foreign key linking to reference.gene_model. Business justification: Gene-level QC metrics (coverage per gene, uniformity) require gene model specification. Essential for clinical assay validation, gene panel QC reporting, and identifying genes with inadequate coverage',
    `genome_assembly_id` BIGINT COMMENT 'Foreign key linking to reference.genome_assembly. Business justification: QC metrics like alignment rate, coverage uniformity, on-target rate are calculated against specific reference assembly. Essential for QC reporting, regulatory compliance, and troubleshooting sequencin',
    `genomic_region_id` BIGINT COMMENT 'Foreign key linking to reference.genomic_region. Business justification: On-target QC metrics require knowing the target region definition (BED file coordinates). Essential for calculating on-target rate, coverage uniformity over targets, and validating sequencing performa',
    `library_id` BIGINT COMMENT 'Reference to the sequencing library (prepared sample) for which per-library coverage metrics are recorded. Nullable — populated only when metric_granularity_level is library. Enables per-library coverage adequacy assessment for WGS, WES, and targeted assays.',
    `oos_investigation_id` BIGINT COMMENT 'Foreign key linking to quality.oos_investigation. Business justification: Run QC metrics that fail specifications (Q30 below threshold, cluster density out of range, high error rate) trigger OOS investigations. Labs link investigations to specific QC metrics for root cause ',
    `qc_result_id` BIGINT COMMENT 'Foreign key linking to quality.qc_result. Business justification: Run QC metrics (Q30, cluster density, error rate, PhiX alignment) ARE QC results in the quality system. Labs must link sequencing QC to the broader QC result framework for trending, OOS investigations',
    `run_lane_id` BIGINT COMMENT 'Foreign key linking to sequencing.run_lane. Business justification: QC metrics can be captured at multiple granularity levels including lane level (metric_granularity_level attribute). When metrics are lane-specific, they should formally link to run_lane. Currently ha',
    `sample_specimen_id` BIGINT COMMENT 'Reference to the biological sample associated with the library being assessed. Nullable — populated when metric_granularity_level is library. Supports sample-level quality traceability and clinical reporting.',
    `sequencing_run_id` BIGINT COMMENT 'Reference to the parent sequencing run for which this QC metric record was generated. Links the metric to the instrument run event, enabling run-level pass/fail determination and instrument performance trending.',
    `support_case_id` BIGINT COMMENT 'Foreign key linking to customer.support_case. Business justification: QC failures trigger customer support cases. Links metrics to cases for root cause analysis, resolution tracking, and customer communication. Critical for service lab incident management and SLA compli',
    `variant_database_id` BIGINT COMMENT 'Foreign key linking to reference.variant_database. Business justification: QC workflows check against known variant databases for contamination detection, sample identity verification, and positive control validation. Essential for clinical laboratory quality control and tro',
    `alignment_rate_percent` DECIMAL(18,2) COMMENT 'Percentage of reads that successfully aligned to the reference genome. Low alignment rates may indicate sample contamination, wrong species, or library preparation failures. Sourced from samtools flagstat or DRAGEN alignment metrics.',
    `assay_type` STRING COMMENT 'Classification of the sequencing assay type performed: Whole Genome Sequencing (WGS), Whole Exome Sequencing (WES), targeted panel, amplicon, RNA-seq, or other. Determines applicable coverage thresholds and QC pass/fail criteria for the run or library.. Valid values are `WGS|WES|targeted|amplicon|RNA-seq|other`',
    `cluster_density_k_per_mm2` DECIMAL(18,2) COMMENT 'Number of clusters per square millimeter on the flow cell surface, expressed in thousands (K/mm²). Optimal cluster density is critical for sequencing quality; too high causes overcrowding and quality degradation, too low reduces yield. Sourced from Illumina InterOp.',
    `clusters_passing_filter_percent` DECIMAL(18,2) COMMENT 'Percentage of clusters that pass Illuminas chastity filter, indicating the proportion of high-quality reads retained after filtering. A key run-level QC metric; typically ≥75–85% is expected for acceptable run quality. Sourced from Illumina InterOp.',
    `coverage_uniformity_percent` DECIMAL(18,2) COMMENT 'Percentage of target bases covered at ≥20% of the mean coverage depth, measuring how evenly reads are distributed across the target region. High uniformity indicates consistent library preparation and sequencing performance. Sourced from Picard or samtools.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this QC metric record was first created in the system, typically upon automated ingestion from the source QC tool (InterOp, BaseSpace, Picard, or samtools). Supports audit trail requirements under GxP and FDA 21 CFR Part 11.',
    `duplication_rate_percent` DECIMAL(18,2) COMMENT 'Percentage of reads identified as PCR or optical duplicates, which are removed prior to variant calling. High duplication rates reduce effective coverage and indicate over-amplification during library preparation. Sourced from Picard MarkDuplicates.',
    `error_rate_percent` DECIMAL(18,2) COMMENT 'Percentage of base calls that do not match the reference sequence, typically measured using PhiX control spike-in. Reflects sequencing chemistry and instrument performance. Lower values indicate higher accuracy. Sourced from Illumina InterOp.',
    `gc_bias_index` DECIMAL(18,2) COMMENT 'Quantitative measure of GC content bias in sequencing coverage, indicating the degree to which GC-rich or GC-poor regions are over- or under-represented relative to expected coverage. Values near 0 indicate minimal bias. Sourced from Picard CollectGcBiasMetrics.',
    `insert_size_std_dev_bp` DECIMAL(18,2) COMMENT 'Standard deviation of the insert size distribution in base pairs. High standard deviation indicates heterogeneous fragmentation, which can affect alignment accuracy and coverage uniformity. Sourced from Picard CollectInsertSizeMetrics.',
    `mean_coverage_depth` DECIMAL(18,2) COMMENT 'Average number of times each base in the target region (genome, exome, or panel) is covered by sequencing reads, expressed as fold-coverage (X). Primary metric for assessing whether sufficient sequencing depth was achieved for reliable variant calling. Populated for library-level records. Sourced from Picard or samtools.',
    `mean_insert_size_bp` DECIMAL(18,2) COMMENT 'Average size of the DNA fragment inserted between sequencing adapters, in base pairs. Reflects library preparation quality; deviations from expected insert size indicate degradation, over-fragmentation, or adapter contamination. Sourced from Picard CollectInsertSizeMetrics.',
    `mean_phred_score` DECIMAL(18,2) COMMENT 'Average Phred quality score across all bases in the run or lane, representing overall base call accuracy. A Phred score of 30 corresponds to 99.9% accuracy. Used for instrument performance benchmarking and run-level QC trending.',
    `median_coverage_depth` DECIMAL(18,2) COMMENT 'Median fold-coverage across the target region, less sensitive to outliers than mean coverage. Used alongside mean_coverage_depth to assess coverage uniformity and detect regions of extreme over- or under-representation. Sourced from Picard or samtools.',
    `metric_granularity_level` STRING COMMENT 'Indicates the level of aggregation at which this QC metric record applies: run for instrument-wide metrics, lane for per-lane flow cell metrics, or library for per-library/per-sample coverage metrics. Determines which metric fields are populated and how the record is used in QC workflows.. Valid values are `run|lane|library`',
    `metric_source_system` STRING COMMENT 'Identifies the upstream tool or system from which this QC metric record was derived: Illumina InterOp files, BaseSpace, bcl2fastq demultiplexing stats, Picard alignment tools, samtools, DRAGEN, or other. Supports data lineage tracking and metric reproducibility audits. [ENUM-REF-CANDIDATE: InterOp|BaseSpace|bcl2fastq|Picard|samtools|DRAGEN|other — 7 candidates stripped; promote to reference product]',
    `on_target_rate_percent` DECIMAL(18,2) COMMENT 'Percentage of aligned reads that map to the intended target region (exome capture or targeted panel). Applicable for WES and targeted sequencing assays. Low on-target rates indicate poor library enrichment or capture efficiency. Sourced from Picard CollectHsMetrics.',
    `pct_bases_at_100x` DECIMAL(18,2) COMMENT 'Fraction of target bases covered at a minimum depth of 100X, expressed as a percentage. Used for high-depth targeted sequencing panels, somatic variant calling, and liquid biopsy applications requiring high sensitivity at low allele frequencies. Sourced from Picard or samtools.',
    `pct_bases_at_10x` DECIMAL(18,2) COMMENT 'Fraction of target bases covered at a minimum depth of 10X, expressed as a percentage. Used as a coverage adequacy threshold for low-depth applications and as a QC gate for variant calling sensitivity. Sourced from Picard CollectHsMetrics or samtools depth.',
    `pct_bases_at_20x` DECIMAL(18,2) COMMENT 'Fraction of target bases covered at a minimum depth of 20X, expressed as a percentage. Standard coverage threshold for WES clinical assays; used to assess whether sufficient depth was achieved for reliable heterozygous variant detection. Sourced from Picard or samtools.',
    `pct_bases_at_30x` DECIMAL(18,2) COMMENT 'Fraction of target bases covered at a minimum depth of 30X, expressed as a percentage. Common coverage threshold for WGS clinical applications; used to confirm adequate depth for high-confidence variant calling across the genome. Sourced from Picard or samtools.',
    `pf_reads` BIGINT COMMENT 'Number of reads passing Illuminas chastity filter (PF reads), representing high-quality reads used in downstream alignment and variant calling. Distinct from total_reads which includes all raw clusters. Sourced from Illumina InterOp or bcl2fastq.',
    `phix_alignment_rate_percent` DECIMAL(18,2) COMMENT 'Percentage of reads that align to the PhiX bacteriophage control genome, which is spiked into sequencing runs as an internal quality control standard. Used to validate sequencing chemistry performance and calibrate error rate measurements.',
    `phix_error_rate_percent` DECIMAL(18,2) COMMENT 'Sequencing error rate calculated from PhiX control reads, providing an unbiased measure of instrument and chemistry accuracy independent of sample biology. Sourced from Illumina InterOp. Used for instrument performance trending and GxP compliance.',
    `q30_percent` DECIMAL(18,2) COMMENT 'Percentage of bases with a Phred quality score of 30 or higher (Q30), indicating ≥99.9% base call accuracy. Industry-standard instrument performance metric; Illumina typically requires ≥75–80% Q30 for run acceptance. Sourced from Illumina InterOp or BaseSpace.',
    `qc_failure_reason` STRING COMMENT 'Free-text or structured description of the reason(s) for QC failure or warning status, such as Q30 below threshold, high duplication rate, or low on-target rate. Populated when qc_status is fail or warning. Supports root-cause analysis and corrective action tracking.',
    `qc_reviewed_by` STRING COMMENT 'Username or employee identifier of the scientist or QA analyst who performed the manual QC review and sign-off for this metric record. Required for GxP audit trail and electronic signature compliance under FDA 21 CFR Part 11.',
    `qc_reviewed_timestamp` TIMESTAMP COMMENT 'Date and time when the QC review and sign-off was completed for this metric record. Supports GxP audit trail, turnaround time (TAT) tracking, and regulatory submission documentation.',
    `qc_status` STRING COMMENT 'Overall QC determination for this metric record: pass indicates all applicable thresholds met, fail indicates one or more critical thresholds breached, warning indicates marginal performance requiring review, pending_review indicates awaiting manual QC sign-off, invalidated indicates the run or library was voided. Central to GxP compliance reporting and run release decisions.. Valid values are `pass|fail|warning|pending_review|invalidated`',
    `read_length_bp` STRING COMMENT 'Length of sequencing reads in base pairs (bp) for this run or library (e.g., 150 bp for paired-end 150). Determines the resolution of variant calling and structural variant detection. Sourced from run configuration in Illumina BaseSpace.',
    `read_type` STRING COMMENT 'Indicates whether the sequencing run used single-end or paired-end read chemistry. Paired-end reads provide improved alignment accuracy and structural variant detection. Affects coverage calculation and bioinformatics pipeline configuration.. Valid values are `single_end|paired_end`',
    `run_date` DATE COMMENT 'Calendar date on which the sequencing run was initiated. Used as the principal business event date for instrument performance trending, throughput reporting, and time-series QC analysis.',
    `total_reads` BIGINT COMMENT 'Total number of sequencing reads generated for the run, lane, or library before quality filtering. Used to assess raw sequencing throughput and as the denominator for percentage-based QC metrics such as clusters passing filter and undetermined index rate.',
    `undetermined_index_rate_percent` DECIMAL(18,2) COMMENT 'Percentage of reads that could not be assigned to a sample index during demultiplexing, indicating index hopping, contamination, or library preparation issues. High undetermined rates may trigger run failure or sample reprocessing. Sourced from bcl2fastq demultiplexing stats.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this QC metric record was last modified, such as when a QC status was updated following manual review or when a metric value was corrected. Required for GxP audit trail and data integrity compliance.',
    `use_classification` STRING COMMENT 'Regulatory use classification of the sequencing run: Research Use Only (RUO), In Vitro Diagnostic (IVD), Laboratory Developed Test (LDT), clinical, or research. Governs applicable regulatory standards, QC thresholds, and reporting obligations.. Valid values are `RUO|IVD|LDT|clinical|research`',
    `yield_gb` DECIMAL(18,2) COMMENT 'Total sequencing output in gigabases (Gb) for the run, lane, or library. Represents the volume of sequence data generated and is used to assess whether sufficient data was produced to meet coverage requirements for the assay type. Sourced from Illumina BaseSpace or bcl2fastq.',
    CONSTRAINT pk_run_qc_metric PRIMARY KEY(`run_qc_metric_id`)
) COMMENT 'Transactional record storing quantitative quality metrics for sequencing runs at multiple granularity levels: run-level, lane-level, and per-library. Instrument-level metrics include Q30%, mean Phred score, error rate, cluster density, clusters passing filter, yield (Gb), PhiX alignment and error rate, and undetermined index rate. Per-library coverage metrics include mean/median coverage depth (X), coverage uniformity (%), fraction of bases at ≥10X/≥20X/≥30X/≥100X thresholds, on-target rate (% for WES/targeted), duplication rate (%), insert size statistics, and GC bias. Each metric row is attributed to a run, optionally a lane, and optionally a library — enabling both run-level pass/fail determination and per-library coverage adequacy assessment. Sourced from Illumina InterOp files, BaseSpace, bcl2fastq stats, and alignment tools (Picard, samtools). Supports instrument performance trending, assay-specific coverage thresholds, and GxP compliance reporting.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sequencing`.`demux_result` (
    `demux_result_id` BIGINT COMMENT 'Unique surrogate identifier for each demultiplexing result record. Primary key for the demux_result data product. Entity role: TRANSACTION_HEADER — captures the discrete business event of demultiplexing a pooled sequencing run into per-sample FASTQ outputs.',
    `employee_id` BIGINT COMMENT 'Reference to the laboratory operator or bioinformatician who initiated or reviewed the demultiplexing job. Supports GxP audit trail requirements and operator accountability for regulated sequencing workflows.',
    `experiment_id` BIGINT COMMENT 'Foreign key linking to research.experiment. Business justification: Demultiplexing results are evaluated in experiment context to determine if per-sample read counts meet experimental design (e.g., minimum reads per sample for statistical power). Drives sample reseque',
    `genome_assembly_id` BIGINT COMMENT 'Foreign key linking to reference.genome_assembly. Business justification: Demultiplexed data is immediately aligned to reference genome. Tracking which build enables traceability from raw data through analysis pipeline and supports reproducibility requirements for clinical ',
    `library_id` BIGINT COMMENT 'Reference to the sequencing library (prepared sample) whose reads were assigned during demultiplexing. Provides the authoritative link between the demux result and the source library.',
    `original_demux_result_id` BIGINT COMMENT 'Reference to the original demux_result record when this record represents a reprocessing event (reprocessing_flag = True). Enables full lineage tracing from reprocessed results back to the original demultiplexing output. Null when reprocessing_flag = False.',
    `project_id` BIGINT COMMENT 'Reference to the research or clinical project under which this sequencing and demultiplexing activity was performed. Enables project-level aggregation of demux results for reporting, billing, and data governance purposes.',
    `quality_issue_id` BIGINT COMMENT 'Foreign key linking to data.quality_issue. Business justification: Demultiplexing failures (high undetermined reads, index collisions, sample swaps) logged as quality issues for pipeline troubleshooting and sample tracking integrity - critical for clinical sample ide',
    `run_lane_id` BIGINT COMMENT 'Foreign key linking to sequencing.run_lane. Business justification: Demultiplexing results are generated per lane within a sequencing run. demux_result currently has run_id (to sequencing_run) and lane_number (integer), but no formal FK to the run_lane master record. ',
    `sample_specimen_id` BIGINT COMMENT 'Reference to the biological sample associated with the library. Enables traceability from raw FASTQ output back to the original sample submitted for sequencing.',
    `sequencing_run_id` BIGINT COMMENT 'Reference to the sequencing run from which this demultiplexing result was produced. Links the demux output back to the originating instrument run and flow cell.',
    `assigned_read_count` BIGINT COMMENT 'Total number of sequencing reads assigned to this library after demultiplexing. Primary quantitative outcome of the demux process. Used to assess library representation and coverage depth adequacy for downstream analysis.',
    `assigned_read_pct` DECIMAL(18,2) COMMENT 'Percentage of total reads in the lane assigned to this library (assigned_read_count / total lane reads × 100). Indicates library balance within the pool. Values significantly deviating from expected multiplexing ratio trigger QC review.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this demux result record was first captured in the data platform. Audit trail field for data lineage and GxP compliance.',
    `data_release_flag` BOOLEAN COMMENT 'Indicates whether the FASTQ files produced by this demux result have been formally released for downstream bioinformatics processing or delivery to the customer/requester. True = released; False = held (pending QC review or approval). Supports data governance and release management workflows.',
    `demux_completion_timestamp` TIMESTAMP COMMENT 'The date and time at which the demultiplexing process completed for this library within the sequencing run. Principal business event timestamp. Used for turnaround time (TAT) calculation and SLA monitoring.',
    `demux_run_identifier` STRING COMMENT 'Externally-known business identifier for the demultiplexing execution job, as assigned by the demux software (e.g., bcl2fastq job ID or DRAGEN BCL Convert run name). Used for cross-referencing with Illumina BaseSpace Sequence Hub and bioinformatics pipeline logs.',
    `demux_software` STRING COMMENT 'Name of the software tool used to perform demultiplexing (e.g., bcl2fastq, DRAGEN BCL Convert). Critical for reproducibility, audit trails, and bioinformatics pipeline compatibility validation.. Valid values are `bcl2fastq|DRAGEN_BCL_Convert|BCL2FASTQ2|other`',
    `demux_software_version` STRING COMMENT 'Version number of the demultiplexing software used (e.g., 2.20.0 for bcl2fastq or 3.9.3 for DRAGEN BCL Convert). Required for GxP software validation records, reproducibility documentation, and regulatory submissions.. Valid values are `^d+.d+(.d+)?$`',
    `demux_start_timestamp` TIMESTAMP COMMENT 'The date and time at which the demultiplexing process was initiated for this run. Used in conjunction with demux_completion_timestamp to calculate demux processing duration for performance monitoring.',
    `demux_status` STRING COMMENT 'Current lifecycle status of the demultiplexing job for this library-run combination. completed indicates successful assignment; partial indicates some reads assigned but below threshold; failed indicates job error or no reads assigned.. Valid values are `completed|failed|partial|in_progress|cancelled`',
    `fastq_i1_path` STRING COMMENT 'Storage path or URI to the FASTQ file containing Index Read 1 (i7 index) sequences. Generated when index reads are retained in FASTQ format. Used for index QC validation and troubleshooting demultiplexing failures.',
    `fastq_r1_path` STRING COMMENT 'Storage path or URI to the FASTQ file containing Read 1 (forward reads) generated for this library after demultiplexing. Provides the authoritative link between the demux result and the resulting FASTQ output file for downstream bioinformatics pipeline ingestion.',
    `fastq_r2_path` STRING COMMENT 'Storage path or URI to the FASTQ file containing Read 2 (reverse reads) generated for this library after demultiplexing. Populated only for paired-end sequencing runs. Null for single-end runs.',
    `index_mismatch_count` BIGINT COMMENT 'Number of reads assigned to this library that contained one or more base mismatches in the index sequence relative to the expected index, within the allowed mismatch tolerance. Elevated counts may indicate index synthesis errors or library contamination.',
    `index_sequence` STRING COMMENT 'The nucleotide index sequence (i7 and optionally i5 dual-index) matched to assign reads to this library during demultiplexing. Supports single-index (e.g., ACGTACGT) and dual-index (e.g., ACGTACGT+TTGGCCAA) formats. Critical for multiplexing validation and index collision analysis.. Valid values are `^[ACGTN]+(+[ACGTN]+)?$`',
    `instrument_platform` STRING COMMENT 'The sequencing instrument platform model used for the run (e.g., NovaSeq 6000, NovaSeq X, NextSeq 2000, MiSeq). Determines flow cell format, lane count, and applicable demux parameters. [ENUM-REF-CANDIDATE: NovaSeq_6000|NovaSeq_X|NextSeq_2000|MiSeq|HiSeq_4000|PromethION|other — promote to reference product]. Valid values are `NovaSeq_6000|NovaSeq_X|NextSeq_2000|MiSeq|HiSeq_4000|other`',
    `lane_number` STRING COMMENT 'The physical lane number on the flow cell from which reads were demultiplexed. Flow cells may contain 1, 2, 4, or 8 lanes depending on instrument type (e.g., NovaSeq, HiSeq). Required for per-lane QC analysis and troubleshooting.',
    `mean_phred_score_r1` DECIMAL(18,2) COMMENT 'Mean Phred quality score across all bases in Read 1 for this library. Phred score (Q score) represents base call accuracy (Q30 = 99.9% accuracy). A key NGS QC metric; values below Q30 threshold may trigger QC failure.',
    `mean_phred_score_r2` DECIMAL(18,2) COMMENT 'Mean Phred quality score across all bases in Read 2 for this library. Typically lower than R1 due to signal degradation in paired-end sequencing. Null for single-end runs.',
    `min_read_count_threshold` BIGINT COMMENT 'The minimum number of assigned reads required for this library to pass QC, as defined by the applicable assay protocol or SOP. Stored at the record level to capture the threshold in effect at the time of demultiplexing, supporting historical QC audits.',
    `mismatch_tolerance` STRING COMMENT 'Number of allowable base mismatches permitted when matching a reads index sequence to the expected library index during demultiplexing. Typically 0 or 1. Higher values increase assignment rate but risk index cross-contamination between libraries.',
    `pct_q30_r1` DECIMAL(18,2) COMMENT 'Percentage of Read 1 bases with a Phred quality score of 30 or higher (≥Q30). Industry-standard NGS QC threshold; Illumina specifies ≥75–80% Q30 as passing for most platforms. Used in run-level and library-level QC reporting.',
    `pct_q30_r2` DECIMAL(18,2) COMMENT 'Percentage of Read 2 bases with a Phred quality score of 30 or higher (≥Q30). Null for single-end runs. Compared against run-specific QC thresholds for paired-end quality assessment.',
    `qc_failure_reason` STRING COMMENT 'Descriptive reason for QC failure when qc_pass_flag = False. Examples include: low_read_count, high_undetermined_rate, index_collision, low_q30. Populated by automated QC rules or manual review. Null when qc_pass_flag = True.',
    `qc_pass_flag` BOOLEAN COMMENT 'Indicates whether the demultiplexing result for this library passed all defined QC thresholds (read count, percentage assigned, undetermined rate). True = QC passed; False = QC failed. Authoritative gate for downstream bioinformatics pipeline processing.',
    `read_length_r1` STRING COMMENT 'Length in base pairs (bp) of Read 1 sequences produced for this library. Determined by the sequencing run configuration. Critical for downstream alignment and variant calling pipeline compatibility.',
    `read_length_r2` STRING COMMENT 'Length in base pairs (bp) of Read 2 sequences produced for this library. Null for single-end runs. Used to confirm paired-end symmetry and pipeline input validation.',
    `reprocessing_flag` BOOLEAN COMMENT 'Indicates whether this demux result was generated by reprocessing a previously demultiplexed run (e.g., due to sample sheet correction, software update, or QC failure remediation). True = reprocessed; False = original demux. Supports data lineage and audit trail requirements.',
    `run_use_type` STRING COMMENT 'Intended use classification of the sequencing run from which this demux result originates. RUO (Research Use Only), IVD (In Vitro Diagnostic), LDT (Laboratory Developed Test), clinical_validation, or research. Governs applicable regulatory requirements and data handling obligations.. Valid values are `RUO|IVD|LDT|clinical_validation|research`',
    `sample_sheet_version` STRING COMMENT 'Version identifier of the sample sheet used to configure the demultiplexing run. The sample sheet defines library-to-index mappings and run parameters. Versioning ensures traceability and supports reprocessing with corrected configurations.',
    `sequencing_type` STRING COMMENT 'Classification of the sequencing assay type for this library (e.g., WGS — Whole Genome Sequencing, WES — Whole Exome Sequencing, targeted panel, amplicon, RNA-seq). Determines applicable QC thresholds and downstream bioinformatics pipeline routing. [ENUM-REF-CANDIDATE: WGS|WES|targeted|amplicon|RNA-seq|single-cell|metagenomics|other — promote to reference product]. Valid values are `WGS|WES|targeted|amplicon|RNA-seq|other`',
    `total_lane_read_count` BIGINT COMMENT 'Total number of reads generated in the flow cell lane from which this library was demultiplexed. Used as the denominator for calculating assigned_read_pct and undetermined_read_pct. Enables per-lane yield assessment.',
    `undetermined_read_count` BIGINT COMMENT 'Number of reads in the lane that could not be assigned to any library due to index mismatch or ambiguity. High undetermined counts indicate index contamination, library preparation issues, or incorrect sample sheet configuration.',
    `undetermined_read_pct` DECIMAL(18,2) COMMENT 'Percentage of total lane reads that were unassigned (undetermined_read_count / total lane reads × 100). A key QC metric; values exceeding the defined threshold (typically >5%) trigger run-level QC failure investigation.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this demux result record was last modified in the data platform. Supports change tracking and data lineage auditing.',
    CONSTRAINT pk_demux_result PRIMARY KEY(`demux_result_id`)
) COMMENT 'Transactional record capturing the output of the demultiplexing process (bcl2fastq / DRAGEN BCL Convert) for each library within a pooled sequencing run. Records library ID, run ID, lane, index sequence matched, read count assigned, percentage of reads assigned, undetermined read count, mismatch tolerance used, demux software version, demux completion timestamp, and demux QC pass/fail status. Provides the authoritative link between a sequencing run and the resulting per-sample FASTQ files.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sequencing`.`fastq_file` (
    `fastq_file_id` BIGINT COMMENT 'Unique surrogate identifier for the FASTQ file record in the sequencing data inventory. Primary key for this master resource entity representing a raw sequencing output file.',
    `access_request_id` BIGINT COMMENT 'Foreign key linking to data.access_request. Business justification: FASTQ files are primary data assets requested for external access in genomics data sharing - standard practice in dbGaP, EGA, and institutional repositories. Requests track data use statements and pub',
    `asset_id` BIGINT COMMENT 'Reference to the sequencing instrument (e.g., Illumina NovaSeq, NextSeq, MiSeq) that generated the raw data for this FASTQ file. Enables instrument-level performance tracking, maintenance correlation, and QC trend analysis.',
    `demux_result_id` BIGINT COMMENT 'Reference to the demultiplexing process execution that generated this FASTQ file from the raw BCL sequencing output. Enables traceability to the specific demultiplexing parameters, software version, and sample sheet used.',
    `experiment_id` BIGINT COMMENT 'Foreign key linking to research.experiment. Business justification: FASTQ files are primary sequencing outputs evaluated per-experiment for data completeness and quality. Linking enables experiment-level data release decisions, analysis pipeline triggering based on ex',
    `flow_cell_id` BIGINT COMMENT 'Reference to the flow cell consumable used in the sequencing run that produced this FASTQ file. Enables flow cell-level QC analysis, lot traceability for reagent investigations, and consumable performance benchmarking.',
    `genome_assembly_id` BIGINT COMMENT 'Foreign key linking to reference.genome_assembly. Business justification: FASTQ files are aligned to specific reference builds. This link enables complete traceability from raw sequencing data through alignment and variant calling, critical for regulatory compliance and dat',
    `genomic_access_control_id` BIGINT COMMENT 'Foreign key linking to data.genomic_access_control. Business justification: FASTQ files contain PHI and genomic data requiring access controls per HIPAA, GDPR, and NIH Genomic Data Sharing Policy - privacy and compliance requirement. Controls enforce encryption, audit logging',
    `library_id` BIGINT COMMENT 'Reference to the sequencing library (prepared sample) from which this FASTQ file was generated. Enables traceability from raw data back to library preparation and upstream sample management.',
    `project_id` BIGINT COMMENT 'Reference to the research or clinical project under which this FASTQ file was generated. Enables project-level data aggregation, access control scoping, and cost allocation for sequencing activities.',
    `quality_assessment_id` BIGINT COMMENT 'Foreign key linking to data.quality_assessment. Business justification: FASTQ files are primary targets of bioinformatics QC pipelines measuring read quality, contamination, duplication rates - universal practice. Assessment results determine pipeline-ready status and dat',
    `quality_issue_id` BIGINT COMMENT 'Foreign key linking to data.quality_issue. Business justification: Corrupted files, unexpectedly low read counts, contamination detected in FASTQ trigger quality issue logging for data integrity investigation - critical for clinical diagnostic workflows and research ',
    `research_protocol_id` BIGINT COMMENT 'The IRB protocol identifier under which human subject samples associated with this FASTQ file were collected and sequenced. Required for clinical and research genomics data governance, consent verification, and regulatory audit trails.',
    `retention_policy_id` BIGINT COMMENT 'Foreign key linking to data.retention_policy. Business justification: FASTQ file retention periods vary by use classification (clinical diagnostic vs research vs commercial) and regulatory requirements - data governance requirement. Policies define archival triggers, st',
    `run_lane_id` BIGINT COMMENT 'Foreign key linking to sequencing.run_lane. Business justification: FASTQ files are generated per lane and currently have lane_number (integer) but no FK to run_lane. Adding run_lane_id links FASTQ files to their lane master record, enabling retrieval of lane-level QC',
    `sample_specimen_id` BIGINT COMMENT 'Reference to the biological sample associated with this FASTQ file. Provides direct linkage from raw sequencing output to the originating sample for end-to-end traceability per CLIA and CAP requirements.',
    `sequencing_run_id` BIGINT COMMENT 'Reference to the sequencing run that produced this FASTQ file. Links the file to its originating instrument run for traceability and run-level quality assessment.',
    `adapter_trimming_flag` BOOLEAN COMMENT 'Indicates whether adapter sequences were trimmed from reads during or after demultiplexing. Adapter trimming affects downstream alignment and variant calling accuracy. Relevant for pipeline configuration validation.',
    `basespace_dataset_code` STRING COMMENT 'The unique dataset identifier assigned by Illumina BaseSpace Sequence Hub to the dataset object containing this FASTQ file. Used for cross-referencing and API retrieval from BaseSpace.',
    `basespace_file_code` STRING COMMENT 'The unique file-level identifier assigned by Illumina BaseSpace Sequence Hub to this specific FASTQ file object. Enables direct file-level API operations and provenance tracking within BaseSpace.',
    `compression_format` STRING COMMENT 'The compression algorithm applied to the FASTQ file. Standard for NGS data is gzip (.gz). Determines decompression requirements for bioinformatics pipeline ingestion and storage cost calculations.. Valid values are `gzip|bzip2|zstd|uncompressed`',
    `consent_status` STRING COMMENT 'The informed consent status of the subject associated with this FASTQ files sample. Governs permissible uses of the genomic data (research, clinical, secondary use). Withdrawn consent triggers data deletion or de-identification workflows per GDPR and HIPAA.. Valid values are `consented|withdrawn|not_required|pending`',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this FASTQ file record was first created in the sequencing data inventory (Silver Layer). Audit trail timestamp for data governance and lineage tracking.',
    `data_classification` STRING COMMENT 'The data sensitivity classification level assigned to this FASTQ file per Genomics Biotech data governance policy. Restricted = highest sensitivity (PHI/PII), Confidential = sensitive business data, Internal = general internal use, Public = no restrictions. Drives access control, encryption, and retention policies.. Valid values are `restricted|confidential|internal|public`',
    `encryption_status` STRING COMMENT 'Indicates whether this FASTQ file is encrypted at rest in cloud storage. Encryption is mandatory for PHI-containing files under HIPAA Security Rule and for GxP-regulated data. Supports security compliance auditing.. Valid values are `encrypted|unencrypted|pending`',
    `file_name` STRING COMMENT 'The full file name of the FASTQ output file including extension (e.g., SampleA_S1_L001_R1_001.fastq.gz). Follows Illumina naming conventions encoding sample, lane, read number, and index.. Valid values are `^[A-Za-z0-9_-.]+.fastq(.gz)?$`',
    `file_path` STRING COMMENT 'Cloud storage URI indicating the full path to the FASTQ file on BaseSpace or Amazon S3 (e.g., s3://genomics-biotech-seq/runs/RUN001/SampleA_R1.fastq.gz). Serves as the authoritative location reference for downstream bioinformatics pipeline access.',
    `file_size_bytes` BIGINT COMMENT 'The size of the FASTQ file in bytes as stored in cloud storage. Used for storage capacity planning, data transfer cost estimation, and file integrity verification. Compressed (gzip) size is recorded.',
    `file_status` STRING COMMENT 'Current lifecycle status of the FASTQ file in the sequencing data inventory. Pending = demultiplexing in progress, Available = ready for pipeline consumption, Archived = moved to cold storage, Deleted = purged per retention policy, Failed = generation error, Quarantined = held for QC investigation.. Valid values are `pending|available|archived|deleted|failed|quarantined`',
    `generation_timestamp` TIMESTAMP COMMENT 'The date and time when this FASTQ file was generated by the demultiplexing process. Represents the principal business event timestamp — the moment raw sequencing data became available as a FASTQ artifact. Used for TAT (Turnaround Time) calculations and data lineage.',
    `index_sequence` STRING COMMENT 'The nucleotide index sequence (barcode) used to identify and demultiplex this sample from a multiplexed sequencing run. Composed of ACGT bases. Critical for validating correct sample assignment and detecting index hopping or cross-contamination.. Valid values are `^[ACGTN]+$`',
    `intended_use_class` STRING COMMENT 'Regulatory classification of the intended use of this sequencing data. RUO = Research Use Only, IVD = In Vitro Diagnostic (FDA-cleared/approved), LDT = Laboratory Developed Test (CLIA-regulated). Governs data handling, access controls, and regulatory reporting obligations.. Valid values are `RUO|IVD|LDT|clinical_research`',
    `md5_checksum` STRING COMMENT 'The MD5 cryptographic hash of the FASTQ file used to verify file integrity during transfer, storage, and archival. Mandatory for data integrity validation in GxP-regulated environments and regulatory submissions.. Valid values are `^[a-f0-9]{32}$`',
    `mean_phred_quality_score` DECIMAL(18,2) COMMENT 'The mean Phred quality score (Q-score) across all bases in this FASTQ file. Phred scores represent the probability of a base call error (Q30 = 99.9% accuracy). A key QC metric for raw sequencing data quality assessment per NGS best practices.',
    `mean_read_length_bp` STRING COMMENT 'The mean length of sequencing reads in this FASTQ file measured in base pairs (bp). Reflects the sequencing chemistry and run configuration. Relevant for alignment pipeline parameter selection and quality benchmarking.',
    `pct_bases_q30` DECIMAL(18,2) COMMENT 'The percentage of bases in this FASTQ file with a Phred quality score of 30 or higher (≥Q30), indicating ≥99.9% base call accuracy. Industry-standard QC threshold for NGS data quality; typically ≥80% Q30 is required for clinical-grade sequencing.',
    `pct_reads_passing_filter` DECIMAL(18,2) COMMENT 'The percentage of reads in this FASTQ file that passed the Illumina chastity filter (PF reads). Reads failing the filter are excluded from analysis. A key indicator of cluster quality and flow cell performance.',
    `phi_flag` BOOLEAN COMMENT 'Indicates whether this FASTQ file is associated with Protected Health Information (PHI) as defined under HIPAA. When True, the file is subject to HIPAA Privacy and Security Rule requirements, access restrictions, and audit logging obligations. Drives data governance and access control enforcement.',
    `pipeline_ready_flag` BOOLEAN COMMENT 'Indicates whether this FASTQ file has passed all QC checks and is cleared for ingestion into bioinformatics analysis pipelines. When True, the file is eligible for alignment, variant calling, and downstream processing. Prevents failed or quarantined files from entering production pipelines.',
    `qc_failure_reason` STRING COMMENT 'Free-text description of the reason for QC failure when qc_status is fail or review. Documents specific quality issues (e.g., low Q30 percentage, insufficient read count, adapter contamination) for root cause analysis and CAPA processes.',
    `qc_status` STRING COMMENT 'The QC assessment outcome for this FASTQ file based on Phred scores, read counts, and other quality metrics. Pass = meets all QC thresholds, Fail = below minimum thresholds, Review = borderline requiring manual review, Not Assessed = QC not yet performed. Governs eligibility for downstream bioinformatics processing.. Valid values are `pass|fail|review|not_assessed`',
    `read_number` STRING COMMENT 'Designates the read type of this FASTQ file within a paired-end or indexed sequencing run. R1 = forward read, R2 = reverse read, I1 = index 1 (i7), I2 = index 2 (i5). Critical for demultiplexing validation and downstream alignment pipeline configuration.. Valid values are `R1|R2|I1|I2`',
    `retention_expiry_date` DATE COMMENT 'The calculated date on which this FASTQ file becomes eligible for deletion or archival based on the applied retention policy. Enables automated data lifecycle management and compliance with regulatory retention mandates.',
    `retention_policy` STRING COMMENT 'The data retention policy applied to this FASTQ file, governing how long the file must be retained before eligible for deletion or archival. Clinical data typically requires 10-year retention per CLIA/CAP; RUO data may follow shorter policies. Drives automated lifecycle management.. Valid values are `standard_1yr|extended_7yr|clinical_10yr|indefinite|custom`',
    `sequencing_assay_type` STRING COMMENT 'The type of NGS sequencing assay that produced this FASTQ file. Determines applicable bioinformatics pipelines, QC thresholds, and regulatory classification. [ENUM-REF-CANDIDATE: WGS|WES|targeted_panel|amplicon|RNA-seq|metagenomics|single_cell — promote to reference product]',
    `storage_tier` STRING COMMENT 'The cloud storage tier in which this FASTQ file currently resides. Hot = frequently accessed (active analysis), Warm = infrequent access, Cold = rare access, Archive = long-term retention (e.g., AWS Glacier). Drives storage cost management and retrieval SLA expectations.. Valid values are `hot|warm|cold|archive`',
    `total_read_count` BIGINT COMMENT 'The total number of sequencing reads contained in this FASTQ file after demultiplexing. A primary indicator of sequencing yield for this sample-lane combination. Used to assess whether minimum coverage depth thresholds are met for downstream analysis.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this FASTQ file record was most recently modified in the sequencing data inventory. Tracks status changes, QC updates, and metadata corrections for audit compliance.',
    `upload_timestamp` TIMESTAMP COMMENT 'The date and time when this FASTQ file was successfully uploaded to cloud storage (BaseSpace or S3). Distinct from generation_timestamp; captures the transfer completion event for data availability tracking and SLA monitoring.',
    CONSTRAINT pk_fastq_file PRIMARY KEY(`fastq_file_id`)
) COMMENT 'Master record representing a FASTQ output file generated from demultiplexing. Captures file name, file path (cloud storage URI on BaseSpace/S3), file size (bytes), read number (R1/R2/I1/I2), total read count, mean read length (bp), compression format (gzip), MD5 checksum, generation timestamp, associated library and run, BaseSpace dataset ID, retention policy, and data classification (PHI/non-PHI). SSOT for raw sequencing data file inventory — the primary output artifact of the sequencing domain.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sequencing`.`coverage_stat` (
    `coverage_stat_id` BIGINT COMMENT 'Unique surrogate identifier for each coverage statistic record computed post-demultiplexing for a sequencing library. Primary key for the coverage_stat data product in the Databricks Silver Layer.',
    `bioinformatics_pipeline_run_id` BIGINT COMMENT 'Reference to the bioinformatics pipeline run that computed these coverage statistics post-demultiplexing. Enables data lineage tracing from raw FASTQ to coverage metrics.',
    `experiment_id` BIGINT COMMENT 'Foreign key linking to research.experiment. Business justification: Coverage statistics are analyzed per-experiment to assess whether sequencing depth meets experimental objectives (e.g., variant detection sensitivity requirements). Drives resequencing decisions, expe',
    `gene_annotation_track_id` BIGINT COMMENT 'Foreign key linking to reference.gene_annotation_track. Business justification: Coverage over genes and exons requires specific annotation track for coordinate mapping. Enables gene-level coverage reporting for clinical assays and research applications, critical for interpreting ',
    `gene_model_id` BIGINT COMMENT 'Foreign key linking to reference.gene_model. Business justification: Coverage statistics are often reported at gene level for clinical and research applications. Enables gene-level coverage reporting, identifies genes with coverage gaps, and supports clinical interpret',
    `genome_assembly_id` BIGINT COMMENT 'Foreign key linking to reference.genome_assembly. Business justification: Coverage statistics are inherently reference-genome-dependent (coordinates, target regions, mappability). Essential for clinical reporting, QC assessment, and comparing coverage across different refer',
    `genomic_region_id` BIGINT COMMENT 'Foreign key linking to reference.genomic_region. Business justification: Coverage statistics for targeted assays are calculated over specific genomic regions. Enables region-level coverage reporting, identifies coverage gaps in target regions, and supports clinical assay v',
    `library_id` BIGINT COMMENT 'Reference to the sequencing library for which this coverage statistic record was computed. Links to the library preparation entity in the sequencing domain.',
    `pharmacogenomics_marker_id` BIGINT COMMENT 'Foreign key linking to reference.pharmacogenomics_marker. Business justification: PGx assays require coverage verification over specific markers for clinical reporting. Essential for validating that all required PGx markers have adequate coverage for FDA/EMA-compliant pharmacogenom',
    `sample_specimen_id` BIGINT COMMENT 'Reference to the biological sample associated with the library. Enables traceability from coverage statistics back to the originating sample in the Sample Management domain.',
    `sequencing_run_id` BIGINT COMMENT 'Reference to the sequencing run that produced the raw reads from which this coverage statistic was derived. Enables traceability from coverage metrics back to the instrument run.',
    `test_catalog_id` BIGINT COMMENT 'Reference to the clinical or research assay definition against which coverage QC thresholds are evaluated. Determines the minimum coverage requirements applicable to this library.',
    `variant_database_id` BIGINT COMMENT 'Foreign key linking to reference.variant_database. Business justification: Coverage over clinically relevant variants (from databases like ClinVar) is a key QC metric for clinical assays. Ensures adequate coverage of actionable variants for clinical reporting and regulatory ',
    `approved_for_analysis` BOOLEAN COMMENT 'Indicates whether this librarys coverage statistics have been reviewed and approved for downstream bioinformatics analysis (variant calling, annotation). Set to True only when qc_status is Pass and any required manual review has been completed.',
    `assay_type` STRING COMMENT 'Classification of the sequencing assay type for which coverage statistics are computed. Determines applicable QC thresholds and on-target rate relevance. WGS (Whole Genome Sequencing), WES (Whole Exome Sequencing), Targeted panel, Amplicon, or RNA-Seq. [ENUM-REF-CANDIDATE: WGS|WES|Targeted|Amplicon|RNA-Seq|Other — promote to reference product if additional assay types are added]. Valid values are `WGS|WES|Targeted|Amplicon|RNA-Seq|Other`',
    `computed_timestamp` TIMESTAMP COMMENT 'Date and time when the coverage statistics were computed by the bioinformatics pipeline post-demultiplexing. Represents the principal business event timestamp for this record. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `coverage_uniformity_pct` DECIMAL(18,2) COMMENT 'Percentage of target bases covered at greater than or equal to 20% of the mean coverage depth. Measures how evenly reads are distributed across the target region. Higher uniformity indicates more consistent library preparation and hybridization efficiency.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this coverage statistic record was first created in the data platform. Supports audit trail and data lineage requirements. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `duplication_rate_pct` DECIMAL(18,2) COMMENT 'Percentage of mapped reads identified as PCR or optical duplicates. High duplication rates reduce effective coverage depth and can introduce variant calling artifacts. Computed by duplicate-marking tools (e.g., Picard MarkDuplicates) during bioinformatics processing.',
    `gc_bias_metric` DECIMAL(18,2) COMMENT 'Quantitative measure of GC content bias in coverage distribution, typically expressed as the normalized coverage deviation across GC content bins. Values near zero indicate minimal GC bias; large deviations indicate systematic under- or over-representation of GC-rich or GC-poor regions.',
    `insert_size_mean_bp` DECIMAL(18,2) COMMENT 'Mean insert size of the sequencing library in base pairs (bp). Reflects the average length of the DNA fragment between adapter sequences. Deviations from expected insert size indicate library preparation issues affecting coverage uniformity and read alignment.',
    `insert_size_std_dev_bp` DECIMAL(18,2) COMMENT 'Standard deviation of the insert size distribution in base pairs (bp). High standard deviation indicates heterogeneous fragment sizes, which may affect coverage uniformity and paired-end alignment efficiency.',
    `mapped_reads` BIGINT COMMENT 'Number of reads successfully aligned to the reference genome. Used to compute mapping rate and assess library quality. Low mapped read counts relative to total reads indicate contamination, adapter issues, or reference mismatch.',
    `mapping_rate_pct` DECIMAL(18,2) COMMENT 'Percentage of total reads that successfully aligned to the reference genome. A key indicator of library quality and sample integrity. Typically expected to be >95% for high-quality human genomic libraries.',
    `mean_base_quality_score` DECIMAL(18,2) COMMENT 'Mean Phred quality score across all bases in the library. Phred scores represent the probability of a base call error (Q30 = 99.9% accuracy). Used to assess sequencing chemistry performance and overall run quality.',
    `mean_coverage_depth` DECIMAL(18,2) COMMENT 'Average number of times each base in the target region (or genome for WGS) is sequenced, expressed in fold-coverage (X). Primary metric for assessing sequencing depth adequacy. Computed as total aligned bases divided by target region size.',
    `median_coverage_depth` DECIMAL(18,2) COMMENT 'Median number of times each base in the target region is sequenced, expressed in fold-coverage (X). Less sensitive to outlier regions than mean coverage; used alongside mean to assess coverage distribution skewness.',
    `min_coverage_threshold` DECIMAL(18,2) COMMENT 'Assay-specific minimum mean coverage depth threshold (in X) that must be met for the library to pass QC. Defined in the assay specification and used to evaluate the qc_status determination. Varies by assay type (e.g., 30X for clinical WGS, 100X for somatic oncology panels).',
    `min_pct_bases_threshold` DECIMAL(18,2) COMMENT 'Assay-specific minimum percentage of target bases that must achieve the defined coverage depth threshold (e.g., ≥95% of bases at ≥20X) for the library to pass QC. Defined in the assay specification document.',
    `notes` STRING COMMENT 'Free-text field for laboratory scientists or bioinformaticians to record observations, exceptions, or contextual information about this coverage statistic record. Used during manual QC review to document borderline cases or special circumstances.',
    `on_target_rate_pct` DECIMAL(18,2) COMMENT 'Percentage of aligned reads that map to the intended target region (capture panel or amplicon targets). Applicable for WES and targeted sequencing assays. Low on-target rate indicates poor hybridization capture efficiency or library quality issues.',
    `pct_bases_at_100x` DECIMAL(18,2) COMMENT 'Fraction of target bases (expressed as a percentage) achieving a minimum coverage depth of 100X. Relevant for somatic variant calling in oncology panels where high depth is required to detect low-frequency variants (low LOD applications).',
    `pct_bases_at_10x` DECIMAL(18,2) COMMENT 'Fraction of target bases (expressed as a percentage) achieving a minimum coverage depth of 10X. Standard threshold for variant calling sensitivity in WES and targeted sequencing panels.',
    `pct_bases_at_20x` DECIMAL(18,2) COMMENT 'Fraction of target bases (expressed as a percentage) achieving a minimum coverage depth of 20X. Common minimum threshold for clinical-grade variant calling in WES and targeted panels per CAP and CLIA guidelines.',
    `pct_bases_at_30x` DECIMAL(18,2) COMMENT 'Fraction of target bases (expressed as a percentage) achieving a minimum coverage depth of 30X. Recommended threshold for high-confidence germline variant calling in clinical WGS and WES workflows.',
    `pct_q30_bases` DECIMAL(18,2) COMMENT 'Percentage of bases in the library with a Phred quality score of 30 or higher (Q30), indicating 99.9% base call accuracy. Industry-standard metric for sequencing run quality assessment. Illumina typically specifies ≥80% Q30 as a run quality threshold.',
    `qc_failure_reason` STRING COMMENT 'Descriptive reason for QC failure when qc_status is Fail or Borderline. Documents which specific coverage metric(s) fell below assay-defined thresholds, supporting root cause analysis and resequencing decisions.',
    `qc_status` STRING COMMENT 'Overall QC pass/fail determination for this librarys coverage statistics evaluated against assay-specific thresholds. A Pass status indicates the library meets minimum coverage requirements for downstream bioinformatics analysis. Borderline indicates marginal coverage requiring manual review.. Valid values are `Pass|Fail|Borderline|Pending|Cancelled`',
    `reference_genome_version` STRING COMMENT 'Version of the reference genome used for read alignment and coverage computation (e.g., GRCh38, GRCh37/hg19, GRCm39). Critical for reproducibility and cross-sample comparability of coverage statistics. Must match the reference used in downstream variant calling pipelines.',
    `resequencing_required` BOOLEAN COMMENT 'Indicates whether this library has been flagged for resequencing due to insufficient coverage or QC failure. When True, the library must be re-run on the sequencer before downstream bioinformatics analysis can proceed.',
    `review_timestamp` TIMESTAMP COMMENT 'Date and time when the manual QC review of this coverage statistic record was completed. Supports audit trail requirements under CLIA, CAP, and GxP regulations. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `reviewed_by` STRING COMMENT 'Name or identifier of the laboratory scientist or bioinformatician who performed the manual QC review of this coverage statistic record. Required for clinical assays under CLIA and CAP accreditation to maintain an auditable review trail.',
    `source_system` STRING COMMENT 'Operational system of record from which this coverage statistic record originated. Supports data lineage and provenance tracking in the Databricks Silver Layer. Typically Illumina BaseSpace Sequence Hub for automated pipeline outputs or LabVantage LIMS for manually entered records.. Valid values are `BaseSpace|LabVantage|Benchling|Manual|Other`',
    `stat_identifier` STRING COMMENT 'Human-readable business identifier for this coverage statistic record, following the COVSTAT-{alphanumeric} naming convention. Used for cross-system referencing and audit trail purposes in LIMS and BaseSpace.. Valid values are `^COVSTAT-[A-Z0-9]{8,20}$`',
    `target_region_bed_file` STRING COMMENT 'Name or path of the BED file defining the target genomic regions used for on-target coverage calculations. Applicable for WES and targeted sequencing assays. Ensures coverage metrics are computed against the correct capture or amplicon panel definition.',
    `target_region_size_bp` BIGINT COMMENT 'Total size of the target genomic region in base pairs as defined by the BED file. Used as the denominator for coverage depth calculations. For WGS, this represents the effective genome size used in analysis.',
    `total_reads` BIGINT COMMENT 'Total number of sequencing reads generated for this library after demultiplexing. Represents the raw read count before any filtering or alignment steps. Used to assess sequencing yield and library loading efficiency.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this coverage statistic record was last modified, such as after a QC review decision or recomputation. Supports audit trail requirements under GxP and ISO 13485. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `use_classification` STRING COMMENT 'Regulatory use classification of the assay producing this coverage statistic. RUO (Research Use Only), IVD (In Vitro Diagnostic), or LDT (Laboratory Developed Test). Determines applicable regulatory reporting and QC requirements under FDA, CLIA, and IVDR frameworks.. Valid values are `RUO|IVD|LDT|Clinical|Research`',
    CONSTRAINT pk_coverage_stat PRIMARY KEY(`coverage_stat_id`)
) COMMENT 'Transactional record storing per-library sequencing coverage statistics computed post-demultiplexing. Captures mean coverage depth (X), median coverage depth, coverage uniformity (%), fraction of bases at ≥10X, ≥20X, ≥30X, ≥100X thresholds, on-target rate (% for targeted/WES), duplication rate (%), insert size mean and standard deviation, GC bias metric, and coverage QC pass/fail against assay-specific thresholds. Enables assessment of whether a library meets minimum coverage requirements for downstream bioinformatics analysis.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sequencing`.`index_set` (
    `index_set_id` BIGINT COMMENT 'Unique surrogate identifier for the sequencing index set record in the Genomics Biotech lakehouse. Primary key for the index_set master resource.',
    `batch_id` BIGINT COMMENT 'Foreign key linking to supply.batch. Business justification: Index kits are batch-managed. Link enables lot traceability for quality investigations (index hopping, demux failures), recall management, expiry tracking, and GMP documentation. Removes denormalized ',
    `catalog_item_id` BIGINT COMMENT 'Foreign key linking to product.catalog_item. Business justification: Index/adapter sets are sold as catalog items with specific SKUs. Critical for ordering, compatibility validation with library prep kits, regulatory documentation, and ensuring correct product versions',
    `coa_id` BIGINT COMMENT 'Reference identifier for the Certificate of Analysis (COA) document associated with this index set lot, stored in Veeva Vault or MasterControl. Provides traceability to quality release documentation including purity, concentration, and sequence verification results.',
    `material_id` BIGINT COMMENT 'Foreign key linking to supply.material. Business justification: Index kits are materials. Link enables inventory management, demand planning based on multiplexing forecasts, MRP planning, and supply chain integration for procurement and stock level optimization.',
    `nonconformance_id` BIGINT COMMENT 'Foreign key linking to quality.nonconformance. Business justification: Index sets can be nonconforming (failed validation, incorrect sequences, manufacturing defect, contamination). Labs track NCRs for supplier quality management, lot disposition, and regulatory reportin',
    `supplier_id` BIGINT COMMENT 'Foreign key linking to supply.supplier. Business justification: Index kit supplier tracking. Enables supplier quality management for index-related issues (index hopping, low demux rates), performance evaluation, and supplier qualification. Removes denormalized man',
    `validation_study_id` BIGINT COMMENT 'Foreign key linking to quality.validation_study. Business justification: Index sets are validated for use in multiplexed sequencing (cross-contamination testing, demultiplexing accuracy, color balance verification). Labs link index sets to validation studies for regulatory',
    `adapter_sequence_read1` STRING COMMENT 'Full adapter sequence flanking the i7 index on the Read 1 side, used for adapter trimming in bioinformatics preprocessing pipelines. Stored in 5→3 orientation per IUPAC convention.. Valid values are `^[ACGTNacgtn]*$`',
    `adapter_sequence_read2` STRING COMMENT 'Full adapter sequence flanking the i5 index on the Read 2 side, used for adapter trimming in paired-end bioinformatics preprocessing pipelines. Null for single-end or single-index configurations.. Valid values are `^[ACGTNacgtn]*$`',
    `approval_date` DATE COMMENT 'Date on which the index set was formally approved for production use by the sequencing operations quality authority. Null if not yet approved. Triggers availability for pool design and run scheduling.',
    `approval_status` STRING COMMENT 'Current lifecycle and approval status of the index set within Genomics Biotech sequencing operations. pending_validation = under internal validation; validated = technically validated but not yet formally approved; approved = approved for production use; deprecated = superseded by a newer set, no new runs; retired = fully decommissioned.. Valid values are `pending_validation|validated|approved|deprecated|retired`',
    `approved_by` STRING COMMENT 'Name or employee identifier of the quality authority or sequencing operations manager who granted formal production approval for this index set. Required for GxP and ISO 13485 audit trails.',
    `basespace_index_set_code` STRING COMMENT 'The unique identifier assigned to this index set within Illumina BaseSpace Sequence Hub. Enables direct cross-reference between the Genomics Biotech lakehouse master record and the operational sequencing data management platform for run configuration and demultiplexing.',
    `color_balance_status` STRING COMMENT 'Indicates whether the index set provides adequate color (fluorescence channel) balance across all sequencing cycles on two-channel or four-channel chemistry instruments. balanced = no spike-in required; unbalanced = color imbalance detected; requires_spike_in = PhiX or other spike-in control is mandatory. Prevents base-calling failures on patterned flow cells.. Valid values are `balanced|unbalanced|requires_spike_in`',
    `compatible_instruments` STRING COMMENT 'Comma-separated list of sequencing instrument models validated for use with this index set (e.g., NovaSeq 6000, NextSeq 550, MiSeq). Ensures that run configuration and read cycle parameters are compatible with the index chemistry.',
    `compatible_library_prep_kits` STRING COMMENT 'Comma-separated list of library preparation kit names or catalogue numbers validated for use with this index set (e.g., TruSeq DNA PCR-Free, TruSeq Stranded mRNA, Nextera DNA Flex). Managed by sequencing operations to prevent incompatible kit-index pairings during run setup.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this index set record was first created in the Genomics Biotech lakehouse data platform. Supports audit trail, data lineage, and GxP record integrity requirements. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `deprecation_date` DATE COMMENT 'Date on which the index set was deprecated or retired from active use. Null if still active. Used to enforce that no new sequencing runs are configured with deprecated index sets and to support historical traceability.',
    `gmp_compliant` BOOLEAN COMMENT 'Indicates whether the index set was manufactured under Good Manufacturing Practice (GMP) conditions as required for IVD or clinical use. True = GMP-manufactured; False = non-GMP (RUO grade). Drives quality management and supplier qualification requirements.',
    `i5_sequence` STRING COMMENT 'Nucleotide sequence of the i5 (read 2 side) index used in dual-index configurations. Null or empty for single-index sets. Stored as a representative or consensus sequence; individual per-sample i5 sequences are tracked at the library level.. Valid values are `^[ACGTNacgtn]*$`',
    `i7_sequence` STRING COMMENT 'Nucleotide sequence of the i7 (read 1 side) index used for sample identification during demultiplexing. Stored as a representative or consensus sequence for the set; individual per-sample i7 sequences are tracked at the library level. Validated against IUPAC nucleotide codes.. Valid values are `^[ACGTNacgtn]+$`',
    `index_count` STRING COMMENT 'Total number of unique index sequences (barcodes) available in the set. Determines the maximum multiplexing capacity — i.e., the maximum number of samples that can be pooled in a single sequencing run using this index set.',
    `index_length_bp` STRING COMMENT 'Length of the index sequence in base pairs (bp), typically 6, 8, 10, or 12 bp. Determines the read cycle configuration on the sequencer and affects the number of unique indices available in the set. Must match the sequencing run setup parameters.',
    `index_type` STRING COMMENT 'Classification of the indexing strategy used in the set. single = single-end index (i7 only); dual = dual-index (i7 + i5, may be combinatorial); UDI = Unique Dual Index (each sample has a unique i7+i5 pair, preventing index hopping); combinatorial = combinatorial dual index (i7 and i5 drawn from independent pools). Critical for demultiplexing configuration and index-hopping risk assessment.. Valid values are `single|dual|UDI|combinatorial`',
    `intended_use` STRING COMMENT 'Regulatory intended use classification for the index set. RUO = Research Use Only; IVD = In Vitro Diagnostic; LDT = Laboratory Developed Test; research = internal research; clinical = clinical genomics applications; agricultural = agricultural genomics; both = dual RUO and clinical use. Governs which workflows and regulatory submissions this index set may support. [ENUM-REF-CANDIDATE: RUO|IVD|LDT|research|clinical|agricultural|both — promote to reference product]',
    `lims_index_set_code` STRING COMMENT 'The unique identifier for this index set in LabVantage LIMS, the system of record for sample tracking and laboratory workflow management. Enables traceability between the lakehouse master record and LIMS-managed library preparation and pool design workflows.',
    `max_multiplex_samples` STRING COMMENT 'Maximum number of samples that can be pooled (multiplexed) in a single sequencing run using this index set while maintaining the minimum Hamming distance threshold. Derived from the validated index set design; used in pool design planning and run capacity management.',
    `min_hamming_distance` STRING COMMENT 'The minimum Hamming distance between any two index sequences within the set. A higher value (typically ≥3) reduces the risk of index misassignment during demultiplexing. Critical quality parameter for pool design validation and collision prevention.',
    `notes` STRING COMMENT 'Free-text field for sequencing operations scientists to record additional context, known limitations, special handling instructions, or validation observations for this index set that are not captured in structured fields.',
    `phix_spike_in_pct` DECIMAL(18,2) COMMENT 'Recommended percentage of PhiX control library to spike into the pool when using this index set, to correct for color imbalance or low-diversity libraries. Expressed as a percentage of total library pool volume (e.g., 1.00, 5.00, 20.00). Zero if no spike-in is required.',
    `read_orientation` STRING COMMENT 'Specifies the orientation in which the i5 index is read on the sequencer. Critical for correct demultiplexing on instruments with different flow cell orientations (e.g., NovaSeq v1.5 flow cells require reverse complement of i5 vs. standard orientation). [ENUM-REF-CANDIDATE: forward|reverse_complement|forward_reverse|reverse_complement_forward — promote to reference product]. Valid values are `forward|reverse_complement|forward_reverse|reverse_complement_forward`',
    `regulatory_clearance_number` STRING COMMENT 'FDA 510(k) clearance number, CE-IVD certificate number, or equivalent regulatory authorization number if the index set is part of a cleared or approved IVD product. Null for RUO-only index sets. Required for regulatory submissions and audit trails.',
    `sequencing_chemistry` STRING COMMENT 'The sequencing chemistry type for which this index set is designed. Determines color balance requirements and base-calling algorithm compatibility. two_channel = Illumina two-channel SBS (e.g., NextSeq, NovaSeq); four_channel = Illumina four-channel SBS (e.g., MiSeq, HiSeq); ion_semiconductor = Ion Torrent; nanopore = Oxford Nanopore; other = other chemistry.. Valid values are `two_channel|four_channel|ion_semiconductor|nanopore|other`',
    `set_code` STRING COMMENT 'Externally-known unique alphanumeric code or catalogue number assigned to the index set by the manufacturer or internally by sequencing operations. Used as the business key for cross-system lookups and BOM references in SAP S/4HANA MM.. Valid values are `^[A-Z0-9_-]{2,30}$`',
    `set_name` STRING COMMENT 'Human-readable name of the sequencing index set as defined by the manufacturer or sequencing operations team (e.g., Illumina TruSeq CD Index Set A, IDT xGen UDI-UMI Adapters). Used as the primary display label in library preparation workflows and pool design tools.',
    `shelf_life_months` STRING COMMENT 'Manufacturer-specified shelf life of the index set reagents in months from the date of manufacture. Used for expiry tracking, inventory management, and ensuring reagents are not used beyond their validated stability window.',
    `sop_reference` STRING COMMENT 'Document number or identifier of the Standard Operating Procedure (SOP) governing the use, handling, and storage of this index set. Links to the controlled document in MasterControl or Veeva Vault. Ensures procedural compliance during library preparation.',
    `storage_temperature_c` DECIMAL(18,2) COMMENT 'Required storage temperature for the index set reagents in degrees Celsius (e.g., -20.0, 4.0). Critical for reagent integrity, shelf-life compliance, and cold-chain management in the laboratory.',
    `superseded_by_set_code` STRING COMMENT 'Set code of the newer index set that replaces this one when it is deprecated. Enables migration guidance for sequencing operations teams transitioning from legacy to current index chemistries. Null if not superseded.',
    `umi_included` BOOLEAN COMMENT 'Indicates whether the index set includes Unique Molecular Identifiers (UMIs) integrated into the adapter design. UMIs enable PCR duplicate removal and error correction in downstream bioinformatics pipelines, critical for low-input and cfDNA applications.',
    `umi_length_bp` STRING COMMENT 'Length of the UMI sequence in base pairs when UMIs are included in the index set design (e.g., 8, 12 bp). Null if umi_included is False. Required for configuring UMI extraction steps in bioinformatics pipelines.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this index set record in the Genomics Biotech lakehouse. Tracks the last modification event for change control, data freshness monitoring, and GxP audit trail compliance. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `validated_by` STRING COMMENT 'Name or employee identifier of the sequencing operations scientist or engineer who performed and signed off on the internal technical validation of this index set. Supports GxP audit trail requirements.',
    `validation_date` DATE COMMENT 'Date on which the index set completed internal technical validation by Genomics Biotech sequencing operations, confirming that demultiplexing performance, Hamming distance, and color balance meet acceptance criteria. Null if validation is pending.',
    `version_number` STRING COMMENT 'Version number of the index set definition, following semantic versioning convention (e.g., v1.0, v2.1, v1.0.3). Incremented when index sequences, Hamming distance parameters, or compatibility matrices are updated. Supports change control and audit trail requirements.. Valid values are `^vd+.d+(.d+)?$`',
    CONSTRAINT pk_index_set PRIMARY KEY(`index_set_id`)
) COMMENT 'Controlled reference master for sequencing index (barcode) sets used in library multiplexing. Captures index set name, manufacturer, index type (single/dual/UDI/combinatorial), i7 and i5 sequences, index length (bp), compatible library prep kits and instruments, Hamming distance from nearest neighbor in the set, color balance properties, and approval status. Managed by sequencing operations to prevent index collisions during pool design and ensure reliable demultiplexing. Updated when new index chemistries are validated.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sequencing`.`sequencing_protocol` (
    `sequencing_protocol_id` BIGINT COMMENT 'Unique surrogate identifier for the sequencing protocol record. Primary key for the sequencing_protocol data product in the Silver Layer lakehouse. Role: MASTER_RESOURCE.',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: GxP-regulated sequencing protocols require documented approval by qualified personnel for regulatory submissions and CLIA/CAP compliance. Distinct from protocol_owner. Real process: protocol validatio',
    `catalog_item_id` BIGINT COMMENT 'Foreign key linking to product.catalog_item. Business justification: Validated sequencing protocols specify approved/compatible kit catalog items. Essential for SOP compliance, regulatory submissions (FDA/IVDR), quality system requirements, and ensuring only validated ',
    `change_control_id` BIGINT COMMENT 'Foreign key linking to quality.change_control. Business justification: Changes to sequencing protocols (parameter updates, new applications, cycle count changes) require change control in GxP environments. Labs link protocol changes to change control records for validati',
    `controlled_document_id` BIGINT COMMENT 'Foreign key linking to quality.controlled_document. Business justification: Sequencing protocols ARE controlled documents in GxP environments. Every protocol must link to its document record for version control, training tracking, change control, and regulatory compliance. Fu',
    `gene_annotation_track_id` BIGINT COMMENT 'Foreign key linking to reference.gene_annotation_track. Business justification: Protocols for RNA-seq and targeted gene panels specify which annotation version to use. Critical for protocol standardization, regulatory compliance, and ensuring consistent gene-level analysis across',
    `genome_assembly_id` BIGINT COMMENT 'Foreign key linking to reference.genome_assembly. Business justification: Sequencing protocols specify which reference genome build to use for alignment and analysis. Regulatory validation is build-specific; this link ensures protocol compliance and supports regulatory subm',
    `genomic_region_id` BIGINT COMMENT 'Foreign key linking to reference.genomic_region. Business justification: Targeted sequencing protocols define the specific genomic regions to be captured. Essential for protocol validation, regulatory submissions, and ensuring all runs following protocol target the correct',
    `material_id` BIGINT COMMENT 'Foreign key linking to supply.material. Business justification: Sequencing protocols specify approved materials (reagent kits, consumables) for GMP compliance. Link enables procurement to validate material purchases against approved protocols and supports MRP plan',
    `mdm_policy_id` BIGINT COMMENT 'Foreign key linking to data.mdm_policy. Business justification: Sequencing protocols must comply with master data management policies (GxP validation requirements, CLIA quality standards, data retention mandates) - regulatory alignment requirement. Policies govern',
    `metadata_schema_id` BIGINT COMMENT 'Foreign key linking to data.metadata_schema. Business justification: Sequencing protocols define required metadata fields (sample sheet structure, run parameters, QC thresholds) that must conform to standardized schemas for FAIR compliance, regulatory submissions, and ',
    `rd_capitalization_id` BIGINT COMMENT 'Foreign key linking to finance.rd_capitalization. Business justification: Validated sequencing protocols achieving technical feasibility and regulatory approval represent capitalized R&D assets. Links protocol development milestones to capitalization decisions for accurate ',
    `document_id` BIGINT COMMENT 'Document control identifier for the approved SOP governing execution of this sequencing protocol, as managed in MasterControl or Veeva Vault. Provides a direct link from the protocol record to the procedural document for GxP audit trails and training compliance.',
    `validation_study_id` BIGINT COMMENT 'Foreign key linking to quality.validation_study. Business justification: Sequencing protocols are validated through validation studies (method validation, protocol verification, performance qualification). Each protocol version must link to its validation study for regulat',
    `variant_database_id` BIGINT COMMENT 'Foreign key linking to reference.variant_database. Business justification: Clinical sequencing protocols specify which variant databases to use for interpretation (regulatory requirement). Essential for protocol validation, regulatory submissions, and ensuring consistent cli',
    `approval_date` DATE COMMENT 'Date on which the protocol version received final approval from the qualified approver. Distinct from effective_date (when it becomes operational). Required for GxP audit trails and regulatory submissions. Captured from MasterControl electronic signature timestamp.',
    `approval_status` STRING COMMENT 'Current lifecycle state of the sequencing protocol within the GxP change control workflow. Serves as the LIFECYCLE_STATUS category for MASTER_RESOURCE role. Only protocols in approved status may be used for clinical or regulated sequencing runs. Managed in Veeva Vault and MasterControl.. Valid values are `draft|under_review|approved|deprecated|retired`',
    `approved_by` STRING COMMENT 'Name or employee identifier of the qualified person (QP) or scientific director who granted final approval for this protocol version in the GxP change control system. Supports regulatory audit trail requirements. Captured from MasterControl or Veeva Vault electronic signature records.',
    `approved_library_prep_kits` STRING COMMENT 'Comma-separated list of approved library preparation kit names and catalog numbers validated for use with this sequencing protocol (e.g., Illumina DNA Prep (20018704), TruSeq DNA PCR-Free (20015963)). Only kits on this list may be used in GxP-regulated runs. Validated in Benchling and controlled in MasterControl.',
    `cap_accredited` BOOLEAN COMMENT 'Indicates whether this protocol is covered under a CAP-accredited laboratorys scope of accreditation. True = included in CAP accreditation scope; False = not within CAP scope. Relevant for clinical genomics laboratories reporting patient results.',
    `clia_validated` BOOLEAN COMMENT 'Indicates whether this protocol has been validated under CLIA requirements for clinical laboratory use. True = CLIA validation completed and documented; False = not CLIA validated (RUO or research only). Required for protocols used in LDT or clinical reporting contexts.',
    `compatible_instrument_models` STRING COMMENT 'Comma-separated list of sequencing instrument models validated for use with this protocol (e.g., NovaSeq 6000, NovaSeq X Plus, NextSeq 2000). Ensures run parameters are only applied to compatible hardware. Validated against instrument qualification records in LabVantage LIMS.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this sequencing protocol record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Serves as the RECORD_AUDIT_CREATED category. Populated automatically on insert and immutable thereafter. Supports GxP audit trail requirements.',
    `demultiplexing_tool` STRING COMMENT 'Approved software tool used to demultiplex raw BCL files into per-sample FASTQ files for this protocol. Governs the bioinformatics pipeline entry point. BCL Convert is the current Illumina-recommended tool; DRAGEN provides accelerated on-instrument demultiplexing.. Valid values are `bcl2fastq|BCL Convert|DRAGEN|custom`',
    `effective_date` DATE COMMENT 'Date on which this protocol version became (or becomes) effective for use in sequencing operations. Serves as the EFFECTIVE_FROM category. Protocols may not be used in regulated runs before this date. Managed through GxP change control in MasterControl.',
    `flow_cell_type` STRING COMMENT 'Specific flow cell cartridge type required by this protocol (e.g., S4 Flow Cell, SP Flow Cell, P2 Flow Cell, 25B Flow Cell). Determines lane count, cluster capacity, and maximum data output. Must match the instrument model and run configuration. [ENUM-REF-CANDIDATE: S1|S2|S4|SP|P1|P2|P3|25B|nano — promote to reference product]',
    `gxp_classification` STRING COMMENT 'Regulatory practice classification applicable to runs executed under this protocol. GMP = Good Manufacturing Practice (production reagents); GLP = Good Laboratory Practice (non-clinical studies); GCP = Good Clinical Practice (clinical trials); non-GxP = research use. Determines documentation, validation, and audit requirements.. Valid values are `GMP|GLP|GCP|non-GxP`',
    `index1_cycle_count` STRING COMMENT 'Number of cycles for the Index 1 (i7) read used in multiplexing to demultiplex samples on a shared flow cell. Typically 8 or 10 cycles. Required for all multiplexed library pools. Null for non-indexed single-sample runs.',
    `index2_cycle_count` STRING COMMENT 'Number of cycles for the Index 2 (i5) read used in dual-index multiplexing schemes. Typically 8 or 10 cycles. Null for single-index or non-indexed protocols. Dual indexing reduces index-hopping artifacts in high-multiplex runs.',
    `intended_use` STRING COMMENT 'Regulatory classification of the protocols intended use. RUO = Research Use Only; IVD = In Vitro Diagnostic (FDA-cleared); LDT = Laboratory Developed Test (CLIA-regulated); CE-IVD = EU Conformité Européenne In Vitro Diagnostic. Determines applicable regulatory framework, labeling requirements, and permissible clinical use.. Valid values are `RUO|IVD|LDT|CE-IVD|research`',
    `max_cluster_density` DECIMAL(18,2) COMMENT 'Maximum acceptable cluster density on the flow cell surface in K/mm². Exceeding this threshold causes cluster overlap (over-clustering), degrading base call quality and Q30 scores. Paired with min_cluster_density to define the acceptable loading range.',
    `max_insert_size_bp` STRING COMMENT 'Maximum acceptable DNA insert size in base pairs for library fragments. Inserts exceeding this threshold may indicate insufficient fragmentation, leading to reduced cluster density and read-through artifacts. Paired with min_insert_size_bp to define the acceptable library size range.',
    `min_cluster_density` DECIMAL(18,2) COMMENT 'Minimum acceptable cluster density on the flow cell surface, expressed in thousands of clusters per square millimeter (K/mm²). Below this threshold, insufficient data yield is expected. Used as a pre-run and mid-run QC gate in Illumina BaseSpace.',
    `min_insert_size_bp` STRING COMMENT 'Minimum acceptable DNA insert size in base pairs for library fragments sequenced under this protocol. Insert sizes below this threshold indicate over-fragmentation and may degrade paired-end alignment quality. Used as a library QC acceptance criterion in LabVantage LIMS.',
    `min_q30_threshold_pct` DECIMAL(18,2) COMMENT 'Minimum acceptable percentage of bases with a Phred quality score of 30 or higher (Q30), indicating ≥99.9% base call accuracy. Industry-standard QC gate for sequencing run acceptance. Runs falling below this threshold are flagged for investigation or resequencing. Typically ≥75% for most NGS applications.',
    `min_yield_gb` DECIMAL(18,2) COMMENT 'Minimum acceptable total sequencing data yield in gigabases (Gb) per run or per sample lane, as required to achieve the target coverage depth. Runs not meeting this threshold trigger a QC failure and potential resequencing. Derived from target coverage, genome size, and read length.',
    `mismatch_tolerance` STRING COMMENT 'Number of allowable base mismatches in the index sequence during demultiplexing before a read is assigned to the undetermined bin. Typically 0 or 1. Higher values increase sample assignment rates but risk index cross-contamination in high-multiplex pools.',
    `multiplexing_max_samples` STRING COMMENT 'Maximum number of samples that can be pooled and multiplexed on a single flow cell lane under this protocol while maintaining the target coverage depth per sample. Governs library pooling decisions in LabVantage LIMS and run planning in BaseSpace.',
    `owner` STRING COMMENT 'Name or employee identifier of the scientist or team lead responsible for maintaining and updating this sequencing protocol. The protocol owner initiates change control requests and is accountable for scientific validity. Sourced from Oracle Cloud HCM.',
    `phi_data_generated` BOOLEAN COMMENT 'Indicates whether sequencing runs executed under this protocol generate Protected Health Information (PHI) as defined by HIPAA. True = PHI is generated (clinical patient samples); False = no PHI (research/RUO samples). Governs data handling, storage, and access control requirements for resulting FASTQ and downstream files.',
    `protocol_code` STRING COMMENT 'Externally-known, human-readable unique code identifying this protocol and version (e.g., WGS-PCR-v2.1). Used as the business identifier across LIMS, BaseSpace, and regulatory submissions. Serves as the BUSINESS_IDENTIFIER category for MASTER_RESOURCE role.. Valid values are `^[A-Z]{2,6}-[A-Z0-9]{3,10}-v[0-9]{1,3}.[0-9]{1,2}$`',
    `protocol_name` STRING COMMENT 'Full descriptive name of the sequencing protocol (e.g., Whole Genome Sequencing PCR-Free 150bp Paired-End). Serves as the IDENTITY_LABEL category for MASTER_RESOURCE role. Used in reporting, SOP references, and customer-facing documentation.',
    `r1_cycle_count` STRING COMMENT 'Number of sequencing cycles for Read 1 (R1), determining the read length in base pairs for the forward read. Common values include 75, 100, 150, 250 cycles. Directly impacts data quality, coverage, and FASTQ file size. Serves as the MEASUREMENT_OR_VALUE category for MASTER_RESOURCE role.',
    `r2_cycle_count` STRING COMMENT 'Number of sequencing cycles for Read 2 (R2) in paired-end configurations. Null for single-end protocols. Must match R1 cycle count for symmetric paired-end runs or may differ for asymmetric configurations. Governs reverse read length in base pairs.',
    `read_configuration` STRING COMMENT 'Specifies whether the sequencing run is configured for single-end or paired-end reads. Paired-end reads generate two reads per fragment (R1 and R2), improving alignment accuracy and variant calling. Directly governs flow cell programming and FASTQ output structure.. Valid values are `single_end|paired_end`',
    `reference_genome_build` STRING COMMENT 'Standard reference genome assembly version used for alignment and variant calling under this protocol (e.g., GRCh38 for human, GRCm39 for mouse). Ensures reproducibility and comparability of genomic results across runs and cohorts. Aligns with NIH Genomic Data Sharing Policy requirements.. Valid values are `GRCh38|GRCh37|GRCm39|GRCm38|T2T-CHM13|custom`',
    `retirement_date` DATE COMMENT 'Date on which this protocol version was retired or superseded and is no longer approved for new sequencing runs. Serves as the EFFECTIVE_UNTIL category. Null for currently active protocols. Historical runs executed under this protocol remain valid after retirement.',
    `sequencing_application_type` STRING COMMENT 'Classification of the genomic sequencing application this protocol supports. Serves as the CLASSIFICATION_OR_TYPE category for MASTER_RESOURCE role. Drives downstream bioinformatics pipeline selection and QC thresholds. WGS = Whole Genome Sequencing; WES = Whole Exome Sequencing; RNA-seq = RNA Sequencing.. Valid values are `WGS|WES|targeted_panel|RNA-seq|amplicon|methylation`',
    `sequencing_protocol_description` STRING COMMENT 'Free-text narrative description of the sequencing protocol, including its scientific rationale, key distinguishing parameters, intended sample types, and any special handling requirements. Authored by the protocol owner and reviewed during the GxP approval process.',
    `sop_version` STRING COMMENT 'Version of the SOP document referenced by sop_document_id that is current and approved for use with this protocol version. Ensures the protocol record is always linked to the correct procedural revision, supporting GxP change control.. Valid values are `^[0-9]{1,3}.[0-9]{1,2}$`',
    `strand_specificity` STRING COMMENT 'Specifies the strand orientation of the sequencing library for RNA-seq and methylation protocols. Unstranded = no strand information preserved; Forward = sense strand; Reverse = antisense strand. Critical for accurate transcript quantification and differential expression analysis. Null for DNA-based protocols.. Valid values are `unstranded|forward|reverse`',
    `superseded_by_protocol_code` STRING COMMENT 'Protocol code of the newer version that replaces this protocol upon retirement. Null for the current active version. Enables forward navigation in the protocol version chain for change control traceability and migration of active runs.',
    `target_coverage_depth` STRING COMMENT 'Recommended mean sequencing coverage depth (in X, e.g., 30X for WGS, 100X for WES) required to meet analytical sensitivity thresholds for this protocol. Used to calculate required cluster density and flow cell loading. Governs pass/fail criteria for sequencing run QC.',
    `target_panel_bed_file` STRING COMMENT 'File path or artifact identifier for the BED (Browser Extensible Data) file defining the genomic target regions for targeted panel or WES protocols. Null for WGS protocols. Used by bioinformatics pipelines for on-target coverage calculation and variant calling region restriction. Stored in genomic artifact repository.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this sequencing protocol record, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Updated automatically on every write. Supports change detection, incremental ETL processing, and GxP audit trail requirements.',
    `version` STRING COMMENT 'Semantic version number of the sequencing protocol (e.g., 2.1.0). Incremented upon any approved change to run parameters, kit compatibility, or QC thresholds. Supports GxP change control traceability.. Valid values are `^[0-9]{1,3}.[0-9]{1,2}(.[0-9]{1,2})?$`',
    CONSTRAINT pk_sequencing_protocol PRIMARY KEY(`sequencing_protocol_id`)
) COMMENT 'Reference master for approved sequencing protocols and run configurations. Captures protocol name, version, sequencing application type (WGS, WES, targeted panel, RNA-seq, amplicon, methylation), instrument compatibility, read configuration (single-end/paired-end), read lengths (R1/R2 cycles), index read cycles, recommended coverage target, minimum Q30 threshold, approved library prep kits, SOP document reference, effective date, and approval status. Governs which run parameters are permissible for each assay type and supports GxP compliance.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sequencing`.`run_sample_sheet` (
    `run_sample_sheet_id` BIGINT COMMENT 'Unique surrogate identifier for the run sample sheet record in the Databricks Silver Layer. Primary key for this transactional entity. Role: TRANSACTION_HEADER.',
    `asset_id` BIGINT COMMENT 'Reference to the sequencing instrument (e.g., NovaSeq, NextSeq, MiSeq) on which this sample sheet is loaded and executed. Drives instrument-specific configuration parameters.',
    `employee_id` BIGINT COMMENT 'Reference to the laboratory operator or scientist who submitted and authorized the sample sheet for the sequencing run. Required for GxP audit trail and operator accountability under CLIA and GMP regulations.',
    `flow_cell_id` BIGINT COMMENT 'The unique serial or barcode identifier of the physical flow cell cartridge used in this sequencing run. Enables traceability from sample sheet to physical consumable for GxP lot tracking and COA reconciliation.',
    `sequencing_protocol_id` BIGINT COMMENT 'Foreign key linking to sequencing.sequencing_protocol. Business justification: Sample sheets configure sequencing runs according to approved protocols. run_sample_sheet currently has application_type, read_type, and cycle counts but no FK to sequencing_protocol. Adding sequencin',
    `sequencing_run_id` BIGINT COMMENT 'Reference to the sequencing run that this sample sheet configures. Links the sample sheet to the parent run record in the sequencing domain.',
    `adapter_read1` STRING COMMENT 'The adapter sequence to be trimmed from the 3 end of Read 1 during BCLConvert processing (e.g., AGATCGGAAGAGCACACGTCTGAACTCCAGTCA for TruSeq). Correct adapter specification is critical for accurate read trimming and downstream alignment quality.. Valid values are `^[ACGTN]+$`',
    `adapter_read2` STRING COMMENT 'The adapter sequence to be trimmed from the 3 end of Read 2 in paired-end runs (e.g., AGATCGGAAGAGCGTCGTGTAGGGAAAGAGTGT for TruSeq). Null for single-end runs. Must match the library preparation kit adapter chemistry.. Valid values are `^[ACGTN]+$`',
    `application_type` STRING COMMENT 'The genomic sequencing application configured for this run. Drives pipeline selection, adapter trimming, and analysis settings. Examples: WGS (Whole Genome Sequencing), WES (Whole Exome Sequencing), Targeted Panel, Amplicon, RNA-Seq, Methylation, 16S rRNA. [ENUM-REF-CANDIDATE: WGS|WES|Targeted Panel|Amplicon|RNA-Seq|Methylation|16S rRNA|Custom — promote to reference product]',
    `approved_timestamp` TIMESTAMP COMMENT 'Timestamp when the sample sheet received final approval (electronic signature) for use in a GxP-controlled sequencing run. Distinct from submission timestamp; captures the authorization event in the document lifecycle.',
    `basespace_run_code` STRING COMMENT 'The unique run identifier assigned by Illumina BaseSpace Sequence Hub upon run registration or upload. Enables direct cross-reference between the internal data platform record and the BaseSpace cloud environment for FASTQ retrieval and run monitoring.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this run sample sheet record was first created in the data platform. Used for audit trail and data lineage tracking per GxP and 21 CFR Part 11 electronic records requirements.',
    `demultiplexing_software` STRING COMMENT 'The software tool configured to process this sample sheet for demultiplexing BCL files into per-sample FASTQ files. Options include BCLConvert (current Illumina standard), bcl2fastq (legacy), or DRAGEN (on-instrument or cloud). Determines compatible sample sheet sections and parameter keys.. Valid values are `BCLConvert|bcl2fastq|DRAGEN`',
    `demultiplexing_software_version` STRING COMMENT 'Version string of the demultiplexing software (BCLConvert, bcl2fastq, or DRAGEN) specified in the sample sheet settings. Critical for reproducibility, pipeline validation, and regulatory submission documentation.',
    `electronic_signature` STRING COMMENT 'The electronic signature identifier or hash of the authorized signatory who approved this sample sheet for GxP-controlled runs. Required under 21 CFR Part 11 for electronic records in regulated environments. Stored as a reference token, not the raw signature credential.',
    `experiment_name` STRING COMMENT 'The experiment identifier or label captured in the [Header] section of the Illumina sample sheet. Provides a human-readable label for the run experiment, used for BaseSpace project organization and LIMS cross-referencing.',
    `flow_cell_type` STRING COMMENT 'The specific flow cell cartridge type loaded on the instrument for this run (e.g., SP, S1, S2, S4 for NovaSeq; P1, P2, P3 for NovaSeq X; High Output, Mid Output for NextSeq). Determines lane count, cluster density, and total output capacity.',
    `gxp_controlled` BOOLEAN COMMENT 'Indicates whether this sample sheet is subject to GxP (Good Practice Regulations) document control requirements, including version control, electronic signature, and audit trail obligations under 21 CFR Part 11 and applicable GMP/GLP/GCP frameworks.',
    `index1_cycles` STRING COMMENT 'Number of cycles for Index 1 (i7 index read) used in multiplexed library demultiplexing. Typically 8 or 10 cycles. Determines the length of the i7 barcode sequence read during the indexing phase.',
    `index2_cycles` STRING COMMENT 'Number of cycles for Index 2 (i5 index read) used in dual-indexed multiplexed library demultiplexing. Typically 8 or 10 cycles. Null for single-indexed runs. Required for dual-index demultiplexing workflows.',
    `index_adapter_kit` STRING COMMENT 'The specific index adapter kit used for multiplexing (e.g., IDT for Illumina DNA/RNA UD Indexes, Nextera DNA CD Indexes). Defines the index sequence set and ensures correct barcode assignment during demultiplexing.',
    `instrument_platform` STRING COMMENT 'The Illumina sequencing instrument platform model for which this sample sheet is configured. Determines supported flow cell types, read lengths, and chemistry parameters. [ENUM-REF-CANDIDATE: NovaSeq 6000|NovaSeq X|NextSeq 550|NextSeq 2000|MiSeq|HiSeq 4000|iSeq 100 — promote to reference product]',
    `investigator_name` STRING COMMENT 'Name of the principal investigator or study lead responsible for the samples in this run. Captured in the [Header] section of the Illumina sample sheet. Used for accountability, reporting, and GxP traceability.',
    `lane_count` STRING COMMENT 'Number of flow cell lanes configured in this sample sheet. Determines how samples are distributed across lanes for multiplexing. Varies by flow cell type (e.g., 2 lanes for SP, 4 lanes for S2/S4 on NovaSeq 6000).',
    `library_prep_kit` STRING COMMENT 'The name and version of the library preparation kit used to prepare samples for sequencing (e.g., Illumina DNA Prep, TruSeq DNA PCR-Free, Nextera DNA Flex). Determines adapter sequences, index compatibility, and recommended run parameters.',
    `lims_request_code` STRING COMMENT 'The work order or sequencing request identifier from LabVantage LIMS that initiated this sample sheet. Provides bidirectional traceability between the sample sheet and the originating laboratory workflow request.',
    `mask_short_reads` STRING COMMENT 'The MaskShortReads BCLConvert setting specifying the read length threshold below which reads are masked (replaced with Ns) rather than discarded. Complements minimum_trimmed_read_length to control short-read handling behavior in FASTQ output.',
    `minimum_trimmed_read_length` STRING COMMENT 'The MinimumTrimmedReadLength BCLConvert setting specifying the minimum acceptable read length (in base pairs) after adapter trimming. Reads shorter than this threshold are discarded. Impacts FASTQ output quality and downstream alignment performance.',
    `override_cycles_string` STRING COMMENT 'The OverrideCycles parameter string in Illumina sample sheet v2 format (e.g., Y151;I8;I8;Y151) that explicitly defines the cycle allocation for each read and index segment. Overrides default cycle settings and is used by BCLConvert for precise demultiplexing configuration.',
    `project_name` STRING COMMENT 'The project or study name associated with the samples in this sample sheet. Used for grouping FASTQ output files by project in BaseSpace and downstream bioinformatics pipelines. Maps to the Sample_Project column in the sample manifest.',
    `read1_cycles` STRING COMMENT 'Number of sequencing cycles for Read 1 (forward read). Directly determines the read length in base pairs for the primary read. Typical values range from 50 to 300 cycles depending on application and instrument platform.',
    `read2_cycles` STRING COMMENT 'Number of sequencing cycles for Read 2 (reverse read) in paired-end runs. Null for single-end runs. Must match Read 1 cycles for symmetric paired-end configurations or may differ for asymmetric designs.',
    `read_type` STRING COMMENT 'Specifies whether the sequencing run is configured as single-end (one read direction) or paired-end (forward and reverse reads). Paired-end reads improve alignment accuracy and are standard for WGS and WES applications.. Valid values are `single_end|paired_end`',
    `reagent_kit_lot_number` STRING COMMENT 'The lot number (LOT) of the sequencing reagent kit used for this run. Critical for GxP traceability, COA verification, and investigation of run failures attributable to reagent quality. Sourced from SAP S/4HANA QM batch records.',
    `run_sample_sheet_description` STRING COMMENT 'Free-text description field from the [Header] section of the Illumina sample sheet. May include run purpose, special instructions, or notes relevant to the sequencing configuration. Supports operational context for lab staff.',
    `sample_count` STRING COMMENT 'Total number of samples listed in the sample manifest section of this sample sheet. Represents the multiplexing depth for the run. Used for capacity planning, lane loading calculations, and demultiplexing validation.',
    `sample_sheet_format_version` STRING COMMENT 'Version of the Illumina sample sheet format used (v1 or v2). v2 supports multi-section configuration including [Header], [Reads], [BCLConvert_Settings], and [BCLConvert_Data] sections. Determines downstream demultiplexing compatibility and parser behavior.. Valid values are `v1|v2`',
    `sample_sheet_name` STRING COMMENT 'Human-readable name or title assigned to the sample sheet file, typically following the Illumina naming convention (e.g., SampleSheet_RunID_YYYYMMDD). Serves as the externally-known business identifier for this document. Aligns with Illumina BaseSpace Sequence Hub sample sheet naming standards.',
    `submission_timestamp` TIMESTAMP COMMENT 'The precise date and time (ISO 8601 with timezone offset) when the sample sheet was submitted to the instrument or uploaded to Illumina BaseSpace Sequence Hub. This is the principal business event timestamp for this transaction.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this run sample sheet record. Supports change tracking and GxP audit trail requirements for controlled documents.',
    `use_type` STRING COMMENT 'Regulatory intended use classification for the samples in this run. RUO (Research Use Only) indicates non-clinical research; IVD (In Vitro Diagnostic) indicates regulated diagnostic use; LDT (Laboratory Developed Test) indicates a lab-specific validated test; GMP indicates manufacturing-grade production run.. Valid values are `RUO|IVD|LDT|GMP|Research`',
    `validation_error_summary` STRING COMMENT 'Free-text summary of validation errors or warnings identified during automated sample sheet validation (e.g., index collision detected, invalid cycle count, missing required fields). Populated when validation_status is failed_validation. Supports rapid troubleshooting by lab operators.',
    `validation_status` STRING COMMENT 'Current lifecycle and validation state of the sample sheet. draft indicates in-preparation; pending_validation awaiting automated or manual QC check; validated passed all checks and approved for run execution; failed_validation contains errors blocking run start; superseded replaced by a corrected version; cancelled withdrawn before use. [ENUM-REF-CANDIDATE: draft|pending_validation|validated|failed_validation|superseded|cancelled — promote to reference product]. Valid values are `draft|pending_validation|validated|failed_validation|superseded|cancelled`',
    `version_number` STRING COMMENT 'Document version number of this sample sheet (e.g., v1.0, v1.1, v2.0). Incremented upon each revision or correction. Supports GxP document version control and supersession tracking. The combination of sample_sheet_name and version_number uniquely identifies a document revision.. Valid values are `^vd+.d+$`',
    CONSTRAINT pk_run_sample_sheet PRIMARY KEY(`run_sample_sheet_id`)
) COMMENT 'Transactional record representing the sample sheet submitted to configure a sequencing run on an Illumina instrument. Captures sample sheet format version (v1/v2), associated run and instrument, flow cell type, operator, submission timestamp, sample manifest (sample IDs, index assignments, project groupings), override cycles string, adapter sequences, application settings, and validation status. The sample sheet is the authoritative GxP-controlled input document that drives both instrument run setup and downstream demultiplexing configuration.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sequencing`.`run_failure_event` (
    `run_failure_event_id` BIGINT COMMENT 'Unique surrogate identifier for each sequencing run failure or abort event record in the Silver layer lakehouse. Primary key for this transactional entity. Role: TRANSACTION_HEADER.',
    `asset_id` BIGINT COMMENT 'Reference to the sequencing instrument on which the failed run was executed. Supports instrument reliability tracking, mean time between failures (MTBF) analysis, and preventive maintenance scheduling.',
    `employee_id` BIGINT COMMENT 'Reference to the laboratory operator or technician who initiated or was responsible for the failed sequencing run. Required for GxP deviation management and operator error root-cause analysis.',
    `flow_cell_id` BIGINT COMMENT 'Reference to the flow cell loaded on the instrument during the failed run. Supports flow cell lot-level failure trending, reagent quality investigation, and consumable reliability analysis.',
    `sequencing_run_id` BIGINT COMMENT 'Reference to the sequencing run that experienced the failure or abort event. Links this failure record to the parent run entity for traceability and root-cause analysis.',
    `support_case_id` BIGINT COMMENT 'Foreign key linking to customer.support_case. Business justification: Run failures generate customer support cases for service labs. Links failure events to customer incident tracking, CAPA, rerun coordination, and SLA impact assessment. Essential for customer-facing op',
    `affected_lanes` STRING COMMENT 'Comma-separated list or range notation of flow cell lane numbers affected by the failure event (e.g., 1,2,3 or 1-4 or ALL). Enables partial-lane failure analysis and assessment of sample impact scope. Null if failure affected the entire flow cell uniformly.',
    `affected_sample_count` STRING COMMENT 'Number of samples whose sequencing data was lost or compromised as a result of this failure event. Drives impact assessment, customer notification decisions, and rerun prioritization. Sourced from the pool/library manifest associated with the failed run.',
    `basespace_run_code` STRING COMMENT 'The run identifier assigned by Illumina BaseSpace Sequence Hub for the failed run. Enables direct cross-reference to the BaseSpace run record for diagnostic log retrieval, run metrics review, and support case filing with Illumina.',
    `capa_reference` STRING COMMENT 'Reference number linking this failure event to a formal Corrective and Preventive Action (CAPA) record in the quality management system (e.g., Veeva Vault). Null if no formal CAPA was initiated. Supports GxP deviation-to-CAPA traceability.. Valid values are `^CAPA-[0-9]{4,10}$`',
    `cluster_density_at_failure` DECIMAL(18,2) COMMENT 'Flow cell cluster density (in thousands of clusters per mm²) measured at or near the time of failure. Abnormal cluster density (too high or too low) is a key diagnostic indicator for library preparation issues, loading concentration errors, or flow cell defects.',
    `corrective_action_taken` STRING COMMENT 'Free-text description of the immediate corrective action taken in response to the failure event (e.g., instrument restart, reagent replacement, operator retraining). Distinct from the formal CAPA process; captures the on-the-spot remediation steps.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this run failure event record was first created in the system. Serves as the RECORD_AUDIT_CREATED field for audit trail and data lineage purposes.',
    `customer_notification_timestamp` TIMESTAMP COMMENT 'Date and time at which the customer or project owner was formally notified of the failure event. Used to measure notification turnaround time (TAT) against SLA commitments and regulatory reporting timelines.',
    `customer_notified` BOOLEAN COMMENT 'Indicates whether the customer or project owner was formally notified of the sequencing run failure and its impact on their samples or data deliverables. Supports SLA compliance tracking and customer communication audit trails.',
    `deviation_report_number` STRING COMMENT 'Formal deviation report number assigned in the quality management system (e.g., Veeva Vault) for this failure event. Distinct from the CAPA reference; the deviation report documents the non-conformance event itself, while CAPA tracks the systemic corrective action.',
    `downtime_duration_min` STRING COMMENT 'Total duration of instrument downtime in minutes attributable to this failure event, from failure detection to instrument return-to-service. Key input for instrument availability KPI calculation, OEE (Overall Equipment Effectiveness) reporting, and maintenance cost analysis.',
    `estimated_data_loss_gb` DECIMAL(18,2) COMMENT 'Estimated volume of sequencing data (in gigabases, Gb) lost as a result of the failure event. Calculated based on cycles completed, affected lanes, and expected yield per lane. Key metric for assessing business impact and prioritizing rerun decisions. Serves as the QUANTITATIVE_RESULT for this non-monetary transaction.',
    `failure_category` STRING COMMENT 'High-level classification of the root cause category for the sequencing run failure. Used for trend analysis, quality KPI reporting, and directing corrective action. Categories align with standard GxP deviation classification taxonomy.. Valid values are `instrument_error|reagent_failure|sample_quality|operator_error|software_error|environmental`',
    `failure_code` STRING COMMENT 'Structured alphanumeric code identifying the specific failure mode within the failure category. Sourced from the instrument error code library or quality management system codebook (e.g., INS-00142, REA-00031). Enables precise failure mode trending and FMEA alignment.. Valid values are `^[A-Z]{2,4}-[0-9]{3,6}$`',
    `failure_cycle` STRING COMMENT 'The sequencing cycle number at which the failure or abort event occurred during the run. Critical for diagnosing instrument or chemistry issues at specific cycle positions (e.g., early cycles vs. late cycles). Null if failure occurred before sequencing commenced.',
    `failure_description` STRING COMMENT 'Free-text narrative description of the sequencing run failure event, including observed symptoms, error messages, and contextual details captured at the time of detection. Supports root-cause investigation and deviation report authoring.',
    `failure_detected_timestamp` TIMESTAMP COMMENT 'The precise date and time at which the sequencing run failure or abort event was detected or reported. This is the principal real-world business event timestamp (BUSINESS_EVENT_TIMESTAMP) for this transaction, distinct from record audit timestamps.',
    `failure_event_code` STRING COMMENT 'Externally-known, human-readable business identifier for this failure event, used in deviation reports, CAPA references, and quality management system cross-references (e.g., RFE-20240315-0042). Serves as the BUSINESS_IDENTIFIER for this transaction.. Valid values are `^RFE-[A-Z0-9]{4,12}$`',
    `failure_status` STRING COMMENT 'Current lifecycle status of the failure event record within the quality management workflow. Tracks progression from initial detection through investigation, resolution, and closure. Serves as the LIFECYCLE_STATUS for this transaction.. Valid values are `open|under_investigation|resolved|closed|escalated`',
    `gxp_impacting` BOOLEAN COMMENT 'Indicates whether this failure event occurred in a GxP-regulated context (e.g., GMP, GLP, GCP) and therefore requires formal deviation management, CAPA, and regulatory documentation per applicable GxP guidelines. Drives regulatory reporting workflow routing.',
    `instrument_error_message` STRING COMMENT 'Verbatim error message or fault code string reported by the sequencing instrument at the time of failure. Sourced directly from instrument logs or Illumina BaseSpace Sequence Hub run diagnostics. Essential for instrument engineering root-cause analysis.',
    `ivd_run` BOOLEAN COMMENT 'Indicates whether the failed sequencing run was performed as part of an In Vitro Diagnostic (IVD) or Clinical Laboratory Developed Test (LDT) workflow, as opposed to a Research Use Only (RUO) application. Determines applicable regulatory reporting obligations (FDA, IVDR, CLIA).',
    `lims_event_code` STRING COMMENT 'The event or non-conformance record identifier from LabVantage LIMS corresponding to this failure event. Supports bidirectional traceability between the lakehouse Silver layer and the operational LIMS system of record.',
    `notes` STRING COMMENT 'Additional free-text notes or observations recorded by the investigator, quality team, or instrument engineer during the failure event lifecycle. Captures supplementary context not covered by structured fields, such as environmental conditions, shift notes, or escalation history.',
    `phred_score_at_failure` DECIMAL(18,2) COMMENT 'The mean Phred base quality score (Q-score) recorded at the cycle of failure or at the last completed quality checkpoint before failure. Provides quantitative evidence of data quality degradation leading up to the failure event. Null if failure occurred before quality metrics were generated.',
    `reagent_lot_number` STRING COMMENT 'Lot number of the sequencing reagent kit used during the failed run. Critical for reagent failure root-cause analysis, lot-level quality investigations, and supplier corrective action requests. Aligns with GMP lot traceability requirements.',
    `rerun_required` BOOLEAN COMMENT 'Indicates whether the failed sequencing run must be repeated to recover the lost data or meet the required coverage depth and quality thresholds. Drives rerun scheduling, resource allocation, and customer communication workflows.',
    `resolution_timestamp` TIMESTAMP COMMENT 'Date and time at which the failure event was formally resolved and the record was closed in the quality management system. Used to calculate mean time to resolution (MTTR) and compliance with deviation closure SLA targets.',
    `root_cause_category` STRING COMMENT 'Confirmed root cause category determined after investigation of the failure event. Distinct from failure_category (which is the initial classification at detection); this field is populated after root-cause analysis is complete. Aligns with standard fishbone/Ishikawa root cause taxonomy.. Valid values are `equipment|process|material|human_factor|environment|unknown`',
    `root_cause_description` STRING COMMENT 'Detailed narrative of the confirmed root cause identified through formal investigation. Populated after root-cause analysis is completed. Supports CAPA authoring, regulatory submission documentation, and institutional knowledge capture.',
    `sample_quality_issue` BOOLEAN COMMENT 'Indicates whether a sample quality problem (e.g., degraded DNA, low input concentration, contamination) was identified as a contributing factor to the run failure. Supports sample management quality trending and upstream LIMS feedback.',
    `servicenow_ticket_number` STRING COMMENT 'Reference to the ServiceNow incident or field service ticket created to manage the instrument repair or technical support response associated with this failure event. Enables cross-system traceability between quality events and IT/field service workflows.',
    `severity_level` STRING COMMENT 'Severity classification of the failure event based on its impact on data quality, patient safety, regulatory compliance, and business operations. Drives escalation workflows, notification requirements, and CAPA prioritization.. Valid values are `critical|major|minor|informational`',
    `software_version` STRING COMMENT 'Version of the instrument control software or run control application active at the time of the failure event. Required for software error root-cause analysis and version-specific defect tracking.',
    `total_cycles_planned` STRING COMMENT 'The total number of sequencing cycles that were planned for the run at the time of setup. Used in conjunction with failure_cycle to calculate the proportion of the run completed before failure, informing data loss estimation.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this run failure event record was last modified. Serves as the RECORD_AUDIT_UPDATED field for audit trail and change tracking purposes.',
    CONSTRAINT pk_run_failure_event PRIMARY KEY(`run_failure_event_id`)
) COMMENT 'Transactional record documenting a sequencing run failure or abort event. Captures failure event ID, run ID, failure category (instrument error, reagent failure, sample quality, operator error, software error), failure code, failure description, cycle at which failure occurred, affected lanes, estimated data loss (Gb), corrective action taken, rerun required flag, CAPA reference, and resolution timestamp. Feeds into quality management and instrument reliability tracking. Supports GxP deviation management.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sequencing`.`basecall_model` (
    `basecall_model_id` BIGINT COMMENT 'Unique identifier for the basecalling algorithm model record. Primary key.',
    `approval_id` BIGINT COMMENT 'Foreign key linking to regulatory.regulatory_approval. Business justification: Basecalling algorithms are software components of regulated IVD systems and must be traceable to the approval covering the complete system. FDA and EU MDR require software version control and approval',
    `change_control_id` BIGINT COMMENT 'Foreign key linking to quality.change_control. Business justification: Basecall model changes (version upgrades, algorithm updates, parameter tuning) require change control in regulated environments. Labs track model changes through change control for validation impact a',
    `employee_id` BIGINT COMMENT 'Reference to the user or authority who approved this basecalling model for operational use.',
    `submission_id` BIGINT COMMENT 'Reference identifier for regulatory submission (FDA 510(k), PMA, or CE-IVD) associated with this basecalling model.',
    `research_protocol_id` BIGINT COMMENT 'Reference identifier for the validation protocol document used to validate this basecalling model.',
    `catalog_item_id` BIGINT COMMENT 'Foreign key linking to product.catalog_item. Business justification: Basecalling software is a licensable product catalog item. Needed for license entitlement management, version control, regulatory validation documentation, and tracking which software SKU/version is a',
    `superseded_by_model_basecall_model_id` BIGINT COMMENT 'Reference to the newer basecalling model that supersedes this version.',
    `validation_study_id` BIGINT COMMENT 'Foreign key linking to quality.validation_study. Business justification: Basecall models are validated before use in GxP environments (accuracy testing, performance qualification, software validation). Each model version must link to its validation study for regulatory com',
    `superseded_basecall_model_id` BIGINT COMMENT 'Self-referencing FK on basecall_model (superseded_basecall_model_id)',
    `accuracy_percent` DECIMAL(18,2) COMMENT 'Measured accuracy of the basecalling model expressed as a percentage, representing the proportion of correctly called bases.',
    `algorithm_type` STRING COMMENT 'Classification of the underlying algorithm approach used for basecalling (e.g., neural network, machine learning, statistical).. Valid values are `neural_network|machine_learning|statistical|hybrid|template_matching|deep_learning`',
    `approval_date` DATE COMMENT 'Date when this basecalling model was officially approved for use in production sequencing workflows.',
    `ce_ivd_certified` BOOLEAN COMMENT 'Indicates whether the basecalling model has received CE-IVD certification for use in the European Union.',
    `compatible_chemistry_versions` STRING COMMENT 'Comma-separated list of sequencing chemistry versions supported by this basecalling model.',
    `compatible_instrument_platforms` STRING COMMENT 'Comma-separated list of sequencing instrument platforms compatible with this basecalling model (e.g., NovaSeq, MiSeq, NextSeq).',
    `computational_requirements` STRING COMMENT 'Description of computational resources required to run this basecalling model (CPU, GPU, memory, storage).',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this basecalling model record was first created in the system.',
    `deprecation_date` DATE COMMENT 'Date when this basecalling model was deprecated and is no longer recommended for new sequencing runs.',
    `developer_organization` STRING COMMENT 'Name of the organization or company that developed the basecalling model.',
    `documentation_url` STRING COMMENT 'Web URL link to the official documentation for this basecalling model.. Valid values are `^https?://.*$`',
    `error_rate_percent` DECIMAL(18,2) COMMENT 'Measured error rate of the basecalling model expressed as a percentage, representing the proportion of incorrectly called bases.',
    `fda_cleared` BOOLEAN COMMENT 'Indicates whether the basecalling model has received FDA clearance or approval for clinical use in the United States.',
    `gpu_accelerated` BOOLEAN COMMENT 'Indicates whether the basecalling model utilizes GPU acceleration for improved processing speed.',
    `gxp_compliant` BOOLEAN COMMENT 'Indicates whether the basecalling model has been developed and validated under Good Practice regulations (GMP, GLP, GCP).',
    `intended_use_classification` STRING COMMENT 'Regulatory classification of the basecalling model indicating whether it is for Research Use Only (RUO), In Vitro Diagnostic (IVD), Laboratory Developed Test (LDT), clinical, or research applications.. Valid values are `RUO|IVD|LDT|clinical|research`',
    `license_type` STRING COMMENT 'Type of software license governing the use of this basecalling model.. Valid values are `proprietary|open_source|commercial|academic|evaluation`',
    `mean_phred_score` DECIMAL(18,2) COMMENT 'Average Phred quality score produced by this basecalling model, indicating the confidence level of base calls.',
    `model_code` STRING COMMENT 'Unique business identifier code for the basecalling model used in operational systems and documentation.. Valid values are `^[A-Z0-9_-]{3,50}$`',
    `model_name` STRING COMMENT 'Human-readable name of the basecalling algorithm model.',
    `model_status` STRING COMMENT 'Current lifecycle status of the basecalling model indicating its availability and approval for use in production sequencing workflows.. Valid values are `active|deprecated|experimental|validated|retired|under_review`',
    `notes` STRING COMMENT 'Free-text notes containing additional information, usage guidelines, or special considerations for this basecalling model.',
    `processing_speed_gb_per_hour` DECIMAL(18,2) COMMENT 'Throughput speed of the basecalling model measured in gigabases processed per hour.',
    `q30_percent` DECIMAL(18,2) COMMENT 'Percentage of bases called with Phred quality score of 30 or higher (99.9% accuracy) by this model.',
    `release_date` DATE COMMENT 'Date when this basecalling model version was officially released for use.',
    `retirement_date` DATE COMMENT 'Date when this basecalling model was retired and is no longer supported or available for use.',
    `software_version` STRING COMMENT 'Version number of the software package that implements this basecalling model.',
    `supports_real_time_basecalling` BOOLEAN COMMENT 'Indicates whether the basecalling model can perform real-time basecalling during sequencing runs.',
    `training_dataset_description` STRING COMMENT 'Description of the dataset used to train the basecalling model, including sample types and sequencing conditions.',
    `training_dataset_size_gb` DECIMAL(18,2) COMMENT 'Size of the training dataset in gigabytes used to develop the basecalling model.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this basecalling model record was last modified in the system.',
    `validation_date` DATE COMMENT 'Date when the basecalling model successfully completed analytical validation studies.',
    `validation_status` STRING COMMENT 'Current validation status of the basecalling model indicating whether it has passed required analytical validation studies.. Valid values are `not_validated|in_validation|validated|failed_validation|revalidation_required`',
    `version` STRING COMMENT 'Version number of the basecalling model following semantic versioning convention (e.g., 1.0, 2.1.3).. Valid values are `^[0-9]+.[0-9]+(.[0-9]+)?$`',
    CONSTRAINT pk_basecall_model PRIMARY KEY(`basecall_model_id`)
) COMMENT 'Reference catalog of basecalling algorithm models and versions used to convert raw signal data to nucleotide sequences including accuracy and speed specifications';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sequencing`.`array_hybridization` (
    `array_hybridization_id` BIGINT COMMENT 'Unique identifier for the array hybridization run. Primary key for this transactional record of array-based hybridization operations.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Array services performed for customer accounts. Core service offering relationship for genotyping/expression services. Essential for billing, sample ownership, data access control, and regulatory comp',
    `approval_id` BIGINT COMMENT 'Foreign key linking to regulatory.regulatory_approval. Business justification: Array-based clinical assays must link to the regulatory approval authorizing their diagnostic use. Essential for FDA 510(k) compliance and CE-IVD traceability. Labs must document which approval covers',
    `catalog_item_id` BIGINT COMMENT 'Foreign key linking to product.catalog_item. Business justification: Array chips are catalog items with SKUs, lot numbers, and regulatory classifications. Critical for procurement, cost-per-sample tracking, regulatory traceability, and compatibility validation with sca',
    `array_type_id` BIGINT COMMENT 'Reference to the specific array product type used in this hybridization run (SNP array, methylation array, CGH array, expression array).',
    `asset_id` BIGINT COMMENT 'Reference to the scanner or hybridization instrument used to perform the array hybridization and imaging.',
    `clinical_evidence_id` BIGINT COMMENT 'Foreign key linking to regulatory.clinical_evidence. Business justification: Array hybridizations performed during clinical validation studies must link to the evidence record they contribute to. Required for tracing raw data to published performance claims and supporting regu',
    `contact_id` BIGINT COMMENT 'Foreign key linking to customer.contact. Business justification: Sample submitter for array services, result delivery contact. Critical for customer-facing service operations, QC notifications, and regulatory traceability of data delivery.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Array hybridization assays consume lab resources requiring cost center allocation for departmental cost tracking, project accounting, and accurate cost-per-sample calculations. Essential for genomics ',
    `employee_id` BIGINT COMMENT 'Reference to the laboratory technician or scientist who performed the array hybridization run.',
    `experiment_id` BIGINT COMMENT 'Foreign key linking to research.experiment. Business justification: Array hybridizations are experimental procedures generating genotyping/expression data for specific experiments. Linking enables experiment-level data aggregation, QC assessment against experimental o',
    `genome_assembly_id` BIGINT COMMENT 'Foreign key linking to reference.genome_assembly. Business justification: Array-based genotyping uses probe coordinates defined in specific genome builds. Variant calling from arrays requires reference genome context for coordinate mapping and clinical interpretation of arr',
    `installed_instrument_id` BIGINT COMMENT 'Foreign key linking to customer.installed_instrument. Business justification: Array hybridization on customer-site scanners. Tracks instrument usage, utilization, and service delivery for customer-installed array scanning instruments.',
    `internal_order_id` BIGINT COMMENT 'Foreign key linking to finance.internal_order. Business justification: Array experiments frequently support specific R&D projects or validation studies tracked via internal orders for project cost accumulation, budget management, and capitalization decisions. Standard ge',
    `lims_workflow_assignment_id` BIGINT COMMENT 'Foreign key linking to sample.lims_workflow_assignment. Business justification: Array hybridization processing is LIMS-tracked in genomics labs. Linking hybridization to workflow assignment enables tracking processing SLA compliance, operator accountability, batch-level quality c',
    `opportunity_id` BIGINT COMMENT 'Foreign key linking to commercial.opportunity. Business justification: Array hybridization services delivered for customer projects require opportunity linkage for service revenue tracking, project cost allocation, and billing. Standard in genomics service business where',
    `project_id` BIGINT COMMENT 'Reference to the research or clinical project under which this array hybridization was performed.',
    `qc_result_id` BIGINT COMMENT 'Foreign key linking to quality.qc_result. Business justification: Array hybridizations undergo QC (call rate, signal intensity, background intensity, signal-to-noise ratio). QC results determine sample disposition, reprocessing needs, and batch release. Standard arr',
    `quality_assessment_id` BIGINT COMMENT 'Foreign key linking to data.quality_assessment. Business justification: Array hybridizations assessed for call rate, signal intensity, background noise against manufacturer specifications - standard array QC workflow. Assessment results determine data release approval and',
    `quality_issue_id` BIGINT COMMENT 'Foreign key linking to data.quality_issue. Business justification: Failed array hybridizations (low call rate, high background, scanner errors) trigger quality issue logging for lab investigation and potential re-hybridization - standard lab QC workflow in genotyping',
    `lot_id` BIGINT COMMENT 'Foreign key linking to reagent.lot. Business justification: Array hybridizations consume reagent lots (array chips, hybridization buffers) requiring lot traceability for GxP compliance, COA verification, and quality investigations. New FK needed; removes denor',
    `research_protocol_id` BIGINT COMMENT 'Reference to the Standard Operating Procedure (SOP) or hybridization protocol version used for this run.',
    `sample_specimen_id` BIGINT COMMENT 'Reference to the biological sample loaded onto the array for hybridization. Links to the sample management domain.',
    `service_agreement_id` BIGINT COMMENT 'Foreign key linking to customer.service_agreement. Business justification: Array services delivered under service agreements with defined SLA terms, pricing, turnaround time. Essential for contract compliance verification and billing.',
    `technical_requirement_id` BIGINT COMMENT 'Foreign key linking to customer.technical_requirement. Business justification: Array experiments designed to meet customer-specified technical requirements (array type, application, QC thresholds). Links experiment design to customer engagement specifications for acceptance crit',
    `validation_study_id` BIGINT COMMENT 'Foreign key linking to quality.validation_study. Business justification: Array hybridizations are used in validation studies (array platform validation, assay verification, reproducibility studies). Labs link validation hybridizations to study records for regulatory compli',
    `rerun_array_hybridization_id` BIGINT COMMENT 'Self-referencing FK on array_hybridization (rerun_array_hybridization_id)',
    `analysis_software_version` STRING COMMENT 'Version of the bioinformatics software used for initial quality control and genotype calling from raw intensity data.',
    `array_barcode` STRING COMMENT 'Unique barcode or serial number printed on the physical array chip used in this hybridization run.',
    `array_position` STRING COMMENT 'Position or well location on the array plate or chip where the sample was loaded (e.g., R01C01 for row 1 column 1).',
    `background_intensity` DECIMAL(18,2) COMMENT 'Average background fluorescence intensity measured in non-probe regions of the array, used to assess signal-to-noise ratio.',
    `call_rate_percent` DECIMAL(18,2) COMMENT 'Percentage of probes on the array that produced a valid genotype or methylation call, indicating data completeness.',
    `consent_status` STRING COMMENT 'Status of patient or research participant consent for genomic data generation and sharing from this array hybridization.. Valid values are `consented|not_required|pending|withdrawn|expired`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this array hybridization record was first created in the system.',
    `gxp_classification` STRING COMMENT 'Good Practice regulation classification applicable to this array hybridization run: Good Manufacturing Practice (GMP), Good Laboratory Practice (GLP), Good Clinical Practice (GCP), or non-GxP.. Valid values are `GMP|GLP|GCP|non_gxp`',
    `hybridization_duration_hours` DECIMAL(18,2) COMMENT 'Total duration in hours that the sample was incubated on the array during the hybridization process.',
    `hybridization_end_timestamp` TIMESTAMP COMMENT 'Date and time when the array hybridization process was completed and the array was ready for scanning.',
    `hybridization_start_timestamp` TIMESTAMP COMMENT 'Date and time when the array hybridization process was initiated in the laboratory.',
    `hybridization_status` STRING COMMENT 'Current lifecycle status of the array hybridization run in the laboratory workflow. [ENUM-REF-CANDIDATE: pending|in_progress|completed|failed|aborted|qc_review|approved|rejected — 8 candidates stripped; promote to reference product]',
    `hybridization_temperature_c` DECIMAL(18,2) COMMENT 'Temperature in degrees Celsius at which the array hybridization was performed, critical for assay reproducibility.',
    `input_dna_mass_ng` DECIMAL(18,2) COMMENT 'Total mass of DNA in nanograms used as input for the array hybridization reaction.',
    `intended_use` STRING COMMENT 'Regulatory classification of the array hybridization run: Research Use Only (RUO), In Vitro Diagnostic (IVD), Laboratory Developed Test (LDT), or clinical trial.. Valid values are `RUO|IVD|LDT|clinical_trial|research`',
    `lims_run_code` STRING COMMENT 'External identifier for this array hybridization run in the Laboratory Information Management System (LIMS) for cross-system traceability.',
    `md5_checksum` STRING COMMENT 'MD5 hash of the raw data file used to verify data integrity during transfer and storage.',
    `mean_signal_intensity` DECIMAL(18,2) COMMENT 'Average fluorescence signal intensity across all probes on the array, used as a quality metric.',
    `notes` STRING COMMENT 'Free-text field for capturing additional observations, deviations, or comments about the array hybridization run.',
    `phi_flag` BOOLEAN COMMENT 'Boolean indicator of whether this array hybridization run contains Protected Health Information subject to HIPAA regulations.',
    `probe_count` STRING COMMENT 'Total number of probes present on the array chip used in this hybridization run.',
    `qc_failure_reason` STRING COMMENT 'Detailed explanation of why the array hybridization run failed quality control checks, if applicable.',
    `qc_status` STRING COMMENT 'Quality control outcome for the array hybridization run based on signal intensity, background noise, and other quality metrics.. Valid values are `pending|passed|failed|conditional_pass|retest_required|not_applicable`',
    `raw_data_file_format` STRING COMMENT 'File format of the raw intensity data output from the array scanner (e.g., IDAT for Illumina, CEL for Affymetrix).. Valid values are `IDAT|CEL|TXT|CSV|proprietary`',
    `raw_data_file_path` STRING COMMENT 'File system path or cloud storage location where the raw intensity data (IDAT or CEL files) from the array scan is stored.',
    `raw_data_file_size_mb` DECIMAL(18,2) COMMENT 'Size of the raw intensity data file in megabytes, used for storage planning and data transfer tracking.',
    `run_code` STRING COMMENT 'Human-readable unique identifier or barcode for the array hybridization run, used for tracking and reference in Laboratory Information Management System (LIMS).',
    `run_name` STRING COMMENT 'Descriptive name assigned to the array hybridization run for easy identification and reporting purposes.',
    `sample_concentration_ng_ul` DECIMAL(18,2) COMMENT 'Concentration of nucleic acid sample in nanograms per microliter prior to loading on the array.',
    `sample_volume_ul` DECIMAL(18,2) COMMENT 'Volume of sample in microliters loaded onto the array for hybridization.',
    `scan_timestamp` TIMESTAMP COMMENT 'Date and time when the hybridized array was scanned to capture raw intensity data.',
    `scanner_software_version` STRING COMMENT 'Version of the scanner control software used to capture the array image and generate raw intensity data.',
    `signal_to_noise_ratio` DECIMAL(18,2) COMMENT 'Ratio of mean signal intensity to background intensity, a key quality metric for array hybridization performance.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this array hybridization record was last modified in the system.',
    CONSTRAINT pk_array_hybridization PRIMARY KEY(`array_hybridization_id`)
) COMMENT 'Transactional record of array-based hybridization runs for genotyping and methylation arrays — capturing array type (SNP array, methylation array, CGH array), hybridization protocol, sample loading, scanner assignment, and raw intensity data output references';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sequencing`.`file_quality_evaluation` (
    `file_quality_evaluation_id` BIGINT COMMENT 'Unique surrogate identifier for this quality evaluation execution record. Primary key for the association.',
    `fastq_file_id` BIGINT COMMENT 'Foreign key linking to the FASTQ file being evaluated in this quality check execution',
    `quality_rule_id` BIGINT COMMENT 'Foreign key linking to the quality rule definition applied in this evaluation',
    `evaluated_by` STRING COMMENT 'Identifier of the system, service, or user that executed this quality evaluation. Typically an automated pipeline service account, but may be a bioinformatician for manual QC review.',
    `execution_duration_seconds` DECIMAL(18,2) COMMENT 'The time in seconds required to execute this quality rule against this FASTQ file. Used for pipeline performance monitoring and optimization.',
    `failure_reason` STRING COMMENT 'Free-text description of why this rule failed or produced a warning for this file. Populated when rule_result is FAIL or WARNING. Supports troubleshooting and remediation.',
    `measured_value` DECIMAL(18,2) COMMENT 'The actual measured metric value from this FASTQ file that was compared against the rule threshold. For example, if rule checks minimum read count, this is the actual read count observed. Unit and interpretation depend on the rule type.',
    `pass_fail_status` BOOLEAN COMMENT 'Boolean indicator of whether this file passed this specific quality rule. True = passed, False = failed. Simplified binary version of rule_result for filtering and aggregation.',
    `pipeline_version` STRING COMMENT 'The version identifier of the bioinformatics QC pipeline that executed this rule evaluation. Enables tracking of rule results across pipeline version changes and supports reproducibility.',
    `remediation_action_taken` STRING COMMENT 'Description of any automated or manual remediation action taken in response to this rule failure. Examples: file re-sequenced, sample flagged for review, data excluded from analysis.',
    `rule_execution_timestamp` TIMESTAMP COMMENT 'The date and time when this quality rule was executed against this FASTQ file. Tracks when the evaluation occurred in the pipeline workflow.',
    `rule_result` STRING COMMENT 'The outcome of this quality rule evaluation. PASS = rule criteria met, FAIL = rule criteria not met, WARNING = borderline result, ERROR = execution error, SKIPPED = rule not applicable to this file type.',
    CONSTRAINT pk_file_quality_evaluation PRIMARY KEY(`file_quality_evaluation_id`)
) COMMENT 'This association product represents the Quality Evaluation event between fastq_file and quality_rule. It captures the execution and results of automated data quality checks applied to FASTQ files during bioinformatics pipeline processing. Each record links one FASTQ file to one quality rule execution with measured values, pass/fail status, and pipeline version context that exist only at the intersection of a specific file being evaluated against a specific rule.. Existence Justification: In genomics bioinformatics operations, each FASTQ file is evaluated against multiple quality rules (minimum read count, Q30 threshold, contamination detection, duplication rate limits, adapter content checks), and each quality rule is applied to many FASTQ files as they are generated. The business actively manages these quality evaluation results as operational records - bioinformatics teams query which files failed which rules, track pass rates over time, and trigger remediation workflows based on specific rule failures.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sequencing`.`array_type` (
    `array_type_id` BIGINT COMMENT 'Primary key for array_type',
    `superseded_array_type_id` BIGINT COMMENT 'Self-referencing FK on array_type (superseded_array_type_id)',
    `chemistry_version` STRING COMMENT 'Version of the sequencing chemistry used by the array.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the array type record was first created.',
    `data_format` STRING COMMENT 'File format produced by the array (e.g., FASTQ, BCL).',
    `array_type_description` STRING COMMENT 'Free‑text description of the array type, including use‑case notes.',
    `flow_cell_type` STRING COMMENT 'Designated flow cell format compatible with the array.',
    `is_active` BOOLEAN COMMENT 'Indicates whether the array type is currently active for new runs.',
    `library_prep_kit` STRING COMMENT 'Standard library preparation kit recommended for this array type.',
    `manufacturer` STRING COMMENT 'Company that manufactures the array platform.',
    `max_output_gb_per_run` DECIMAL(18,2) COMMENT 'Maximum data output in gigabytes per sequencing run.',
    `multiplexing_capacity` STRING COMMENT 'Maximum number of samples that can be multiplexed in a single run.',
    `array_type_name` STRING COMMENT 'Human‑readable name of the array type (e.g., "Illumina NovaSeq 6000").',
    `platform` STRING COMMENT 'Specific instrument platform model associated with the array type.',
    `read_length_bp` STRING COMMENT 'Maximum base‑pair read length the array can generate.',
    `recommended_coverage_depth` STRING COMMENT 'Suggested average sequencing depth (fold coverage) for optimal results.',
    `regulatory_approval_status` STRING COMMENT 'Regulatory status of the array type for clinical use.',
    `array_type_status` STRING COMMENT 'Lifecycle status of the array type.',
    `supported_sample_type` STRING COMMENT 'Type of biological sample the array is designed for (e.g., DNA, RNA, cfDNA).',
    `technology` STRING COMMENT 'Underlying sequencing technology (e.g., "Sequencing‑by‑Synthesis").',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the array type record.',
    CONSTRAINT pk_array_type PRIMARY KEY(`array_type_id`)
) COMMENT 'Master reference table for array_type. Referenced by array_type_id.';

CREATE OR REPLACE TABLE `genomics_biotech_ecm`.`sequencing`.`target_panel` (
    `target_panel_id` BIGINT COMMENT 'Primary key for target_panel',
    `superseded_target_panel_id` BIGINT COMMENT 'Self-referencing FK on target_panel (superseded_target_panel_id)',
    `annotation_version` STRING COMMENT 'Version of the genomic annotation set used for panel design.',
    `approval_date` DATE COMMENT 'Date when regulatory approval was granted.',
    `audit_created_by` STRING COMMENT 'User or system that initially created the record.',
    `capture_method` STRING COMMENT 'Laboratory method used to capture target regions.',
    `clinical_significance` STRING COMMENT 'Intended clinical use of the panel results.',
    `cost_currency` STRING COMMENT 'Three‑letter ISO currency code for the panel cost.',
    `coverage_depth_target` STRING COMMENT 'Desired average sequencing depth (X‑fold) for the panel.',
    `creation_timestamp` TIMESTAMP COMMENT 'Date‑time when the panel record was first created.',
    `deprecated_flag` BOOLEAN COMMENT 'Indicates whether the panel is officially deprecated.',
    `deprecation_date` DATE COMMENT 'Date the panel was marked as deprecated.',
    `design_reference` STRING COMMENT 'External document or accession number describing the panel design.',
    `disease_area` STRING COMMENT 'Specific disease(s) or condition(s) the panel is intended to investigate.',
    `effective_from` DATE COMMENT 'Date when the panel becomes valid for use.',
    `effective_until` DATE COMMENT 'Date when the panel is no longer valid (null if open‑ended).',
    `gene_count` STRING COMMENT 'Number of distinct genes targeted by the panel.',
    `is_customizable` BOOLEAN COMMENT 'Indicates whether the panel can be modified for custom gene sets.',
    `last_review_date` DATE COMMENT 'Most recent date the panel design was reviewed for relevance.',
    `manufacturer` STRING COMMENT 'Company that produced the capture reagents.',
    `target_panel_name` STRING COMMENT 'Human‑readable name of the target panel.',
    `panel_category` STRING COMMENT 'High‑level clinical or research domain the panel addresses.',
    `panel_code` STRING COMMENT 'Business identifier used to reference the panel in downstream workflows.',
    `panel_cost` DECIMAL(18,2) COMMENT 'Internal cost to produce or license the panel.',
    `panel_file_checksum` STRING COMMENT 'SHA‑256 checksum of the panel definition file for integrity verification.',
    `panel_file_location` STRING COMMENT 'URI or path to the stored panel definition file.',
    `panel_notes` STRING COMMENT 'Free‑form comments or special instructions for the panel.',
    `panel_owner` STRING COMMENT 'Internal team or department responsible for the panel.',
    `panel_type` STRING COMMENT 'Category of the panel based on sequencing strategy.',
    `probe_type` STRING COMMENT 'Molecular composition of the capture probes.',
    `read_length_target` STRING COMMENT 'Planned read length (bases) for sequencing runs using this panel.',
    `regulatory_approval_status` STRING COMMENT 'Regulatory clearance state for clinical deployment.',
    `release_date` DATE COMMENT 'Date the panel was first released to customers.',
    `sensitivity` DECIMAL(18,2) COMMENT 'Measured sensitivity (percentage) of the panel in validation studies.',
    `sequencing_technology` STRING COMMENT 'Primary sequencing platform compatible with the panel.',
    `specificity` DECIMAL(18,2) COMMENT 'Measured specificity (percentage) of the panel in validation studies.',
    `target_panel_status` STRING COMMENT 'Current lifecycle state of the panel.',
    `strand_specific` BOOLEAN COMMENT 'Indicates whether the panel captures strand‑specific information.',
    `target_regions` STRING COMMENT 'Textual description or BED‑style summary of genomic regions captured.',
    `umi_enabled` BOOLEAN COMMENT 'Indicates whether Unique Molecular Identifiers are used in the capture protocol.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date‑time of the most recent modification to the panel record.',
    `validation_date` DATE COMMENT 'Date of the most recent successful validation.',
    `validation_status` STRING COMMENT 'Current validation state of the panel.',
    `version` STRING COMMENT 'Version identifier for the panel design.',
    CONSTRAINT pk_target_panel PRIMARY KEY(`target_panel_id`)
) COMMENT 'Master reference table for target_panel. Referenced by target_panel_id.';

